import { useState, useEffect } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  CalendarClock,
  Edit,
  Loader2,
  ChevronDown,
  CheckCircle2,
  XCircle,
  Activity,
  ClipboardCheck,
  Calendar as CalendarIcon,
  UserCheck,
  Timer,
  FileText,
  CalendarPlus,
  Users,
  User,
  Phone,
  Clock,
  Stethoscope,
} from "lucide-react";
import { format } from "date-fns";
import { es } from "date-fns/locale";
import { cn } from "@/lib/utils";
import { toast } from "@/hooks/use-toast";
import { useAuthContext } from "@/context/AuthContext";
import ConfirmationDialog from "@/components/common/ConfirmationDialog";
import { updateAppointment, cancelAppointment } from "@/services/appointmentService";
import { useActivityLog } from "@/hooks/useActivityLog";
import {
  APPOINTMENT_STATUS_CONFIG,
  NORMALIZE_STATUS,
  type StatusKey,
} from "@/constants/appointmentConstants";

// ── Types ─────────────────────────────────────────────────────────────────────
interface AppointmentDetails {
  id: string;
  time: string;
  patient: string;
  patientId: string;
  patientPhone?: string;
  treatment: string;
  duration: string;
  status: string;
  date: Date;
  notes?: string;
  createdBy?: string;
  isTreatment?: boolean;
  treatmentName?: string;
  // Campos de atención
  atendidoPor?: string;
  duracionReal?: string;
  notasAtencion?: string;
  planificacionSiguienteCita?: string;
  personalConsulta?: { nombre: string; rol: string }[];
}

interface AppointmentDetailsDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  appointment: AppointmentDetails | null;
  onEdit?: () => void;
  onReschedule?: () => void;
  onSuccess?: () => void;
}

// ── Time slots ────────────────────────────────────────────────────────────────
function generateTimeSlots() {
  const slots: { value: string; label: string }[] = [];
  for (let hour = 7; hour <= 23; hour++) {
    for (const minute of [0, 15, 30, 45]) {
      if (hour === 23 && minute > 30) break;
      const value = `${hour.toString().padStart(2, "0")}:${minute.toString().padStart(2, "0")}`;
      const displayHour = hour > 12 ? hour - 12 : hour === 0 ? 12 : hour;
      const period = hour >= 12 ? "PM" : "AM";
      slots.push({ value, label: `${displayHour}:${minute.toString().padStart(2, "0")} ${period}` });
    }
  }
  return slots;
}

const TIME_SLOTS = generateTimeSlots();

// ── Component ─────────────────────────────────────────────────────────────────
export default function AppointmentDetailsDialog({
  open,
  onOpenChange,
  appointment,
  onEdit,
  onReschedule,
  onSuccess,
}: AppointmentDetailsDialogProps) {
  const { user, userProfile } = useAuthContext();
  const userName = userProfile
    ? `${userProfile.nombre.split(' ')[0]} ${userProfile.apellidoPaterno}`
    : user?.displayName || "Sistema";
  const { log } = useActivityLog();

  const [currentStatus, setCurrentStatus] = useState<StatusKey>("pendiente");
  const [updatingStatus, setUpdatingStatus] = useState(false);
  const [showCancelDialog, setShowCancelDialog] = useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
  const [deleting, setDeleting] = useState(false);

  // Status change dropdown state
  const [pendingStatusChange, setPendingStatusChange] = useState<"confirmada" | "atendiendo" | "atendida" | "cancelada" | null>(null);
  const [showStatusChangeDialog, setShowStatusChangeDialog] = useState(false);

  // Reschedule section state
  const [rescheduleOpen, setRescheduleOpen] = useState(false);
  const [rescheduleDate, setRescheduleDate] = useState<Date | undefined>();
  const [rescheduleTime, setRescheduleTime] = useState<string>("");
  const [rescheduling, setRescheduling] = useState(false);

  useEffect(() => {
    if (appointment && open) {
      setCurrentStatus(NORMALIZE_STATUS[appointment.status?.toLowerCase() || ''] ?? "pendiente");
      // Pre-fill reschedule with current values
      const aptDate = appointment.date instanceof Date ? appointment.date : new Date(appointment.date);
      setRescheduleDate(aptDate);
      setRescheduleTime(appointment.time);
      setRescheduleOpen(false);
    }
  }, [appointment, open]);

  if (!appointment) return null;

  const isRescheduled = currentStatus === "reprogramada";
  const isFinal = currentStatus === "atendida" || currentStatus === "cancelada";
  const statusCfg = APPOINTMENT_STATUS_CONFIG[currentStatus];
  const appointmentDate = appointment.date instanceof Date ? appointment.date : new Date(appointment.date);

  // ── Status change handlers ─────────────────────────────────────────────────
  const handleStatusChangeRequest = (status: "confirmada" | "atendiendo" | "atendida" | "cancelada") => {
    setPendingStatusChange(status);
    setShowStatusChangeDialog(true);
  };

  const handleConfirmStatusChange = async () => {
    if (!pendingStatusChange || !appointment?.id) return;
    try {
      setUpdatingStatus(true);
      await updateAppointment(appointment.id, { estado: pendingStatusChange }, userName);
      log({ modulo: "Calendario", accion: "cambió estado de", entidad: "cita", entidad_id: appointment.id, entidad_nombre: APPOINTMENT_STATUS_CONFIG[pendingStatusChange].label, paciente_nombre: appointment.patient });
      toast({
        title: "Estado actualizado",
        description: `La cita fue marcada como ${APPOINTMENT_STATUS_CONFIG[pendingStatusChange].label.toLowerCase()}.`,
        variant: pendingStatusChange === "cancelada" ? "destructive" : "success",
      });
      setShowStatusChangeDialog(false);
      onOpenChange(false);
      if (onSuccess) await onSuccess();
    } catch (error: any) {
      toast({ title: "Error", description: error.message || "No se pudo actualizar el estado.", variant: "destructive" });
    } finally {
      setUpdatingStatus(false);
      setPendingStatusChange(null);
    }
  };

  const handleConfirmCancellation = async () => {
    try {
      setUpdatingStatus(true);
      await updateAppointment(appointment.id, { estado: "cancelada" }, userName);
      log({ modulo: "Calendario", accion: "canceló", entidad: "cita", entidad_id: appointment.id, entidad_nombre: appointment.patient, paciente_nombre: appointment.patient });
      toast({ title: "Cita cancelada", description: "La cita fue cancelada exitosamente.", variant: "destructive" });
      setShowCancelDialog(false);
      onOpenChange(false);
      if (onSuccess) await onSuccess();
    } catch (error: any) {
      toast({ title: "Error", description: "No se pudo cancelar la cita.", variant: "destructive" });
    } finally {
      setUpdatingStatus(false);
    }
  };

  const handleDeleteAppointment = async () => {
    try {
      setDeleting(true);
      await cancelAppointment(appointment.id);
      log({ modulo: "Calendario", accion: "eliminó", entidad: "cita", entidad_id: appointment.id, entidad_nombre: appointment.patient, paciente_nombre: appointment.patient });
      toast({ title: "Cita eliminada", description: "La cita fue eliminada exitosamente.", variant: "destructive" });
      setShowDeleteDialog(false);
      onOpenChange(false);
      onSuccess?.();
    } catch (error) {
      toast({ title: "Error", description: "No se pudo eliminar la cita.", variant: "destructive" });
    } finally {
      setDeleting(false);
    }
  };

  // ── Reschedule handler ─────────────────────────────────────────────────────
  const handleReschedule = async () => {
    if (!rescheduleDate || !rescheduleTime) {
      toast({ title: "Datos incompletos", description: "Selecciona una fecha y hora.", variant: "warning" });
      return;
    }
    try {
      setRescheduling(true);
      await updateAppointment(appointment.id, {
        fecha: rescheduleDate,
        hora: rescheduleTime,
        estado: "reprogramada" as any,
      }, userName);
      log({ modulo: "Calendario", accion: "reprogramó", entidad: "cita", entidad_id: appointment.id, entidad_nombre: appointment.patient, paciente_nombre: appointment.patient });
      toast({
        title: "Cita reprogramada",
        description: `Reprogramada al ${format(rescheduleDate, "PPP", { locale: es })} a las ${rescheduleTime}.`,
        variant: "warning",
      });
      setRescheduleOpen(false);
      onOpenChange(false);
      if (onSuccess) await onSuccess();
    } catch (error: any) {
      toast({ title: "Error", description: "No se pudo reprogramar la cita.", variant: "destructive" });
    } finally {
      setRescheduling(false);
    }
  };

  // Dropdown options — filter out the current status
  const statusChangeOptions = [
    { key: "confirmada" as const, label: "Confirmar", icon: CheckCircle2, colorClass: "text-emerald-600 focus:text-emerald-600 focus:bg-emerald-50" },
    { key: "atendiendo" as const, label: "Atendiendo", icon: Activity, colorClass: "text-slate-600 focus:text-slate-600 focus:bg-slate-50" },
    { key: "atendida" as const, label: "Atendida", icon: ClipboardCheck, colorClass: "text-slate-500 focus:text-slate-500 focus:bg-slate-50" },
    { key: "cancelada" as const, label: "Cancelar", icon: XCircle, colorClass: "text-red-500 focus:text-red-500 focus:bg-red-50" },
  ].filter((opt) => opt.key !== currentStatus);

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <>
      <Dialog open={open} onOpenChange={onOpenChange}>
        {/* p-0 + overflow-hidden para que el inner flex controle el layout */}
        <DialogContent className="max-w-2xl p-0 overflow-hidden">
          <div className="flex flex-col max-h-[90vh]">

            {/* Header fijo */}
            <div className="flex items-center justify-between gap-4 px-6 pt-6 pb-4 flex-shrink-0">
              <DialogTitle className="text-2xl font-semibold text-slate-900">
                Detalles de cita
              </DialogTitle>
              <span className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium ring-1 ${statusCfg.pill}`}>
                <span className={cn(
                  "h-1.5 w-1.5 rounded-full",
                  statusCfg.dot,
                  currentStatus === "atendiendo" && "animate-glow-pulse"
                )} />
                {statusCfg.label}
              </span>
            </div>

            {/* Contenido — crece y solo hace scroll si es estrictamente necesario */}
            <div className="overflow-y-auto min-h-0 px-6 pb-4">
              <div className="space-y-3">

                {/* Paciente */}
                <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                  <User className="h-4 w-4 text-primary flex-shrink-0" />
                  <div>
                    <p className="text-xs text-muted-foreground">Paciente</p>
                    <p className="text-sm font-semibold">{appointment.patient}</p>
                  </div>
                </div>

                {/* Fecha y Hora */}
                <div className="grid grid-cols-2 gap-3">
                  <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                    <CalendarIcon className="h-4 w-4 text-primary flex-shrink-0" />
                    <div>
                      <p className="text-xs text-muted-foreground">Fecha</p>
                      <p className="text-sm font-semibold">{format(appointmentDate, "PPP", { locale: es })}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                    <Clock className="h-4 w-4 text-primary flex-shrink-0" />
                    <div>
                      <p className="text-xs text-muted-foreground">Hora</p>
                      <p className="text-sm font-semibold">{appointment.time}</p>
                    </div>
                  </div>
                </div>

                {/* Celular y Consulta */}
                <div className="grid grid-cols-2 gap-3">
                  <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                    <Phone className="h-4 w-4 text-primary flex-shrink-0" />
                    <div>
                      <p className="text-xs text-muted-foreground">Celular</p>
                      <p className="text-sm font-semibold">{appointment.patientPhone || "No registrado"}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                    <Stethoscope className="h-4 w-4 text-primary flex-shrink-0" />
                    <div>
                      <p className="text-xs text-muted-foreground">
                        {appointment.isTreatment ? "Tratamiento" : "Consulta"}
                      </p>
                      <p className="text-sm font-semibold">
                        {appointment.isTreatment ? appointment.treatmentName : appointment.treatment}
                      </p>
                    </div>
                  </div>
                </div>

                {/* Duración y Creado por */}
                <div className="grid grid-cols-2 gap-3">
                  <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                    <Clock className="h-4 w-4 text-primary flex-shrink-0" />
                    <div>
                      <p className="text-xs text-muted-foreground">Duración estimada</p>
                      <p className="text-sm font-semibold">{appointment.duration}</p>
                    </div>
                  </div>
                  {appointment.createdBy && (
                    <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                      <User className="h-4 w-4 text-primary flex-shrink-0" />
                      <div>
                        <p className="text-xs text-muted-foreground">Creado por</p>
                        <p className="text-sm font-semibold">{appointment.createdBy}</p>
                      </div>
                    </div>
                  )}
                </div>

                {/* Notas generales */}
                {appointment.notes && (
                  <div className="flex items-start gap-3 p-3 border rounded-lg bg-muted/30">
                    <FileText className="h-4 w-4 text-primary flex-shrink-0 mt-0.5" />
                    <div>
                      <p className="text-xs text-muted-foreground">Notas</p>
                      <p className="text-sm font-semibold whitespace-pre-line mt-0.5">{appointment.notes}</p>
                    </div>
                  </div>
                )}

                {/* ── Sección de atención ────────────────────────────────── */}
                {currentStatus === "atendida" && (
                  <div className="border-t pt-3 space-y-3">
                    <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider flex items-center gap-1.5">
                      <Activity className="h-3.5 w-3.5" />
                      Información de atención
                    </p>

                    {/* Personal */}
                    {appointment.personalConsulta && appointment.personalConsulta.length > 0 ? (
                      <div className="flex items-start gap-3 p-3 border rounded-lg bg-muted/30">
                        <Users className="h-4 w-4 text-primary flex-shrink-0 mt-0.5" />
                        <div className="flex-1">
                          <p className="text-xs text-muted-foreground mb-1.5">Personal</p>
                          <div className="space-y-1">
                            {appointment.personalConsulta.map((p, i) => (
                              <div key={i} className="flex items-center justify-between">
                                <p className="text-sm font-semibold">{p.nombre}</p>
                                <span className="text-xs text-muted-foreground bg-muted px-2 py-0.5 rounded-full">{p.rol}</span>
                              </div>
                            ))}
                          </div>
                        </div>
                      </div>
                    ) : (
                      <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                        <UserCheck className="h-4 w-4 text-primary flex-shrink-0" />
                        <div>
                          <p className="text-xs text-muted-foreground">Atendido por</p>
                          <p className="text-sm font-semibold">{appointment.atendidoPor || "No registrado"}</p>
                        </div>
                      </div>
                    )}

                    <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                      <Timer className="h-4 w-4 text-primary flex-shrink-0" />
                      <div>
                        <p className="text-xs text-muted-foreground">Duración real</p>
                        <p className="text-sm font-semibold">
                          {appointment.duracionReal && appointment.duracionReal !== "0"
                            ? `${appointment.duracionReal} min`
                            : "No registrada"}
                        </p>
                      </div>
                    </div>

                    {appointment.notasAtencion && (
                      <div className="flex items-start gap-3 p-3 border rounded-lg bg-muted/30">
                        <FileText className="h-4 w-4 text-primary flex-shrink-0 mt-0.5" />
                        <div>
                          <p className="text-xs text-muted-foreground">Notas de cita</p>
                          <p className="text-sm font-semibold whitespace-pre-line mt-0.5">{appointment.notasAtencion}</p>
                        </div>
                      </div>
                    )}

                    {appointment.planificacionSiguienteCita && (
                      <div className="flex items-start gap-3 p-3 border rounded-lg bg-muted/30">
                        <CalendarPlus className="h-4 w-4 text-primary flex-shrink-0 mt-0.5" />
                        <div>
                          <p className="text-xs text-muted-foreground">Planificación siguiente cita</p>
                          <p className="text-sm font-semibold whitespace-pre-line mt-0.5">{appointment.planificacionSiguienteCita}</p>
                        </div>
                      </div>
                    )}
                  </div>
                )}

                {/* Reprogramar — oculto en estados finales */}
                {!isFinal && !isRescheduled && (
                  <Collapsible open={rescheduleOpen} onOpenChange={setRescheduleOpen}>
                    <div className="border-t pt-3">
                      <CollapsibleTrigger className="w-full flex items-center justify-between">
                        <div className="flex items-center gap-2">
                          <CalendarClock className="h-4 w-4 text-amber-500" />
                          <span className="text-sm font-medium">Reprogramar cita</span>
                        </div>
                        <ChevronDown
                          className={cn(
                            "h-4 w-4 text-muted-foreground transition-transform duration-200",
                            rescheduleOpen && "rotate-180"
                          )}
                        />
                      </CollapsibleTrigger>
                    </div>

                    <CollapsibleContent>
                      <div className="pt-3 space-y-3">
                        <div className="grid grid-cols-2 gap-3">
                          {/* Nueva fecha */}
                          <div className="flex flex-col gap-1.5">
                            <span className="text-sm font-medium">Nueva fecha</span>
                            <Popover>
                              <PopoverTrigger asChild>
                                <Button
                                  variant="outline"
                                  className={cn(
                                    "h-10 w-full justify-start text-left font-normal text-sm",
                                    !rescheduleDate && "text-muted-foreground"
                                  )}
                                >
                                  <CalendarIcon className="h-4 w-4 mr-2 opacity-50" />
                                  {rescheduleDate ? format(rescheduleDate, "PPP", { locale: es }) : "Seleccionar"}
                                </Button>
                              </PopoverTrigger>
                              <PopoverContent className="w-auto p-0" align="start">
                                <Calendar
                                  mode="single"
                                  selected={rescheduleDate}
                                  onSelect={setRescheduleDate}
                                  disabled={(date) => date < new Date(new Date().setHours(0, 0, 0, 0))}
                                  initialFocus
                                  locale={es}
                                />
                              </PopoverContent>
                            </Popover>
                          </div>

                          {/* Nueva hora */}
                          <div className="flex flex-col gap-1.5">
                            <span className="text-sm font-medium">Nueva hora</span>
                            <Select value={rescheduleTime} onValueChange={setRescheduleTime}>
                              <SelectTrigger className="h-10 text-sm">
                                <SelectValue placeholder="Seleccionar hora" />
                              </SelectTrigger>
                              <SelectContent className="max-h-[300px]">
                                {TIME_SLOTS.map((slot) => (
                                  <SelectItem key={slot.value} value={slot.value} className="text-sm">
                                    {slot.label}
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                          </div>
                        </div>

                        <div className="flex justify-end">
                          <Button
                            onClick={handleReschedule}
                            disabled={rescheduling || !rescheduleDate || !rescheduleTime}
                            className="bg-amber-500 hover:bg-amber-600 text-white"
                          >
                            {rescheduling ? (
                              <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                            ) : (
                              <CalendarClock className="h-4 w-4 mr-2" />
                            )}
                            {rescheduling ? "Guardando..." : "Guardar cambios"}
                          </Button>
                        </div>
                      </div>
                    </CollapsibleContent>
                  </Collapsible>
                )}
              </div>
            </div>

            {/* Footer fijo */}
            <div className="border-t px-6 py-4 flex items-center justify-between flex-shrink-0">
              {/* Izquierda — destructivo */}
              <div>
                {isRescheduled ? (
                  <button
                    onClick={() => setShowCancelDialog(true)}
                    className="text-sm font-medium text-red-500 hover:text-red-600 transition-colors"
                  >
                    Cancelar cita
                  </button>
                ) : !isFinal ? (
                  <button
                    onClick={() => setShowDeleteDialog(true)}
                    className="text-sm font-medium text-red-500 hover:text-red-600 transition-colors"
                  >
                    Eliminar cita
                  </button>
                ) : null}
              </div>

              {/* Derecha — Editar + Cambiar estado */}
              <div className="flex items-center gap-3">
                {onEdit && !isFinal && (
                  <Button variant="outline" onClick={onEdit} disabled={updatingStatus}>
                    <Edit className="h-4 w-4 mr-2" />
                    Editar
                  </Button>
                )}
                {!isRescheduled && !isFinal && statusChangeOptions.length > 0 && (
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button disabled={updatingStatus}>
                        {updatingStatus ? (
                          <>
                            <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                            Cambiando...
                          </>
                        ) : (
                          <>
                            Cambiar estado
                            <ChevronDown className="h-4 w-4 ml-2" />
                          </>
                        )}
                      </Button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="end" className="w-[160px] p-1">
                      {statusChangeOptions.map((opt) => {
                        const Icon = opt.icon;
                        return (
                          <DropdownMenuItem
                            key={opt.key}
                            onClick={() => handleStatusChangeRequest(opt.key)}
                            className={cn(
                              "text-sm cursor-pointer font-bold py-2 px-3 rounded-md transition-colors",
                              opt.colorClass
                            )}
                          >
                            <Icon className="h-4 w-4 mr-2" />
                            {opt.label}
                          </DropdownMenuItem>
                        );
                      })}
                    </DropdownMenuContent>
                  </DropdownMenu>
                )}
              </div>
            </div>

          </div>
        </DialogContent>
      </Dialog>

      {/* Confirm status change (via dropdown) */}
      {pendingStatusChange && (
        <ConfirmationDialog
          open={showStatusChangeDialog}
          onOpenChange={(open) => {
            setShowStatusChangeDialog(open);
            if (!open) setPendingStatusChange(null);
          }}
          onConfirm={handleConfirmStatusChange}
          title={`¿Marcar como ${APPOINTMENT_STATUS_CONFIG[pendingStatusChange].label}?`}
          description={`Se cambiará el estado de la cita de ${appointment.patient} (${format(appointmentDate, "PPP", { locale: es })} a las ${appointment.time}) a "${APPOINTMENT_STATUS_CONFIG[pendingStatusChange].label}".`}
          confirmText={`Sí, marcar como ${APPOINTMENT_STATUS_CONFIG[pendingStatusChange].label.toLowerCase()}`}
          cancelText="Cancelar"
          loadingText="Guardando..."
          variant={pendingStatusChange === "cancelada" ? "destructive" : "default"}
          loading={updatingStatus}
        />
      )}

      {/* Confirm cancel — for rescheduled appointments */}
      <ConfirmationDialog
        open={showCancelDialog}
        onOpenChange={setShowCancelDialog}
        onConfirm={handleConfirmCancellation}
        title="¿Cancelar esta cita?"
        description={`¿Estás seguro de que deseas cancelar la cita de ${appointment.patient} programada para el ${format(appointmentDate, "PPP", { locale: es })} a las ${appointment.time}?`}
        confirmText="Sí, cancelar cita"
        cancelText="No, mantener cita"
        loadingText="Cancelando..."
        variant="destructive"
        loading={updatingStatus}
      />

      {/* Confirm delete */}
      <ConfirmationDialog
        open={showDeleteDialog}
        onOpenChange={setShowDeleteDialog}
        onConfirm={handleDeleteAppointment}
        title="¿Eliminar cita?"
        description={`¿Estás seguro de que deseas eliminar la cita de ${appointment.patient} programada para el ${format(appointmentDate, "PPP", { locale: es })} a las ${appointment.time}? Esta acción no se puede deshacer.`}
        confirmText="Sí, eliminar cita"
        cancelText="No, mantener cita"
        loadingText="Eliminando..."
        variant="destructive"
        loading={deleting}
      />
    </>
  );
}

import { useState, useEffect, useCallback } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
} from "@/components/ui/dialog";
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import {
    Popover,
    PopoverContent,
    PopoverTrigger,
} from "@/components/ui/popover";
import { Textarea } from "@/components/ui/textarea";
import { Calendar as CalendarIcon, Clock, Search, UserPlus, Loader2, AlertCircle, X, User, ClipboardList, Package } from "lucide-react";
import { format, isSameDay } from "date-fns";
import { es } from "date-fns/locale";
import { cn } from "@/lib/utils";
import { toast } from "@/hooks/use-toast";
import { useAuthContext } from "@/context/AuthContext";
import { formatNotes, handleNotesKeyDown } from "@/utils/formatters";

import {
    createAppointment,
    getAllAppointments
} from "@/services/appointmentService";
import {
    createPatient,
    getAllPatients,
    findPatientByDNI,
} from "@/services/patientService";
import { Patient } from "@/types/appointment";
import { DURATIONS } from "@/constants/appointmentConstants";
import { useConsultationPrices } from "@/hooks/useConsultationPrices";
import { capitalizeName } from "@/utils/formatters";
import { useActivityLog } from "@/hooks/useActivityLog";
import { collection, query, where, getDocs, doc, updateDoc, arrayUnion } from "firebase/firestore";
import { db } from "@/lib/firebase";



// 📋 SCHEMA DE VALIDACIÓN
const appointmentFormSchema = z.object({
    date: z.date({
        required_error: "La fecha es requerida",
    }),
    time: z.string().min(1, "La hora es requerida"),
    patientId: z.string().optional(),
    patientName: z.string().min(1, "El nombre del paciente es requerido"),
    isNewPatient: z.boolean().default(false),
    newPatientDni: z.string().optional(),
    newPatientPhone: z.string().optional(),
    newPatientEmail: z.string().email("Email inválido").optional().or(z.literal("")),
    consultation: z.string().optional(),
    duration: z.string().min(1, "Debe seleccionar una duración"),
    notes: z.string().optional(),
}).superRefine((data, ctx) => {
    if (data.isNewPatient) {
        if (!data.newPatientDni || !/^[1-9][0-9]{7}$/.test(data.newPatientDni)) {
            ctx.addIssue({
                code: z.ZodIssueCode.custom,
                message: "Ingresar un DNI válido",
                path: ["newPatientDni"],
            });
        }
        if (!data.newPatientPhone || !/^9[0-9]{8}$/.test(data.newPatientPhone)) {
            ctx.addIssue({
                code: z.ZodIssueCode.custom,
                message: "Ingresar un número de celular válido",
                path: ["newPatientPhone"],
            });
        }
    }
});

type AppointmentFormValues = z.infer<typeof appointmentFormSchema>;

interface AppointmentDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    selectedDate?: Date;
    selectedTime?: string;
    onSuccess?: () => void;
}

export default function AppointmentDialog({
    open,
    onOpenChange,
    selectedDate,
    selectedTime,
    onSuccess,
}: AppointmentDialogProps) {
    const { prices: consultationTypes, getCostByType } = useConsultationPrices();
    const { user, userProfile } = useAuthContext();
    const userName = userProfile
        ? `${userProfile.nombre.split(' ')[0]} ${userProfile.apellidoPaterno}`
        : user?.displayName || "Sistema";
    // Estados
    const [searchPatient, setSearchPatient] = useState("");
    const [patients, setPatients] = useState<Patient[]>([]);
    const [loading, setLoading] = useState(false);
    const { log } = useActivityLog();
    const [loadingPatients, setLoadingPatients] = useState(false);
    const [displayMonth, setDisplayMonth] = useState<Date>(selectedDate || new Date());
    const [appointments, setAppointments] = useState<any[]>([]);
    const [validacion, setValidacion] = useState<{ disponible: boolean; mensaje: string }>({
        disponible: true,
        mensaje: ''
    });
    const [activeTreatments, setActiveTreatments] = useState<any[]>([]);
    const [loadingTreatments, setLoadingTreatments] = useState(false);
    const [selectedTreatmentId, setSelectedTreatmentId] = useState<string | null>(null);

    // Form setup
    const form = useForm<AppointmentFormValues>({
        resolver: zodResolver(appointmentFormSchema),
        defaultValues: {
            date: selectedDate || new Date(),
            time: selectedTime || "",
            patientId: "",
            patientName: "",
            isNewPatient: false,
            newPatientDni: "",
            newPatientPhone: "",
            newPatientEmail: "",
            consultation: "",
            duration: "30",
            notes: "",
        },
    });

    useEffect(() => {
        if (open) {
            form.setValue("date", selectedDate || new Date());
            form.setValue("time", selectedTime || "");
        }
    }, [open, selectedDate, selectedTime, form]);

    // Watch para modo nuevo paciente
    const isNewPatient = form.watch("isNewPatient");
    const watchedDate = form.watch("date");
    const watchedTime = form.watch("time");
    const watchedDuration = form.watch("duration");
    const watchedPatientId = form.watch("patientId");

    // Cargar tratamientos activos cuando se selecciona un paciente
    useEffect(() => {
        if (watchedPatientId && !isNewPatient) {
            loadActiveTreatments(watchedPatientId);
        } else {
            setActiveTreatments([]);
        }
    }, [watchedPatientId, isNewPatient]);

    // ==================== CARGAR PACIENTES Y CITAS ====================
    useEffect(() => {
        if (open) {
            loadPatients();
            loadAppointments();
        }
    }, [open]);

    const loadPatients = async () => {
        setLoadingPatients(true);
        try {
            const patientsData = await getAllPatients();
            setPatients(patientsData || []);
        } catch (error) {
            console.error("Error al cargar pacientes:", error);
            setPatients([]);
            toast({
                title: "⚠️ Advertencia",
                description: "No se pudieron cargar los pacientes.",
                variant: "destructive",
            });
        } finally {
            setLoadingPatients(false);
        }
    };

    const loadAppointments = async () => {
        try {
            const appointmentsData = await getAllAppointments();
            setAppointments(appointmentsData || []);
        } catch (error) {
            console.error("Error al cargar citas:", error);
            setAppointments([]);
        }
    };

    // Cargar tratamientos activos del paciente seleccionado
    const loadActiveTreatments = async (patientId: string) => {
        if (!patientId) {
            setActiveTreatments([]);
            return;
        }

        try {
            setLoadingTreatments(true);
            const treatmentsRef = collection(db, "tratamientos");
            const q = query(
                treatmentsRef,
                where("paciente_id", "==", patientId),
                where("estado", "==", "activo")
            );
            const querySnapshot = await getDocs(q);

            const treatmentsData: any[] = [];
            querySnapshot.forEach((doc) => {
                const data = doc.data();
                treatmentsData.push({
                    id: doc.id,
                    tratamiento: data.tratamiento || "",
                    pago_pendiente: data.pago_pendiente || 0,
                    total_presupuesto: data.total_presupuesto || 0,
                    monto_abonado: data.monto_abonado || 0,
                });
            });

            setActiveTreatments(treatmentsData);
        } catch (error) {
            console.error("Error al cargar tratamientos:", error);
            setActiveTreatments([]);
        } finally {
            setLoadingTreatments(false);
        }
    };

    // ==================== FUNCIÓN DE VALIDACIÓN DE DISPONIBILIDAD ROBUSTA ====================
    const validarDisponibilidadHorario = useCallback((fecha: Date, hora: string): { disponible: boolean; mensaje: string } => {
        if (!fecha || !hora || !appointments || appointments.length === 0) {
            return { disponible: true, mensaje: '' };
        }

        try {
            // Obtener duración seleccionada (con fallback a 30 min)
            const duracionSeleccionada = parseInt(watchedDuration || '30');

            // Convertir hora a minutos desde medianoche
            const horaInicio = (parseInt(hora.split(':')[0]) * 60) + parseInt(hora.split(':')[1] || '0');
            const horaFin = horaInicio + duracionSeleccionada;

            // Filtrar todas las citas del día seleccionado (excluyendo canceladas)
            const citasDelDia = appointments.filter(apt => {
                try {
                    if (!apt.fecha) return false;

                    // Excluir citas canceladas
                    const status = apt.estado?.toLowerCase() || '';
                    if (status === 'cancelada' || status === 'cancelled') return false;

                    let fechaCita: Date;
                    if (typeof apt.fecha.toDate === 'function') {
                        fechaCita = apt.fecha.toDate();
                    } else if (apt.fecha instanceof Date) {
                        fechaCita = apt.fecha;
                    } else {
                        return false;
                    }

                    return isSameDay(fechaCita, fecha);
                } catch {
                    return false;
                }
            });

            // ══════════════════════════════════════════════════════════
            // VALIDACIÓN POR INTERVALOS DE 30 MINUTOS
            // ══════════════════════════════════════════════════════════

            const intervalosConflictivos: string[] = [];

            // Validar cada intervalo de 30 minutos que cubre la nueva cita
            for (let minuto = horaInicio; minuto < horaFin; minuto += 30) {
                const intervaloInicio = minuto;
                const intervaloFin = Math.min(minuto + 30, horaFin);

                // Contar cuántas citas se solapan con este intervalo de 30 min
                const citasEnIntervalo = citasDelDia.filter(apt => {
                    try {
                        if (!apt.hora || !apt.duracion) return false;

                        const aptInicio = (parseInt(apt.hora.split(':')[0]) * 60) + parseInt(apt.hora.split(':')[1] || '0');
                        const aptFin = aptInicio + parseInt(apt.duracion.toString());

                        // La cita se solapa con el intervalo si hay superposición REAL:
                        // - Empieza antes de que termine el intervalo Y
                        // - Termina DESPUÉS (no en el mismo momento) de que empiece el intervalo
                        // Esto excluye citas que solo "tocan" el borde (ej: 8:00-8:30 NO cuenta para 8:30-9:00)
                        return aptInicio < intervaloFin && aptFin > intervaloInicio;
                    } catch {
                        return false;
                    }
                });

                // Si este intervalo ya tiene 4 citas, está lleno
                if (citasEnIntervalo.length >= 4) {
                    const h = Math.floor(minuto / 60);
                    const m = minuto % 60;
                    intervalosConflictivos.push(`${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`);
                }
            }

            if (intervalosConflictivos.length > 0) {
                return {
                    disponible: false,
                    mensaje: `No hay disponibilidad para esta cita. Intervalos llenos: ${intervalosConflictivos.join(', ')}`
                };
            }

            return { disponible: true, mensaje: '' };

        } catch (error) {
            console.error("Error en validación de horario:", error);
            return { disponible: true, mensaje: '' };
        }
    }, [appointments, watchedDuration]);

    // ==================== VALIDAR CUANDO CAMBIE FECHA, HORA O DURACIÓN ====================
    useEffect(() => {
        if (watchedDate && watchedTime) {
            const resultado = validarDisponibilidadHorario(watchedDate, watchedTime);
            setValidacion(resultado);
        } else {
            setValidacion({ disponible: true, mensaje: '' });
        }
    }, [watchedDate, watchedTime, watchedDuration, appointments]);

    // Filtrado de pacientes
    const filteredPatients = patients.filter(p => {
        const fullName = `${p.nombre} ${p.apellido_paterno} ${p.apellido_materno}`.toLowerCase();
        return fullName.includes(searchPatient.toLowerCase()) ||
            p.dni_cliente.includes(searchPatient);
    });

    // FUNCIÓN PARA GENERAR HORAS (7 AM - 12 AM / Medianoche)
    const generateTimeSlots = () => {
        const slots = [];
        for (let hour = 7; hour <= 23; hour++) {
            for (let minute = 0; minute < 60; minute += 15) {
                const timeValue = `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`;
                slots.push({ value: timeValue, label: timeValue });
            }
        }

        return slots;
    };

    const timeSlots = generateTimeSlots();

    // ==================== SEPARAR NOMBRE COMPLETO ====================
    const separateFullName = (fullName: string) => {
        const capitalizedName = capitalizeName(fullName);
        const parts = capitalizedName.split(" ");

        if (parts.length === 1) {
            return { nombre: parts[0], apellido_paterno: "", apellido_materno: "" };
        } else if (parts.length === 2) {
            return { nombre: parts[0], apellido_paterno: parts[1], apellido_materno: "" };
        } else if (parts.length === 3) {
            return { nombre: parts[0], apellido_paterno: parts[1], apellido_materno: parts[2] };
        } else {
            const apellido_materno = parts.pop() || "";
            const apellido_paterno = parts.pop() || "";
            const nombre = parts.join(" ");
            return { nombre, apellido_paterno, apellido_materno };
        }
    };

    // ==================== HANDLER DE SUBMIT ====================
    const onSubmit = async (data: AppointmentFormValues) => {
        // Validar que haya tipo de consulta O tratamiento seleccionado
        if (!selectedTreatmentId && !data.consultation) {
            toast({
                title: "⚠️ Información incompleta",
                description: "Debes seleccionar un tipo de consulta o un tratamiento activo.",
                variant: "destructive",
            });
            return;
        }

        // Validar disponibilidad antes de crear
        if (!validacion.disponible) {
            toast({
                title: "⚠️ Horario no disponible",
                description: validacion.mensaje,
                variant: "destructive",
            });
            return;
        }

        setLoading(true);

        try {
            let patientId = data.patientId;

            // ========== SI ES NUEVO PACIENTE, CREARLO ==========
            if (data.isNewPatient) {
                // Verificar si el DNI ya existe
                const existingPatient = await findPatientByDNI(data.newPatientDni!);

                if (existingPatient) {
                    toast({
                        title: "⚠️ Paciente ya existe",
                        description: "Ya existe un paciente con ese DNI. Se usará el existente.",
                    });
                    patientId = existingPatient.id!;
                } else {
                    // Separar el nombre completo
                    const { nombre, apellido_paterno, apellido_materno } = separateFullName(data.patientName);

                    // Crear nuevo paciente con datos básicos
                    const newPatientData: Omit<Patient, "id" | "fecha_creacion"> = {
                        nombre,
                        apellido_paterno,
                        apellido_materno,
                        dni_cliente: data.newPatientDni!,
                        celular: data.newPatientPhone!,
                        email: data.newPatientEmail || "",
                        // Campos opcionales con valores por defecto vacíos
                        edad: undefined,
                        sexo: "",
                        direccion: "",
                        distrito_direccion: "",
                        estado_civil: "",
                        telefono_fijo: "",
                        ocupacion: "",
                        lugar_procedencia: "",
                        fecha_nacimiento: undefined,
                    };

                    patientId = await createPatient(newPatientData);

                    toast({
                        title: "✅ Paciente creado",
                        description: `Paciente ${data.patientName} creado exitosamente.`,
                    });
                }
            }

            // ========== VERIFICAR QUE TENEMOS UN PACIENTE ID ==========
            if (!patientId) {
                throw new Error("No se pudo obtener el ID del paciente");
            }

            const capitalizedPatientName = capitalizeName(data.patientName);

            // ========== DETERMINAR TIPO Y COSTO ==========
            let tipo_consulta = "";
            let costo = 0;
            let tratamiento_id = "";
            let tratamiento_nombre = "";

            if (selectedTreatmentId) {
                // Cita para tratamiento - tipo_consulta se deja vacío
                const treatment = activeTreatments.find(t => t.id === selectedTreatmentId);
                if (treatment) {
                    tipo_consulta = ""; // Vacío para tratamientos
                    tratamiento_id = treatment.id;
                    tratamiento_nombre = treatment.tratamiento;
                    costo = 0; // El costo está en el presupuesto del tratamiento
                }
            } else {
                // Cita para consulta normal
                tipo_consulta = data.consultation || "";
                costo = getCostByType(data.consultation || "");
            }

            // ========== CREAR LA CITA CON NUEVA ESTRUCTURA ==========
            const appointmentData: any = {
                // Información básica
                fecha: data.date,
                hora: data.time,
                fecha_creacion: new Date(),

                // Información del paciente
                paciente_id: patientId,
                paciente_nombre: capitalizedPatientName,

                // Tipo de cita
                es_tratamiento: !!selectedTreatmentId,
                tipo_consulta: tipo_consulta,

                // Duración y tiempo
                duracion: data.duration,
                duracion_real: "",
                hora_inicio_atencion: "",
                hora_fin_atencion: "",

                // Personal
                atendido_por: "",

                // Estado y pago
                estado: "pendiente" as const,
                costo: costo,
                pagado: false,

                // Notas
                notas_observaciones: data.notes || "",
            };

            // Si es cita de tratamiento, agregar información adicional
            if (selectedTreatmentId) {
                appointmentData.tratamiento_id = tratamiento_id;
                appointmentData.tratamiento_nombre = tratamiento_nombre;
            }

            const appointmentId = await createAppointment(appointmentData, userName);

            // ========== SI ES CITA DE TRATAMIENTO, ACTUALIZAR EL ARRAY DE CITAS ==========
            if (selectedTreatmentId && appointmentId) {
                try {
                    const treatmentRef = doc(db, "tratamientos", selectedTreatmentId);
                    await updateDoc(treatmentRef, {
                        citas: arrayUnion(appointmentId)
                    });
                } catch (updateError) {
                    console.error("Error al actualizar array de citas en tratamiento:", updateError);
                    // No lanzar error, la cita ya se creó exitosamente
                }
            }

            toast({
                title: "✅ Cita creada exitosamente",
                description: selectedTreatmentId
                    ? `Cita para tratamiento "${tratamiento_nombre}" agendada el ${format(data.date, "PPP", { locale: es })} a las ${data.time}.`
                    : `Cita para ${capitalizedPatientName} agendada el ${format(data.date, "PPP", { locale: es })} a las ${data.time}.`,
            });

            log({
                modulo: "Calendario",
                accion: "creó",
                entidad: "cita",
                entidad_id: appointmentId,
                entidad_nombre: selectedTreatmentId
                    ? tratamiento_nombre
                    : "Consulta",
                paciente_nombre: capitalizedPatientName,
            });

            // Reset y cerrar
            form.reset();
            setSearchPatient("");
            setSelectedTreatmentId(null);
            onOpenChange(false);
            onSuccess?.();

        } catch (error: any) {
            console.error("Error completo:", error);
            toast({
                title: "❌ Error",
                description: error.message || "No se pudo crear la cita. Intenta nuevamente.",
                variant: "destructive",
            });
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-3xl h-[90vh] flex flex-col p-0 border-none bg-white rounded-3xl overflow-hidden">
                <DialogHeader className="px-6 py-5 border-b border-slate-100 bg-white flex-none relative">
                    <DialogTitle className="text-2xl font-semibold text-slate-900">Nueva Cita</DialogTitle>
                    <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        className="absolute right-4 top-4 rounded-full h-10 w-10 text-slate-400 hover:text-slate-900 hover:bg-slate-100 transition-all"
                        onClick={() => onOpenChange(false)}
                    >
                        <X className="h-5 w-5" />
                    </Button>
                </DialogHeader>

                <div className="flex-1 overflow-y-auto px-6 pt-1 pb-2">
                    <Form {...form}>
                        <form id="appointment-form" autoComplete="off" onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
                            {/* 🗓️ SECCIÓN 1: FECHA Y HORA */}
                            <div className="space-y-4">
                                <div className="flex items-center gap-2 pb-2 border-b border-slate-100">
                                    <CalendarIcon className="h-4 w-4 text-primary" />
                                    <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Fecha y Horario</h3>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {/* Campo de Fecha */}
                                    <FormField
                                        control={form.control}
                                        name="date"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Fecha de la Cita *</FormLabel>
                                                <Popover>
                                                    <PopoverTrigger asChild>
                                                        <FormControl>
                                                            <Button
                                                                variant="outline"
                                                                className={cn(
                                                                    "w-full pl-3 text-left font-normal",
                                                                    !field.value && "text-muted-foreground"
                                                                )}
                                                            >
                                                                {field.value ? (
                                                                    format(field.value, "PPP", { locale: es })
                                                                ) : (
                                                                    <span>Selecciona una fecha</span>
                                                                )}
                                                                <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                                                            </Button>
                                                        </FormControl>
                                                    </PopoverTrigger>

                                                    <PopoverContent className="w-auto p-3" align="start">
                                                        <div className="flex justify-between mb-2 gap-2">
                                                            <select
                                                                className="border rounded-md px-2 py-1 text-xs"
                                                                value={displayMonth.getMonth()}
                                                                onChange={(e) =>
                                                                    setDisplayMonth(
                                                                        new Date(displayMonth.getFullYear(), parseInt(e.target.value))
                                                                    )
                                                                }
                                                            >
                                                                {Array.from({ length: 12 }, (_, i) => (
                                                                    <option key={i} value={i}>
                                                                        {format(new Date(0, i), "MMMM", { locale: es })}
                                                                    </option>
                                                                ))}
                                                            </select>

                                                            <select
                                                                className="border rounded-md px-2 py-1 text-xs"
                                                                value={displayMonth.getFullYear()}
                                                                onChange={(e) =>
                                                                    setDisplayMonth(
                                                                        new Date(parseInt(e.target.value), displayMonth.getMonth())
                                                                    )
                                                                }
                                                            >
                                                                {Array.from({ length: 11 }, (_, i) => new Date().getFullYear() + i - 1).map((y) => (
                                                                    <option key={y} value={y}>
                                                                        {y}
                                                                    </option>
                                                                ))}
                                                            </select>
                                                        </div>
                                                        <Calendar
                                                            mode="single"
                                                            selected={field.value}
                                                            onSelect={(date) => {
                                                                field.onChange(date);
                                                            }}
                                                            month={displayMonth}
                                                            onMonthChange={setDisplayMonth}
                                                            disabled={(date) => date < new Date(new Date().setHours(0, 0, 0, 0))}
                                                            initialFocus
                                                            locale={es}
                                                        />
                                                    </PopoverContent>
                                                </Popover>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />

                                    {/* Campo de Hora */}
                                    <FormField
                                        control={form.control}
                                        name="time"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Hora *</FormLabel>
                                                <Select onValueChange={field.onChange} value={field.value}>
                                                    <FormControl>
                                                        <SelectTrigger>
                                                            <Clock className="mr-2 h-4 w-4" />
                                                            <SelectValue placeholder="Selecciona una hora" />
                                                        </SelectTrigger>
                                                    </FormControl>
                                                    <SelectContent className="max-h-[300px]">
                                                        {timeSlots.map((slot) => (
                                                            <SelectItem key={slot.value} value={slot.value}>
                                                                {slot.label}
                                                            </SelectItem>
                                                        ))}
                                                    </SelectContent>
                                                </Select>
                                                <FormMessage />

                                                {/* MENSAJE DE ERROR DE DISPONIBILIDAD */}
                                                {!validacion.disponible && (
                                                    <div className="mt-2 text-sm text-red-600 bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-800 rounded-md p-3 flex items-start gap-2">
                                                        <AlertCircle className="h-4 w-4 mt-0.5 flex-shrink-0" />
                                                        <span>{validacion.mensaje}</span>
                                                    </div>
                                                )}
                                            </FormItem>
                                        )}
                                    />
                                </div>
                            </div>

                            {/* 👤 SECCIÓN 2: SELECTOR DE PACIENTE */}
                            <div className="space-y-4">
                                <div className="flex items-center gap-2 pb-2 border-b border-slate-100">
                                    <User className="h-4 w-4 text-primary" />
                                    <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Paciente</h3>
                                </div>
                                <FormField
                                    control={form.control}
                                    name="patientName"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Paciente *</FormLabel>
                                            <FormControl>
                                                <div className="relative">
                                                    {/* Mostrar campo de búsqueda solo si NO hay paciente seleccionado */}
                                                    {!form.watch("patientId") && !isNewPatient && (
                                                        <>
                                                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                                                            <Input
                                                                placeholder="Buscar paciente por nombre o DNI..."
                                                                className="pl-10"
                                                                autoComplete="none"
                                                                value={searchPatient}
                                                                onChange={(e) => {
                                                                    setSearchPatient(e.target.value);
                                                                    form.setValue("isNewPatient", false);
                                                                    form.setValue("patientName", "");
                                                                }}
                                                                disabled={loadingPatients}
                                                            />
                                                            {loadingPatients && (
                                                                <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 animate-spin text-muted-foreground" />
                                                            )}
                                                        </>
                                                    )}

                                                    {/* Mostrar nombre del paciente seleccionado con opción de cambiar */}
                                                    {(form.watch("patientId") || isNewPatient) && (
                                                        <div className="flex items-center gap-2">
                                                            <div className="flex-1 px-3 py-2 bg-primary/5 border border-primary/20 rounded-md">
                                                                <span className="font-medium">{form.watch("patientName")}</span>
                                                            </div>
                                                            <Button
                                                                type="button"
                                                                variant="outline"
                                                                size="sm"
                                                                onClick={() => {
                                                                    form.setValue("patientId", "");
                                                                    form.setValue("patientName", "");
                                                                    form.setValue("isNewPatient", false);
                                                                    setSearchPatient("");
                                                                }}
                                                            >
                                                                Cambiar
                                                            </Button>
                                                        </div>
                                                    )}
                                                </div>
                                            </FormControl>

                                            {/* Lista de resultados */}
                                            {searchPatient && !loadingPatients && !form.watch("patientId") && !isNewPatient && (
                                                <div className="mt-2 border rounded-md max-h-[200px] overflow-y-auto bg-card">
                                                    {filteredPatients.length > 0 ? (
                                                        <div className="p-1">
                                                            {filteredPatients.map((patient) => (
                                                                <button
                                                                    key={patient.id}
                                                                    type="button"
                                                                    onClick={() => {
                                                                        const capitalizedName = capitalizeName(
                                                                            `${patient.nombre} ${patient.apellido_paterno} ${patient.apellido_materno}`
                                                                        );
                                                                        form.setValue("patientId", patient.id!);
                                                                        form.setValue("patientName", capitalizedName);
                                                                        form.setValue("isNewPatient", false);
                                                                        setSearchPatient(capitalizedName);
                                                                    }}
                                                                    className="w-full text-left px-3 py-2 hover:bg-accent rounded-md transition-colors"
                                                                >
                                                                    <div className="font-medium">
                                                                        {capitalizeName(`${patient.nombre} ${patient.apellido_paterno} ${patient.apellido_materno}`)}
                                                                    </div>
                                                                    <div className="text-sm text-muted-foreground">
                                                                        DNI: {patient.dni_cliente}
                                                                    </div>
                                                                </button>
                                                            ))}
                                                        </div>
                                                    ) : (
                                                        <div className="p-4 text-center">
                                                            <p className="text-sm text-muted-foreground mb-3">
                                                                No se encontró paciente con ese nombre o DNI
                                                            </p>
                                                            <Button
                                                                type="button"
                                                                variant="outline"
                                                                size="sm"
                                                                onClick={() => {
                                                                    form.setValue("isNewPatient", true);
                                                                    form.setValue("patientName", searchPatient);
                                                                }}
                                                            >
                                                                <UserPlus className="h-4 w-4 mr-2" />
                                                                Crear nuevo paciente "{searchPatient}"
                                                            </Button>
                                                        </div>
                                                    )}
                                                </div>
                                            )}
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />

                                {/* Campos condicionales para nuevo paciente */}
                                {isNewPatient && (
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4 border rounded-lg bg-primary/5 dark:bg-primary/10 border-primary/20">
                                        <div className="col-span-2">
                                            <p className="text-sm font-medium mb-2">
                                                Completar datos del nuevo paciente
                                            </p>
                                        </div>

                                        <FormField
                                            control={form.control}
                                            name="newPatientDni"
                                            render={({ field }) => (
                                                <FormItem>
                                                    <FormLabel>DNI *</FormLabel>
                                                    <FormControl>
                                                        <Input
                                                            placeholder="8 dígitos"
                                                            maxLength={8}
                                                            autoComplete="none"
                                                            {...field}
                                                            onChange={(e) => {
                                                                const val = e.target.value.replace(/\D/g, "");
                                                                if (val.length > 0 && val[0] === '0') return;
                                                                field.onChange(val);
                                                            }}
                                                        />
                                                    </FormControl>
                                                    <FormMessage />
                                                </FormItem>
                                            )}
                                        />

                                        <FormField
                                            control={form.control}
                                            name="newPatientPhone"
                                            render={({ field }) => (
                                                <FormItem>
                                                    <FormLabel>Celular *</FormLabel>
                                                    <FormControl>
                                                        <div className="flex">
                                                            <div className="flex items-center justify-center px-3 border border-r-0 rounded-l-md bg-primary/5 text-sm font-semibold">
                                                                +51
                                                            </div>
                                                            <Input
                                                                placeholder="999888777"
                                                                maxLength={9}
                                                                className="rounded-l-none"
                                                                autoComplete="none"
                                                                {...field}
                                                                onChange={(e) => {
                                                                    const val = e.target.value.replace(/\D/g, "");
                                                                    if (val.length > 0 && val[0] !== '9') return;
                                                                    field.onChange(val);
                                                                }}
                                                            />
                                                        </div>
                                                    </FormControl>
                                                    <FormMessage />
                                                </FormItem>
                                            )}
                                        />
                                    </div>
                                )}

                                {/* Sección de tratamientos activos */}
                                {watchedPatientId && !isNewPatient && (
                                    <>
                                        <div className="flex items-center justify-between mb-3">
                                            <p className="text-sm font-semibold">
                                                Tratamientos Activos
                                            </p>
                                            {loadingTreatments && (
                                                <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                                            )}
                                        </div>

                                        {!loadingTreatments && activeTreatments.length === 0 && (
                                            <p className="text-sm text-muted-foreground italic mb-3">
                                                No hay tratamientos activos
                                            </p>
                                        )}

                                        {!loadingTreatments && activeTreatments.length > 0 && (
                                            <div className="space-y-2 mb-4">
                                                {activeTreatments.map((treatment) => {
                                                    const isSelected = selectedTreatmentId === treatment.id;
                                                    return (
                                                        <button
                                                            key={treatment.id}
                                                            type="button"
                                                            onClick={() => {
                                                                if (isSelected) {
                                                                    setSelectedTreatmentId(null);
                                                                } else {
                                                                    setSelectedTreatmentId(treatment.id);
                                                                    form.setValue("duration", "45");
                                                                }
                                                            }}
                                                            className={`w-full text-left p-3 rounded-md border-0.5 transition-all ${isSelected
                                                                ? 'border-green-500 bg-green-100 dark:bg-green-900/40 ring-2 ring-green-500'
                                                                : 'border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 hover:border-green-400'
                                                                }`}
                                                        >
                                                            <div className="flex items-start justify-between">
                                                                <p className="font-medium text-sm">{treatment.tratamiento}</p>
                                                                {isSelected && (
                                                                    <span className="text-xs bg-green-500 text-white px-2 py-1 rounded">
                                                                        Seleccionado
                                                                    </span>
                                                                )}
                                                            </div>
                                                            <div className="flex items-center justify-between mt-1">
                                                                <span className="text-xs text-muted-foreground">
                                                                    Pendiente: S/ {treatment.pago_pendiente.toFixed(2)}
                                                                </span>
                                                                <span className="text-xs text-muted-foreground">
                                                                    Total: S/ {treatment.total_presupuesto.toFixed(2)}
                                                                </span>
                                                            </div>
                                                        </button>
                                                    );
                                                })}
                                            </div>
                                        )}
                                    </>
                                )}
                            </div>

                            {/* 3️⃣ TIPO DE CONSULTA - Solo si NO hay tratamiento seleccionado */}
                            {!selectedTreatmentId && (
                                <FormField
                                    control={form.control}
                                    name="consultation"
                                    render={({ field }) => (
                                        <FormItem>
                                            <div className="grid grid-cols-[140px_1fr] items-center gap-4">
                                                <FormLabel className="text-right">Tipo de Consulta *</FormLabel>
                                                <div className="space-y-2">
                                                    <Select
                                                        onValueChange={(val) => {
                                                            field.onChange(val);
                                                            form.setValue("duration", "30");
                                                        }}
                                                        value={field.value}
                                                    >
                                                        <FormControl>
                                                            <SelectTrigger>
                                                                <SelectValue placeholder="Selecciona el tipo de consulta" />
                                                            </SelectTrigger>
                                                        </FormControl>
                                                        <SelectContent>
                                                            {consultationTypes.map((item) => (
                                                                <SelectItem key={item.type} value={item.type}>
                                                                    {item.type} - S/ {item.cost}
                                                                </SelectItem>
                                                            ))}
                                                        </SelectContent>
                                                    </Select>
                                                    <FormMessage />
                                                </div>
                                            </div>
                                        </FormItem>
                                    )}
                                />
                            )}

                            {/* 4️⃣ DURACIÓN */}
                            <FormField
                                control={form.control}
                                name="duration"
                                render={({ field }) => (
                                    <FormItem>
                                        <div className="grid grid-cols-[140px_1fr] items-center gap-4">
                                            <FormLabel className="text-right">Duración aprox.*</FormLabel>
                                            <div className="space-y-2">
                                                <Select onValueChange={field.onChange} value={field.value}>
                                                    <FormControl>
                                                        <SelectTrigger>
                                                            <SelectValue placeholder="Selecciona la duración" />
                                                        </SelectTrigger>
                                                    </FormControl>
                                                    <SelectContent>
                                                        {DURATIONS.map((duration) => (
                                                            <SelectItem key={duration.value} value={duration.value}>
                                                                {duration.label}
                                                            </SelectItem>
                                                        ))}
                                                    </SelectContent>
                                                </Select>
                                                <FormMessage />
                                            </div>
                                        </div>
                                    </FormItem>
                                )}
                            />

                            {/* 5️⃣ NOTAS Y OBSERVACIONES */}
                            <FormField
                                control={form.control}
                                name="notes"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Notas y Observaciones</FormLabel>
                                        <FormControl>
                                            <Textarea
                                                placeholder="Escribe aquí cualquier información adicional sobre la cita"
                                                className="min-h-[100px] resize-none"
                                                {...field}
                                                value={field.value || ""}
                                                onChange={(e) => {
                                                    const formatted = formatNotes(e.target.value);
                                                    field.onChange(formatted);
                                                }}
                                                onKeyDown={(e) => handleNotesKeyDown(e, field.value || "", field.onChange)}
                                            />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                        </form>
                    </Form>
                </div>

                <div className="px-6 py-5 border-t border-slate-100 flex justify-end gap-3 bg-white flex-none">
                    <Button
                        type="button"
                        variant="outline"
                        onClick={() => {
                            onOpenChange(false);
                            form.reset();
                            setSearchPatient("");
                        }}
                        className="rounded-xl h-11 px-6 border-slate-200 text-slate-600 hover:bg-slate-50 transition-all font-medium"
                        disabled={loading}
                    >
                        Cancelar
                    </Button>
                    <Button
                        type="submit"
                        form="appointment-form"
                        disabled={loading || !validacion.disponible}
                        className="bg-primary hover:bg-primary/90 text-white rounded-xl h-11 px-8 font-bold shadow-lg shadow-primary/20 transition-all disabled:opacity-50 disabled:shadow-none"
                    >
                        {loading ? (
                            <>
                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                Procesando...
                            </>
                        ) : (
                            "Agendar Cita"
                        )}
                    </Button>
                </div>
            </DialogContent>
        </Dialog>
    );
}

// src/components/AppointmentEditDialog.tsx
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from "@/components/ui/form";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import {
    Popover,
    PopoverContent,
    PopoverTrigger,
} from "@/components/ui/popover";
import { Textarea } from "@/components/ui/textarea";
import { Calendar as CalendarIcon, Clock, Loader2 } from "lucide-react";
import { format } from "date-fns";
import { es } from "date-fns/locale";
import { cn } from "@/lib/utils";
import { toast } from "@/hooks/use-toast";
import { updateAppointment } from "@/services/appointmentService";
import { useAuthContext } from "@/context/AuthContext";
import { DURATIONS } from "@/constants/appointmentConstants";
import { useConsultationPrices } from "@/hooks/useConsultationPrices";
import { formatNotes, handleNotesKeyDown } from "@/utils/formatters";
import { useActivityLog } from "@/hooks/useActivityLog";

const APPOINTMENT_STATUSES = [
    { value: "pendiente", label: "Pendiente" },
    { value: "confirmada", label: "Confirmada" },
    { value: "atendiendo", label: "Atendiendo" },
    { value: "atendida", label: "Atendida" },
    { value: "cancelada", label: "Cancelada" },
    { value: "reprogramada", label: "Reprogramada" },
];

const editAppointmentSchema = z.object({
    date: z.date({
        required_error: "La fecha es requerida",
    }),
    time: z.string().min(1, "La hora es requerida"),
    consultation: z.string().optional(),
    duration: z.string().min(1, "Debe seleccionar una duración"),
    status: z.string().min(1, "Debe seleccionar un estado"),
    notes: z.string().optional(),
});

type EditAppointmentFormValues = z.infer<typeof editAppointmentSchema>;

interface AppointmentEditDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    appointment: {
        id: string;
        date: Date;
        time: string;
        patient: string;
        treatment: string;
        duration: string;
        status: string;
        notes?: string;
    } | null;
    onBack?: () => void;
    onSuccess?: () => void;
}

export default function AppointmentEditDialog({
    open,
    onOpenChange,
    appointment,
    onBack,
    onSuccess,
}: AppointmentEditDialogProps) {
    const { prices: consultationTypes } = useConsultationPrices();
    const { user, userProfile } = useAuthContext();
    const userName = userProfile
        ? `${userProfile.nombre.split(' ')[0]} ${userProfile.apellidoPaterno}`
        : user?.displayName || "Sistema";
    const { log } = useActivityLog();

    const [loading, setLoading] = useState(false);
    const [displayMonth, setDisplayMonth] = useState<Date>(appointment?.date || new Date());

    const form = useForm<EditAppointmentFormValues>({
        resolver: zodResolver(editAppointmentSchema),
        defaultValues: {
            date: new Date(),
            time: "",
            consultation: "",
            duration: "30",
            status: "pendiente",
            notes: "",
        },
    });

    // Normalizar estado de inglés a español
    const normalizeStatus = (status: string): string => {
        const statusMap: Record<string, string> = {
            'confirmed': 'confirmada',
            'pending': 'pendiente',
            'attending': 'atendiendo',
            'attended': 'atendida',
            'completed': 'atendida',
            'completada': 'atendida',
            'cancelled': 'cancelada',
            'reprogramed': 'reprogramada',
        };
        return statusMap[status?.toLowerCase()] || status;
    };

    // Verificar si la cita está reprogramada
    const isRescheduled = appointment ? normalizeStatus(appointment.status) === "reprogramada" : false;

    // Verificar si la cita es de tratamiento (el tipo_consulta empieza con "Tratamiento:")
    const isTreatmentAppointment = appointment?.treatment?.startsWith("Tratamiento:") ?? false;

    // Cargar datos cuando se abre el diálogo
    useEffect(() => {
        if (open && appointment) {
            const durationMatch = appointment.duration.match(/\d+/);
            const durationValue = durationMatch ? durationMatch[0] : "30";

            form.reset({
                date: appointment.date,
                time: appointment.time,
                consultation: appointment.treatment,
                duration: durationValue,
                status: normalizeStatus(appointment.status),
                notes: appointment.notes || "",
            });
        }
    }, [open, appointment, form]);

    // Generar slots de tiempo (7 AM - 11 PM, cada 15 min)
    const generateTimeSlots = () => {
        const slots = [];
        for (let hour = 7; hour <= 23; hour++) {
            for (let minute = 0; minute < 60; minute += 15) {
                const timeValue = `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`;
                slots.push({ value: timeValue, label: timeValue });
            }
        }
        return slots;
    };

    const timeSlots = generateTimeSlots();

    const onSubmit = async (data: EditAppointmentFormValues) => {
        if (!appointment) return;

        setLoading(true);

        try {
            const updateData = {
                fecha: data.date,
                hora: data.time,
                tipo_consulta: data.consultation,
                duracion: data.duration,
                estado: data.status as any,
                notas_observaciones: data.notes || "",
            };

            await updateAppointment(appointment.id, updateData, userName);

            toast({
                title: "✅ Cita actualizada",
                description: "Los cambios se han guardado correctamente.",
            });

            log({
                modulo: "Calendario",
                accion: "editó",
                entidad: "cita",
                entidad_id: appointment!.id,
                entidad_nombre: `cita del ${format(data.date, "d MMM", { locale: es })} a las ${data.time}`,
                paciente_nombre: appointment!.patient,
            });

            onOpenChange(false);

            // Esperar un momento antes de recargar para que Firebase procese
            setTimeout(() => {
                onSuccess?.();
            }, 500);

        } catch (error: any) {
            console.error("Error al actualizar cita:", error);

            toast({
                title: "❌ Error al actualizar",
                description: error.message || "No se pudieron guardar los cambios. Revisa la consola.",
                variant: "destructive",
            });
        } finally {
            setLoading(false);
        }
    };

    if (!appointment) return null;

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle className="text-xl font-semibold">
                        Editar Cita
                    </DialogTitle>
                </DialogHeader>

                <Form {...form}>
                    <form autoComplete="off" onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                        {/* Información del Paciente - Una sola fila */}
                        <div className="p-3 bg-muted/50 rounded-lg border">
                            <p className="text-xs font-medium text-muted-foreground mb-1">Paciente</p>
                            <p className="text-base font-semibold">{appointment.patient}</p>
                        </div>

                        {/* Fecha y Hora */}
                        <div className="grid grid-cols-2 gap-3">
                            <FormField
                                control={form.control}
                                name="date"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel className="text-sm">Fecha de la Cita *</FormLabel>
                                        <Popover>
                                            <PopoverTrigger asChild>
                                                <FormControl>
                                                    <Button
                                                        variant="outline"
                                                        disabled={isRescheduled}
                                                        className={cn(
                                                            "w-full pl-3 text-left font-normal h-10",
                                                            !field.value && "text-muted-foreground",
                                                            isRescheduled && "opacity-60 cursor-not-allowed"
                                                        )}
                                                    >
                                                        {field.value ? (
                                                            format(field.value, "PPP", { locale: es })
                                                        ) : (
                                                            <span>Selecciona una fecha</span>
                                                        )}
                                                        <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                                                    </Button>
                                                </FormControl>
                                            </PopoverTrigger>
                                            {!isRescheduled && (
                                                <PopoverContent className="w-auto p-3" align="start">
                                                    <div className="flex justify-between mb-2 gap-2">
                                                        <select
                                                            className="border rounded-md px-2 py-1 text-xs"
                                                            value={displayMonth.getMonth()}
                                                            onChange={(e) =>
                                                                setDisplayMonth(
                                                                    new Date(displayMonth.getFullYear(), parseInt(e.target.value))
                                                                )
                                                            }
                                                        >
                                                            {Array.from({ length: 12 }, (_, i) => (
                                                                <option key={i} value={i}>
                                                                    {format(new Date(0, i), "MMMM", { locale: es })}
                                                                </option>
                                                            ))}
                                                        </select>

                                                        <select
                                                            className="border rounded-md px-2 py-1 text-xs"
                                                            value={displayMonth.getFullYear()}
                                                            onChange={(e) =>
                                                                setDisplayMonth(
                                                                    new Date(parseInt(e.target.value), displayMonth.getMonth())
                                                                )
                                                            }
                                                        >
                                                            {Array.from({ length: 11 }, (_, i) => new Date().getFullYear() + i - 1).map((y) => (
                                                                <option key={y} value={y}>
                                                                    {y}
                                                                </option>
                                                            ))}
                                                        </select>
                                                    </div>
                                                    <Calendar
                                                        mode="single"
                                                        selected={field.value}
                                                        onSelect={(date) => {
                                                            field.onChange(date);
                                                        }}
                                                        month={displayMonth}
                                                        onMonthChange={setDisplayMonth}
                                                        disabled={(date) => date < new Date(new Date().setHours(0, 0, 0, 0))}
                                                        initialFocus
                                                        locale={es}
                                                    />
                                                </PopoverContent>
                                            )}
                                        </Popover>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="time"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel className="text-sm">Hora *</FormLabel>
                                        <Select
                                            onValueChange={field.onChange}
                                            value={field.value}
                                            disabled={isRescheduled}
                                        >
                                            <FormControl>
                                                <SelectTrigger
                                                    className={cn(
                                                        "h-10",
                                                        isRescheduled && "opacity-60 cursor-not-allowed"
                                                    )}
                                                >
                                                    <Clock className="mr-2 h-4 w-4" />
                                                    <SelectValue placeholder="Selecciona una hora" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent className="max-h-[300px]">
                                                {timeSlots.map((slot) => (
                                                    <SelectItem key={slot.value} value={slot.value}>
                                                        {slot.label}
                                                    </SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                        </div>

                        {/* Tipo de Consulta - Solo si NO es cita de tratamiento */}
                        {!isTreatmentAppointment && (
                            <FormField
                                control={form.control}
                                name="consultation"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel className="text-sm">Tipo de Consulta *</FormLabel>
                                        <Select
                                            onValueChange={(val) => {
                                                field.onChange(val);
                                                form.setValue("duration", "30");
                                            }}
                                            value={field.value}
                                        >
                                            <FormControl>
                                                <SelectTrigger className="h-10">
                                                    <SelectValue placeholder="Selecciona el tipo de consulta" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                {consultationTypes.map((c) => (
                                                    <SelectItem key={c.type} value={c.type}>
                                                        {c.type}
                                                    </SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                        )}

                        {/* Mostrar info del tratamiento si es cita de tratamiento */}
                        {isTreatmentAppointment && (
                            <div className="p-3 bg-blue-50 dark:bg-blue-950/20 rounded-lg border border-blue-200 dark:border-blue-800">
                                <p className="text-xs font-medium text-blue-900 dark:text-blue-100 mb-1">Tratamiento</p>
                                <p className="text-sm font-semibold text-blue-700 dark:text-blue-300">
                                    {appointment.treatment}
                                </p>
                            </div>
                        )}

                        {/* Duración */}
                        <FormField
                            control={form.control}
                            name="duration"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel className="text-sm">Duración aproximada *</FormLabel>
                                    <Select onValueChange={field.onChange} value={field.value}>
                                        <FormControl>
                                            <SelectTrigger className="h-10">
                                                <SelectValue placeholder="Selecciona la duración" />
                                            </SelectTrigger>
                                        </FormControl>
                                        <SelectContent>
                                            {DURATIONS.map((duration) => (
                                                <SelectItem key={duration.value} value={duration.value}>
                                                    {duration.label}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        {/* Notas */}
                        <FormField
                            control={form.control}
                            name="notes"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel>Notas y Observaciones</FormLabel>
                                    <FormControl>
                                        <Textarea
                                            placeholder="Escribe aquí cualquier información adicional sobre la cita"
                                            className="min-h-[100px] resize-none"
                                            {...field}
                                            value={field.value || ""}
                                            onChange={(e) => {
                                                const formatted = formatNotes(e.target.value);
                                                field.onChange(formatted);
                                            }}
                                            onKeyDown={(e) => handleNotesKeyDown(e, field.value || "", field.onChange)}
                                        />
                                    </FormControl>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        {/* Botones */}
                        <div className="flex justify-end gap-3 pt-3 border-t">
                            {!form.formState.isDirty ? (
                                <Button
                                    type="button"
                                    variant="outline"
                                    onClick={() => {
                                        onOpenChange(false);
                                        onBack?.();
                                    }}
                                    disabled={loading}
                                >
                                    Volver
                                </Button>
                            ) : (
                                <>
                                    <Button
                                        type="button"
                                        variant="outline"
                                        onClick={() => onOpenChange(false)}
                                        disabled={loading}
                                    >
                                        Cancelar
                                    </Button>
                                    <Button type="submit" disabled={loading}>
                                        {loading ? (
                                            <>
                                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                                Guardando...
                                            </>
                                        ) : (
                                            "Guardar Cambios"
                                        )}
                                    </Button>
                                </>
                            )}
                        </div>
                    </form>
                </Form>
            </DialogContent>
        </Dialog>
    );
}

// src/components/AppointmentRescheduleDialog.tsx
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import {
  Calendar as CalendarIcon,
  Clock,
  Loader2,
  CalendarClock,
  User,
  Stethoscope,
} from "lucide-react";
import { format } from "date-fns";
import { es } from "date-fns/locale";
import { cn } from "@/lib/utils";
import { toast } from "@/hooks/use-toast";
import { updateAppointment } from "@/services/appointmentService";
import { useAuthContext } from "@/context/AuthContext";
import { useActivityLog } from "@/hooks/useActivityLog";

// ══════════ SCHEMA — Solo fecha y hora ══════════
const rescheduleSchema = z.object({
  date: z.date({ required_error: "La fecha es requerida" }),
  time: z.string().min(1, "La hora es requerida"),
});

type RescheduleFormValues = z.infer<typeof rescheduleSchema>;

// ══════════ INTERFACES ══════════
interface AppointmentRescheduleDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  appointment: {
    id: string;
    date: Date;
    time: string;
    patient: string;
    treatment: string;
    duration: string;
    status: string;
  } | null;
  onSuccess?: () => void;
}

export default function AppointmentRescheduleDialog({
  open,
  onOpenChange,
  appointment,
  onSuccess,
}: AppointmentRescheduleDialogProps) {
  const { user, userProfile } = useAuthContext();
  const userName = userProfile
    ? `${userProfile.nombre.split(' ')[0]} ${userProfile.apellidoPaterno}`
    : user?.displayName || "Sistema";
  const { log } = useActivityLog();

  const [loading, setLoading] = useState(false);

  const form = useForm<RescheduleFormValues>({
    resolver: zodResolver(rescheduleSchema),
    defaultValues: {
      date: undefined,
      time: "",
    },
  });

  // Resetear form cuando se abre con nueva cita
  useEffect(() => {
    if (appointment && open) {
      const aptDate =
        appointment.date instanceof Date
          ? appointment.date
          : new Date(appointment.date);

      form.reset({
        date: aptDate,
        time: appointment.time,
      });
    }
  }, [appointment, open, form]);

  // Generar slots de tiempo (7:00 AM - 8:00 PM, cada 15 min)
  const generateTimeSlots = () => {
    const slots: { value: string; label: string }[] = [];
    for (let hour = 7; hour <= 23; hour++) {
      for (let minute = 0; minute < 60; minute += 15) {
        const timeValue = `${hour.toString().padStart(2, "0")}:${minute
          .toString()
          .padStart(2, "0")}`;
        slots.push({
          value: timeValue,
          label: timeValue,
        });
      }
    }
    return slots;
  };

  const timeSlots = generateTimeSlots();

  // ══════════ SUBMIT ══════════
  const onSubmit = async (data: RescheduleFormValues) => {
    if (!appointment) return;

    setLoading(true);

    try {
      await updateAppointment(appointment.id, {
        fecha: data.date,
        hora: data.time,
        estado: "reprogramada" as any,
      }, userName);

      log({ modulo: "Calendario", accion: "reprogramó", entidad: "cita", entidad_id: appointment.id, entidad_nombre: `cita del ${format(data.date, "PPP", { locale: es })}`, paciente_nombre: appointment.patient });

      toast({
        title: "✅ Cita reprogramada",
        description: `La cita ha sido reprogramada al ${format(data.date, "PPP", { locale: es })} a las ${data.time}.`,
      });

      onOpenChange(false);
      setTimeout(() => {
        onSuccess?.();
      }, 500);
    } catch (error: any) {
      console.error("Error al reprogramar cita:", error);
      toast({
        title: "❌ Error",
        description: "No se pudo reprogramar la cita.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  if (!appointment) return null;

  const originalDate =
    appointment.date instanceof Date
      ? appointment.date
      : new Date(appointment.date);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-lg">
            <CalendarClock className="h-5 w-5 text-orange-500" />
            Reprogramar Cita
          </DialogTitle>
        </DialogHeader>

        {/* Info de la cita actual (solo lectura) */}
        <div className="p-3 bg-muted/50 rounded-lg border space-y-1.5">
          <div className="flex items-center gap-2">
            <User className="h-3.5 w-3.5 text-muted-foreground" />
            <span className="text-sm font-semibold text-foreground">
              {appointment.patient}
            </span>
          </div>
          <div className="flex items-center gap-4 text-xs text-muted-foreground">
            <span className="flex items-center gap-1">
              <Stethoscope className="h-3 w-3" />
              {appointment.treatment}
            </span>
            <span className="flex items-center gap-1">
              <Clock className="h-3 w-3" />
              {appointment.duration}
            </span>
          </div>
          <div className="text-xs text-muted-foreground pt-1 border-t border-border/50">
            <span className="font-medium">Fecha original:</span>{" "}
            {format(originalDate, "PPP", { locale: es })} a las{" "}
            {appointment.time}
          </div>
        </div>

        {/* Formulario — solo fecha y hora */}
        <Form {...form}>
          <form autoComplete="off" onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              {/* Nueva Fecha */}
              <FormField
                control={form.control}
                name="date"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-xs">Nueva Fecha *</FormLabel>
                    <Popover>
                      <PopoverTrigger asChild>
                        <FormControl>
                          <Button
                            variant="outline"
                            className={cn(
                              "w-full pl-3 text-left font-normal h-9 text-sm",
                              !field.value && "text-muted-foreground"
                            )}
                          >
                            {field.value
                              ? format(field.value, "dd/MM/yyyy")
                              : "Seleccionar"}
                            <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                          </Button>
                        </FormControl>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0" align="start">
                        <Calendar
                          mode="single"
                          selected={field.value}
                          onSelect={field.onChange}
                          disabled={(date) => date < new Date(new Date().setHours(0, 0, 0, 0))}
                          initialFocus
                          locale={es}
                        />
                      </PopoverContent>
                    </Popover>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Nueva Hora */}
              <FormField
                control={form.control}
                name="time"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-xs">Nueva Hora *</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl>
                        <SelectTrigger className="h-9 text-sm">
                          <SelectValue placeholder="Hora" />
                        </SelectTrigger>
                      </FormControl>
                      <SelectContent className="max-h-60">
                        {timeSlots.map((slot) => (
                          <SelectItem key={slot.value} value={slot.value}>
                            {slot.label}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            {/* Botones */}
            <div className="flex justify-end gap-2 pt-2 border-t">
              <Button
                type="button"
                variant="outline"
                size="sm"
                onClick={() => onOpenChange(false)}
                disabled={loading}
              >
                Cancelar
              </Button>
              <Button
                type="submit"
                size="sm"
                disabled={loading}
                className="bg-orange-500 hover:bg-orange-600 text-white"
              >
                {loading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Reprogramando...
                  </>
                ) : (
                  <>
                    <CalendarClock className="mr-2 h-4 w-4" />
                    Reprogramar
                  </>
                )}
              </Button>
            </div>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

// src/components/GoogleCalendarView.tsx
import { useState, useEffect, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import {
  ChevronLeft,
  ChevronRight,
  Plus,
  User,
  Stethoscope,
} from "lucide-react";
import { format, addWeeks, subWeeks, startOfWeek, addDays, isSameDay } from "date-fns";
import { es } from "date-fns/locale";
import { APPOINTMENT_STATUS_CONFIG, NORMALIZE_STATUS } from "@/constants/appointmentConstants";

interface Appointment {
  id: string;
  time: string;
  patient: string;
  patientId: string;
  dentist: string;
  dentistId: string;
  treatment: string;
  duration: string;
  status: string;
  date: Date;
  notes?: string;
  color: string;
  // Nuevos campos para distinguir entre consulta y tratamiento
  isTreatment: boolean;
  treatmentName?: string;
  consultationType?: string;
}

interface GoogleCalendarViewProps {
  appointments: Appointment[];
  onSlotClick: (date: Date, time: string) => void;
  onNewAppointment: () => void;
  onAppointmentClick: (appointment: Appointment) => void;
}

const DEFAULT_COLOR = "#F59E0B";

const getStatusColor = (status: string): string => {
  const key = NORMALIZE_STATUS[status?.toLowerCase() || ''];
  return key ? APPOINTMENT_STATUS_CONFIG[key].hex : DEFAULT_COLOR;
};

const STATUS_LABELS: Record<string, string> = Object.fromEntries([
  ...Object.entries(APPOINTMENT_STATUS_CONFIG).map(([k, v]) => [k, v.label]),
  ["confirmed", "Confirmada"],
  ["pending", "Pendiente"],
  ["attending", "Atendiendo"],
  ["attended", "Atendida"],
  ["completed", "Atendida"],
  ["cancelled", "Cancelada"],
  ["reprogramed", "Reprogramada"],
]);

export default function GoogleCalendarView({
  appointments,
  onSlotClick,
  onNewAppointment,
  onAppointmentClick
}: GoogleCalendarViewProps) {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [viewType, setViewType] = useState("week");
  const [hoveredAppointmentId, setHoveredAppointmentId] = useState<string | null>(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const hasScrolledToCurrentTime = useRef(false);

  // Actualizar la hora actual cada 30 segundos para mantener la línea precisa
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date());
    }, 30000); // Actualizar cada 30 segundos

    return () => clearInterval(timer);
  }, []);

  // ══════════ FILTRAR CITAS CANCELADAS ══════════
  // Las citas canceladas NO se muestran en el calendario
  const visibleAppointments = appointments.filter(apt => {
    const status = apt.status?.toLowerCase() || '';
    return status !== "cancelada" && status !== "cancelled";
  });

  // Generar horas de 7 AM a 12 AM (medianoche) con intervalos de 30 minutos
  const generateHours = () => {
    const hours = [];
    for (let i = 7; i <= 24; i++) {
      // Slot :00 - muestra la hora completa
      const period00 = i >= 12 && i < 24 ? 'PM' : 'AM';
      const displayHour00 = i === 12 ? 12 : i === 24 ? 12 : i > 12 ? i - 12 : i;
      hours.push({
        value: i,
        label: `${displayHour00} ${period00}`,  // Sin :00
        time: `${(i % 24).toString().padStart(2, '0')}:00`,
        showLabel: true  // Mostrar etiqueta
      });

      // Slot :30 (excepto para la última hora - medianoche)
      if (i < 24) {
        const period30 = i >= 12 && i < 24 ? 'PM' : 'AM';
        const displayHour30 = i === 12 ? 12 : i > 12 ? i - 12 : i;
        hours.push({
          value: i + 0.5,
          label: '',  // Sin etiqueta
          time: `${(i % 24).toString().padStart(2, '0')}:30`,
          showLabel: false  // No mostrar etiqueta
        });
      }
    }
    return hours;
  };

  const hours = generateHours();

  // Obtener días de la semana
  const getWeekDays = () => {
    const start = startOfWeek(currentDate, { weekStartsOn: 1 });
    return Array.from({ length: 7 }, (_, i) => addDays(start, i));
  };

  const weekDays = getWeekDays();

  // Formatear rango de fechas
  const getDateRange = () => {
    const start = weekDays[0];
    const end = weekDays[6];
    if (start.getMonth() === end.getMonth()) {
      return format(start, "MMMM yyyy", { locale: es });
    }
    return `${format(start, "MMM", { locale: es })} – ${format(end, "MMM yyyy", { locale: es })}`;
  };

  // Navegación
  const goToPreviousWeek = () => setCurrentDate(subWeeks(currentDate, 1));
  const goToNextWeek = () => setCurrentDate(addWeeks(currentDate, 1));
  const goToToday = () => setCurrentDate(new Date());

  const isToday = (date: Date) => isSameDay(date, new Date());

  // Convertir hora string a minutos desde medianoche
  const timeToMinutes = (time: string): number => {
    const [hours, minutes] = time.split(':').map(Number);
    return hours * 60 + (minutes || 0);
  };

  // Verificar si dos citas se solapan
  const appointmentsOverlap = (apt1: Appointment, apt2: Appointment): boolean => {
    const start1 = timeToMinutes(apt1.time);
    const end1 = start1 + parseInt(apt1.duration);
    const start2 = timeToMinutes(apt2.time);
    const end2 = start2 + parseInt(apt2.duration);

    return start1 < end2 && start2 < end1;
  };

  // Asignar columnas a citas para evitar solapamiento
  const assignColumns = (appointments: Appointment[]): Map<string, number> => {
    const columnMap = new Map<string, number>();
    const columns: Appointment[][] = [[], [], [], []]; // 4 columnas disponibles

    // Ordenar por hora de inicio
    const sortedApts = [...appointments].sort((a, b) =>
      timeToMinutes(a.time) - timeToMinutes(b.time)
    );

    for (const apt of sortedApts) {
      // Buscar la primera columna donde no haya solapamiento
      let assignedColumn = -1;

      for (let col = 0; col < 4; col++) {
        const hasOverlap = columns[col].some(existingApt =>
          appointmentsOverlap(apt, existingApt)
        );

        if (!hasOverlap) {
          assignedColumn = col;
          columns[col].push(apt);
          break;
        }
      }

      // Si encontró columna libre, asignarla
      if (assignedColumn !== -1) {
        columnMap.set(apt.id, assignedColumn);
      }
    }

    return columnMap;
  };

  // Obtener citas para un slot horario específico (max 4)
  const getAppointmentsForSlot = (date: Date, time: string): Appointment[] => {
    const slotHour = parseInt(time.split(':')[0]);
    const slotMinutes = parseInt(time.split(':')[1] || '0');
    const slotStartMinutes = slotHour * 60 + slotMinutes;

    const slotAppointments = visibleAppointments.filter(apt => {
      if (!isSameDay(apt.date, date)) return false;

      // Una cita se muestra en este slot si EMPIEZA en esta hora exacta
      // (no importa cuánto dure, solo donde empieza)
      const aptStartMinutes = timeToMinutes(apt.time);
      return aptStartMinutes === slotStartMinutes;
    });

    return slotAppointments
      .sort((a, b) => {
        const minA = parseInt(a.time.split(':')[1] || '0');
        const minB = parseInt(b.time.split(':')[1] || '0');
        return minA - minB;
      })
      .slice(0, 4);
  };

  // Calcular altura del evento basado en duración real
  // Cada slot de 30 min = 72px → cada minuto = 2.4px
  const getEventHeight = (duration: string): number => {
    const minutes = parseInt(duration);
    return Math.max((minutes / 30) * 72 - 2, 18);
  };

  // Calcular posición de la línea de tiempo actual
  const getCurrentTimePosition = (): number => {
    // Usar la hora ACTUAL en tiempo real, no el estado
    const now = new Date();
    const hours = now.getHours();
    const minutes = now.getMinutes();

    // Calcular minutos desde las 7 AM (inicio del calendario)
    const minutesSince7AM = (hours - 7) * 60 + minutes;

    // Cada 30 minutos = 72px
    return (minutesSince7AM / 30) * 72;
  };

  // Scroll automático a la hora actual al cargar
  useEffect(() => {
    if (!hasScrolledToCurrentTime.current && scrollContainerRef.current) {
      const currentPosition = getCurrentTimePosition();

      // Scroll para centrar la hora actual en la vista
      scrollContainerRef.current.scrollTop = Math.max(0, currentPosition - 200);
      hasScrolledToCurrentTime.current = true;
    }
  }, []);

  return (
    <div className="h-full flex flex-col bg-background">
      {/* ══════════ HEADER / TOOLBAR ══════════ */}
      <div className="flex-shrink-0 border-b bg-card px-4 py-3 lg:px-6">
        <div className="flex items-center justify-between gap-4">
          <div className="flex items-center gap-2">
            <Button variant="outline" size="sm" onClick={goToToday} className="font-medium">
              Hoy
            </Button>
            <div className="flex items-center">
              <Button variant="ghost" size="icon" className="h-8 w-8" onClick={goToPreviousWeek}>
                <ChevronLeft className="h-4 w-4" />
              </Button>
              <Button variant="ghost" size="icon" className="h-8 w-8" onClick={goToNextWeek}>
                <ChevronRight className="h-4 w-4" />
              </Button>
            </div>
            <h2 className="text-lg font-semibold capitalize text-foreground ml-2">
              {getDateRange()}
            </h2>
          </div>

          <div className="flex items-center gap-2">
            <Button onClick={onNewAppointment} size="sm" className="gap-2">
              <Plus className="h-4 w-4" />
              <span className="hidden sm:inline">Nueva Cita</span>
            </Button>
          </div>
        </div>
      </div>

      {/* ══════════ CALENDAR GRID ══════════ */}
      <div ref={scrollContainerRef} className="flex-1 min-h-0 overflow-auto">
        <div className="min-w-[800px] relative">
          {/* Encabezado de días */}
          <div className="grid grid-cols-[80px_repeat(7,1fr)] border-b bg-card sticky top-0 z-[50]">
            <div className="p-3 border-r" />
            {weekDays.map((day, index) => {
              const dayName = format(day, "EEE", { locale: es }).toUpperCase();
              const dayNumber = format(day, "d");
              const todayClass = isToday(day) ? "text-primary" : "text-foreground";

              return (
                <div key={index} className="p-4 text-center border-r last:border-r-0">
                  <div className="text-xs font-medium text-muted-foreground mb-1">
                    {dayName}
                  </div>
                  <div className={`text-2xl font-normal ${todayClass}`}>
                    {isToday(day) ? (
                      <span className="inline-flex items-center justify-center w-10 h-10 rounded-full bg-primary text-primary-foreground">
                        {dayNumber}
                      </span>
                    ) : (
                      dayNumber
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          {/* ══════════ FILAS DE HORAS ══════════ */}
          <div className="relative">
            {hours.map((hour, hourIndex) => (
              <div
                key={hourIndex}
                className="grid grid-cols-[80px_repeat(7,1fr)] border-b border-border/50"
                style={{ height: '72px' }}
              >
                {/* Label de hora */}
                <div className="text-right pr-4 pt-1 text-xs text-muted-foreground border-r">
                  {hour.label}
                </div>

                {/* Celdas de cada día */}
                {weekDays.map((day, dayIndex) => {
                  const slotAppointments = getAppointmentsForSlot(day, hour.time);

                  // Obtener todas las citas del día para calcular columnas
                  const dayAppointments = visibleAppointments.filter(apt => isSameDay(apt.date, day));
                  const columnAssignments = assignColumns(dayAppointments);

                  return (
                    <div
                      key={dayIndex}
                      className="border-r last:border-r-0 relative hover:bg-accent/30 cursor-pointer transition-colors"
                      onClick={() => onSlotClick(day, hour.time)}
                    >
                      {/* ══════════ 4 COLUMNAS INVISIBLES ══════════ */}
                      <div className="absolute inset-0 flex">
                        {[0, 1, 2, 3].map((colIndex) => {
                          // Encontrar la cita asignada a esta columna
                          const apt = slotAppointments.find(a => columnAssignments.get(a.id) === colIndex) || null;
                          const isHovered = apt !== null && hoveredAppointmentId === apt.id;
                          const aptColor = apt ? getStatusColor(apt.status) : DEFAULT_COLOR;

                          return (
                            <div
                              key={colIndex}
                              className="relative"
                              style={{ width: '25%' }}
                            >
                              {apt && (
                                <div
                                  ref={(el) => {
                                    if (el && isHovered) {
                                      // Calcular posición en viewport cuando hay hover
                                      const rect = el.getBoundingClientRect();
                                      const viewportHeight = window.innerHeight;
                                      const spaceAbove = rect.top;
                                      const spaceBelow = viewportHeight - rect.bottom;

                                      // Guardar en el elemento para acceder después
                                      (el as any)._tooltipPosition = spaceBelow > spaceAbove ? 'below' : 'above';
                                    }
                                  }}
                                  onMouseEnter={() => setHoveredAppointmentId(apt.id)}
                                  onMouseLeave={() => setHoveredAppointmentId(null)}
                                  className="absolute left-[2px] right-[2px]"
                                  style={{
                                    top: '2px',
                                  }}
                                >
                                  {/* ══════ BLOQUE DE CITA — color según estado ══════ */}
                                  <div
                                    data-apt-id={apt.id}
                                    className="rounded-md cursor-pointer transition-all duration-200 overflow-hidden"
                                    style={{
                                      height: `${getEventHeight(apt.duration)}px`,
                                      backgroundColor: aptColor,
                                      opacity: isHovered ? 1 : 0.8,
                                      boxShadow: isHovered
                                        ? `0 6px 20px -4px ${aptColor}80`
                                        : `0 1px 3px ${aptColor}25`,
                                      transform: isHovered ? 'scaleX(1.08)' : 'scaleX(1)',
                                      zIndex: isHovered ? 40 : 1,
                                      position: 'relative',
                                    }}
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      onAppointmentClick(apt);
                                    }}
                                  >
                                    {NORMALIZE_STATUS[apt.status?.toLowerCase() || ''] === 'atendiendo' && (
                                      <div className="shimmer-base shimmer-atendiendo" />
                                    )}
                                  </div>

                                  {/* ══════ TOOLTIP EN HOVER ══════ */}
                                  {isHovered && (() => {
                                    // Obtener la posición calculada del ref
                                    const tooltipPosition = (document.querySelector(`[data-apt-id="${apt.id}"]`)?.parentElement as any)?._tooltipPosition || 'below';
                                    const showBelow = tooltipPosition === 'below';
                                    const showAbove = tooltipPosition === 'above';

                                    return (
                                      <div
                                        className="absolute z-50 pointer-events-none"
                                        style={{
                                          ...(showAbove && { bottom: `${getEventHeight(apt.duration) + 8}px` }),
                                          ...(showBelow && { top: `${getEventHeight(apt.duration) + 8}px` }),
                                          left: '50%',
                                          transform: 'translateX(-50%)',
                                        }}
                                      >
                                        <div
                                          className="bg-popover text-popover-foreground border border-border rounded-lg shadow-xl p-3 relative"
                                          style={{ width: '230px' }}
                                        >
                                          {/* Flecha - apunta siempre hacia la cita */}
                                          {showAbove && (
                                            /* Tooltip arriba → flecha abajo (apunta a la cita) */
                                            <div className="absolute -bottom-[5px] left-1/2 -translate-x-1/2 w-2.5 h-2.5 rotate-45 bg-popover border-r border-b border-border" />
                                          )}
                                          {showBelow && (
                                            /* Tooltip abajo → flecha arriba (apunta a la cita) */
                                            <div className="absolute -top-[5px] left-1/2 -translate-x-1/2 w-2.5 h-2.5 rotate-45 bg-popover border-l border-t border-border" />
                                          )}

                                          {/* Nombre del paciente */}
                                          <div className="flex items-center gap-2 mb-2.5 pb-2 border-b border-border/60">
                                            <div
                                              className="w-6 h-6 rounded-md flex items-center justify-center flex-shrink-0"
                                              style={{ backgroundColor: `${aptColor}1A` }}
                                            >
                                              <User className="h-3.5 w-3.5" style={{ color: aptColor }} />
                                            </div>
                                            <p className="font-semibold text-sm text-foreground truncate leading-tight">
                                              {apt.patient}
                                            </p>
                                          </div>

                                          {/* Consulta / Tratamiento */}
                                          <div className="flex items-start gap-2 mb-2">
                                            <Stethoscope
                                              className="h-3.5 w-3.5 mt-0.5 flex-shrink-0"
                                              style={{ color: aptColor }}
                                            />
                                            <div className="min-w-0">
                                              <p className="text-[10px] uppercase tracking-wider text-muted-foreground font-semibold leading-tight">
                                                {apt.isTreatment ? 'Tratamiento' : 'Consulta'}
                                              </p>
                                              <p className="text-xs font-medium text-foreground truncate mt-0.5">
                                                {apt.isTreatment ? apt.treatmentName : apt.consultationType}
                                              </p>
                                            </div>
                                          </div>

                                          {/* Estado + Hora */}
                                          <div className="flex items-center justify-between pt-2 border-t border-border/50">
                                            <div className="flex items-center gap-1.5">
                                              <div
                                                className="w-2 h-2 rounded-full"
                                                style={{ backgroundColor: aptColor }}
                                              />
                                              <span className="text-[11px] font-semibold" style={{ color: aptColor }}>
                                                {STATUS_LABELS[apt.status] || apt.status}
                                              </span>
                                            </div>
                                            <span className="text-[11px] text-muted-foreground font-medium">
                                              {apt.time} · {apt.duration}
                                            </span>
                                          </div>
                                        </div>
                                      </div>
                                    );
                                  })()}
                                </div>
                              )}
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>
            ))}
          </div>

          {/* ══════════ LÍNEA DE TIEMPO ACTUAL ══════════ */}
          {(() => {
            const now = new Date();
            const currentHour = now.getHours();
            return currentHour >= 7 && currentHour <= 23;
          })() && (
              <div
                className="absolute pointer-events-none z-30"
                style={{
                  top: `${getCurrentTimePosition()}px`,
                  left: '80px', // Empieza después de la columna de hora
                  right: 0,
                }}
              >
                {/* Línea horizontal */}
                <div className="relative">
                  {/* La línea - solo los 7 días */}
                  <div className="grid grid-cols-7">
                    {weekDays.map((day, index) => {
                      const isCurrentDay = isSameDay(day, currentTime);
                      return (
                        <div
                          key={index}
                          className="relative"
                        >
                          {isCurrentDay && (
                            <>
                              {/* Círculo al inicio */}
                              <div className="absolute -left-[6px] -top-[6px] w-3 h-3 bg-red-500 rounded-full shadow-lg z-10" />
                              {/* Línea gruesa en el día actual - centrada verticalmente */}
                              <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 h-[3px] bg-red-500 shadow-md" />
                            </>
                          )}
                          {!isCurrentDay && (
                            /* Línea delgada en otros días - centrada verticalmente */
                            <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 h-[1px] bg-red-400/40" />
                          )}
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
            )}

          {/* ══════════ LEYENDA DE ESTADOS (Flotante en esquina inferior derecha) ══════════ */}
          <div className="fixed bottom-6 right-6 bg-card/95 backdrop-blur-sm border border-border rounded-lg shadow-lg p-3 z-40">
            <div className="flex flex-col gap-2">
              {[
                { label: "Pendiente", color: "#F59E0B" },
                { label: "Confirmada", color: "#10B981" },
                { label: "Atendida", color: "#6B7280" },
                { label: "Reprogramada", color: "#F97316" },
              ].map((item) => (
                <div key={item.label} className="flex items-center gap-2">
                  <div
                    className="w-3 h-3 rounded-sm flex-shrink-0"
                    style={{ backgroundColor: item.color }}
                  />
                  <span className="text-xs text-muted-foreground font-medium whitespace-nowrap">
                    {item.label}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// src/components/PctBadge.tsx
import { ArrowUpRight, ArrowDownRight } from "lucide-react";

export function calcPct(current: number, prev: number): number {
  if (prev === 0) return current > 0 ? 100 : 0;
  return ((current - prev) / prev) * 100;
}

interface PctBadgeProps {
  pct: number;
  /** "inline" — plain colored text (default, used in Dashboard stat cards)
   *  "pill"   — rounded badge with background (used in Pagos stat cards)  */
  variant?: "inline" | "pill";
}

export function PctBadge({ pct, variant = "inline" }: PctBadgeProps) {
  const up = pct >= 0;

  if (variant === "pill") {
    return (
      <span
        className={`inline-flex items-center gap-0.5 text-[11px] font-bold px-2 py-0.5 rounded-full ${
          up
            ? "text-emerald-700 bg-emerald-50 ring-1 ring-emerald-200"
            : "text-red-600 bg-red-50 ring-1 ring-red-200"
        }`}
      >
        {up ? <ArrowUpRight className="h-3 w-3" /> : <ArrowDownRight className="h-3 w-3" />}
        {Math.abs(pct).toFixed(0)}%
      </span>
    );
  }

  return (
    <span
      className={`flex items-center gap-0.5 text-sm font-medium ${
        up ? "text-emerald-500" : "text-red-500"
      }`}
    >
      {up ? <ArrowUpRight className="h-3.5 w-3.5" /> : <ArrowDownRight className="h-3.5 w-3.5" />}
      {Math.abs(pct).toFixed(0)}%
    </span>
  );
}

// src/components/MovimientosRecientes.tsx
import { useMemo } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  Calendar,
  Clock,
  DollarSign,
  XCircle,
  RefreshCw,
  CheckCircle,
  AlertCircle,
  Activity,
  Loader2,
  Stethoscope,
  ChevronRight,
} from "lucide-react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";

// ══════════ INTERFACES ══════════
interface EstadoHistorial {
  estado: string;
  fecha: any;
  realizado_por: string;
  tipo: "creacion" | "cambio_estado";
}

interface Appointment {
  id: string;
  tipo_consulta: string;
  fecha: Date;
  hora: string;
  duracion?: string;
  estado: string;
  costo?: number;
  pagado?: boolean;
  notas_observaciones?: string;
  paciente_nombre?: string;
  historial_estados?: EstadoHistorial[];
  es_tratamiento?: boolean;
  tratamiento_nombre?: string;
}

interface Pago {
  id: string;
  monto: number;
  metodo_pago: string;
  fecha: any;
  concepto: string;
  tipo: "consulta" | "tratamiento";
  referencia_id: string;
  referencia_nombre: string;
  paciente_id: string;
  creado_por: string;
  notas?: string;
}

interface MovimientosRecientesProps {
  appointments: Appointment[];
  pagos: Pago[];
  loadingAppointments: boolean;
  loadingPagos: boolean;
}

// ══════════ CONFIGURACIÓN DE ESTADOS ══════════
const ESTADO_CONFIG: Record<string, {
  label: string;
  color: string;
  bgColor: string;
  textColor: string;
  icon: typeof Calendar;
}> = {
  pendiente: {
    label: "Pendiente",
    color: "rgb(245, 158, 11)",
    bgColor: "bg-amber-50 dark:bg-amber-900/20",
    textColor: "text-amber-700 dark:text-amber-400",
    icon: Clock,
  },
  confirmada: {
    label: "Confirmada",
    color: "#10B981",
    bgColor: "bg-emerald-50 dark:bg-emerald-900/20",
    textColor: "text-emerald-700 dark:text-emerald-400",
    icon: CheckCircle,
  },
  completada: {
    label: "Completada",
    color: "#6B7280",
    bgColor: "bg-gray-100 dark:bg-gray-800/40",
    textColor: "text-gray-700 dark:text-gray-400",
    icon: CheckCircle,
  },
  cancelada: {
    label: "Cancelada",
    color: "#EF4444",
    bgColor: "bg-red-50 dark:bg-red-900/20",
    textColor: "text-red-700 dark:text-red-400",
    icon: XCircle,
  },
  atendiendo: {
    label: "Atendiendo",
    color: "#6B7280",
    bgColor: "bg-slate-50 dark:bg-slate-900/20",
    textColor: "text-slate-700 dark:text-slate-400",
    icon: Activity,
  },
  atendida: {
    label: "Atendida",
    color: "#6B7280",
    bgColor: "bg-slate-50 dark:bg-slate-900/20",
    textColor: "text-slate-700 dark:text-slate-400",
    icon: CheckCircle,
  },
  pausada: {
    label: "Pausado",
    color: "#94a3b8",
    bgColor: "bg-slate-50 dark:bg-slate-900/20",
    textColor: "text-slate-600 dark:text-slate-400",
    icon: Clock,
  },
  reprogramada: {
    label: "Reprogramada",
    color: "#F97316",
    bgColor: "bg-orange-50 dark:bg-orange-900/20",
    textColor: "text-orange-700 dark:text-orange-400",
    icon: RefreshCw,
  },
};

const getEstadoConfig = (estado: string) => {
  return ESTADO_CONFIG[estado?.toLowerCase() || ''] || ESTADO_CONFIG.pendiente;
};

const formatCurrency = (amount: number) => {
  return new Intl.NumberFormat("es-PE", {
    style: "currency",
    currency: "PEN",
  }).format(amount);
};

// ══════════ COMPONENTE PRINCIPAL ══════════
export default function MovimientosRecientes({
  appointments,
  pagos,
  loadingAppointments,
  loadingPagos,
}: MovimientosRecientesProps) {
  // Combinar citas y pagos en un solo timeline ordenado por fecha (más reciente primero)
  const movimientos = useMemo(() => {
    const items: Array<{
      id: string;
      type: "cita" | "pago";
      fecha: Date;
      data: any;
    }> = [];

    // Agregar TODAS las citas (incluyendo canceladas y reprogramadas)
    appointments.forEach((apt) => {
      const fecha = apt.fecha instanceof Date ? apt.fecha : new Date(apt.fecha);
      items.push({
        id: `cita-${apt.id}`,
        type: "cita",
        fecha,
        data: apt,
      });
    });

    // Agregar todos los pagos
    pagos.forEach((pago) => {
      const fecha = pago.fecha instanceof Date
        ? pago.fecha
        : pago.fecha?.toDate
          ? pago.fecha.toDate()
          : new Date(pago.fecha);
      items.push({
        id: `pago-${pago.id}`,
        type: "pago",
        fecha,
        data: pago,
      });
    });

    // Ordenar por fecha descendente (más reciente primero)
    return items.sort((a, b) => b.fecha.getTime() - a.fecha.getTime());
  }, [appointments, pagos]);

  const isLoading = loadingAppointments || loadingPagos;

  if (isLoading) {
    return (
      <Card>
        <CardContent className="p-12">
          <div className="flex flex-col items-center justify-center gap-4">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
            <p className="text-sm text-muted-foreground">Cargando movimientos...</p>
          </div>
        </CardContent>
      </Card>
    );
  }

  if (movimientos.length === 0) {
    return (
      <Card>
        <CardContent className="p-12">
          <div className="flex flex-col items-center justify-center gap-4 text-center">
            <Activity className="h-12 w-12 text-muted-foreground" />
            <div>
              <p className="font-semibold text-foreground">No hay movimientos registrados</p>
              <p className="text-sm text-muted-foreground mt-1">
                Las citas, cancelaciones, reprogramaciones y pagos aparecerán aquí
              </p>
            </div>
          </div>
        </CardContent>
      </Card>
    );
  }

  // Agrupar movimientos por mes/año
  const groupedByMonth: Record<string, typeof movimientos> = {};
  movimientos.forEach((mov) => {
    const key = `${mov.fecha.getFullYear()}-${String(mov.fecha.getMonth() + 1).padStart(2, "0")}`;
    if (!groupedByMonth[key]) groupedByMonth[key] = [];
    groupedByMonth[key].push(mov);
  });

  const monthKeys = Object.keys(groupedByMonth).sort((a, b) => b.localeCompare(a));

  return (
    <div className="rounded-3xl border border-slate-100 bg-slate-50/30 overflow-hidden shadow-inner flex flex-col">
      <div className="p-4 bg-white/40 border-b border-slate-100/50 flex justify-start items-center gap-2">
        <Activity className="h-4 w-4 text-[#00665a]" />
        <span className="text-sm font-bold text-slate-700">Cronograma de Movimientos</span>
      </div>
      <ScrollArea className="h-[65vh] px-5 py-6">
        <div className="space-y-8">
          {/* Timeline agrupado por mes */}
          {monthKeys.map((monthKey) => {
            const [year, month] = monthKey.split("-");
            const monthDate = new Date(parseInt(year), parseInt(month) - 1);
            const monthLabel = monthDate.toLocaleDateString("es-PE", {
              month: "long",
              year: "numeric",
            });

            return (
              <div key={monthKey}>
                <h3 className="text-[11px] font-bold text-slate-400 uppercase tracking-[0.1em] mb-4 pl-1">
                  {monthLabel}
                </h3>
                <div className="space-y-4">
                  {groupedByMonth[monthKey].map((mov) => (
                    <Card key={mov.id} className="hover:shadow-md transition-all duration-200 border-slate-100">
                      <CardContent className="p-4">
                        {mov.type === "cita" ? (
                          <CitaMovimiento cita={mov.data} fecha={mov.fecha} />
                        ) : (
                          <PagoMovimiento pago={mov.data} fecha={mov.fecha} />
                        )}
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </ScrollArea>
    </div>
  );
}

// ══════════ HELPER: FORMATEAR FECHA DEL HISTORIAL ══════════
function formatHistorialFecha(fecha: any): string {
  try {
    const date = typeof fecha?.toDate === "function" ? fecha.toDate() : new Date(fecha);
    const dia = date.toLocaleDateString("es-PE", { day: "2-digit", month: "short" });
    const hora = date.toLocaleTimeString("es-PE", { hour: "2-digit", minute: "2-digit", hour12: false });
    return `${dia} ${hora}`;
  } catch {
    return "";
  }
}

// ══════════ HELPER: TRUNCAR NOMBRE A DOS PALABRAS ══════════
function shortName(name: string): string {
  if (!name) return "";
  const parts = name.trim().split(/\s+/);
  return parts.slice(0, 2).join(" ");
}

// ══════════ COMPONENTE: TIMELINE DE ESTADOS ══════════
function EstadoTimeline({ historial }: { historial: EstadoHistorial[] }) {
  if (!historial || historial.length === 0) return null;

  return (
    <div className="flex items-center gap-3 flex-shrink-0 pl-4 border-l border-border/50">
      {historial.map((entry, i) => {
        const cfg = ESTADO_CONFIG[entry.estado?.toLowerCase() || ''] || ESTADO_CONFIG.pendiente;
        const label = entry.tipo === "creacion" ? "Creación" : cfg.label;
        return (
          <div key={i} className="flex items-center gap-2">
            {i > 0 && <ChevronRight className="h-4 w-4 text-muted-foreground flex-shrink-0" />}
            <div className="flex flex-col items-center min-w-0">
              <span
                className={`text-[11px] font-medium px-1.5 py-0.5 rounded whitespace-nowrap ${cfg.bgColor} ${cfg.textColor}`}
              >
                {label}
              </span>
              <span className="text-[12px] font-medium text-muted-foreground mt-1 whitespace-nowrap">
                {formatHistorialFecha(entry.fecha)}
              </span>
              <span className="text-[11px] text-muted-foreground/80 whitespace-nowrap italic">
                {shortName(entry.realizado_por)}
              </span>
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ══════════ COMPONENTE: CITA ══════════
function CitaMovimiento({ cita, fecha }: { cita: Appointment; fecha: Date }) {
  const config = getEstadoConfig(cita.estado);
  const StatusIcon = config.icon;

  return (
    <div className="flex items-start gap-3">
      {/* Indicador lateral con color del estado */}
      <div
        className="w-1 self-stretch rounded-full flex-shrink-0"
        style={{ backgroundColor: config.color }}
      />

      {/* Icono */}
      <div
        className="w-9 h-9 rounded-lg flex items-center justify-center flex-shrink-0 mt-0.5"
        style={{ backgroundColor: `${config.color}15` }}
      >
        <Stethoscope className="h-4 w-4" style={{ color: config.color }} />
      </div>

      {/* Tres contenedores: info | timeline | badge */}
      <div className="flex-1 min-w-0 flex items-center gap-4">

        {/* Contenedor 1: Info principal (1/3 del ancho, alineado start) */}
        <div className="w-1/3 flex justify-start">
          <div>
            <p className="font-semibold text-sm text-foreground">
              {cita.es_tratamiento
                ? `Cita de tratamiento: ${cita.tratamiento_nombre || "Sin nombre"}`
                : cita.tipo_consulta}
            </p>
            <p className="text-xs text-muted-foreground mt-0.5">
              {fecha.toLocaleDateString("es-PE", {
                weekday: "short",
                day: "2-digit",
                month: "short",
                year: "numeric",
              })}{" "}
              • {cita.hora}
              {cita.duracion && ` • ${cita.duracion} min`}
            </p>

            {/* Info extra para canceladas y reprogramadas */}
            {(cita.estado?.toLowerCase() === "cancelada" ||
              cita.estado?.toLowerCase() === "reprogramada") &&
              cita.notas_observaciones && (
                <div className="mt-2 p-2 rounded-md bg-muted/50 border border-border/50">
                  <p className="text-xs text-muted-foreground">
                    <span className="font-medium">Nota:</span> {cita.notas_observaciones}
                  </p>
                </div>
              )}

            {/* Costo si aplica (solo para consultas, no tratamientos) */}
            {!cita.es_tratamiento && cita.costo && cita.costo > 0 && (
              <div className="flex items-center gap-1.5 mt-1.5">
                <DollarSign className="h-3 w-3 text-muted-foreground" />
                <span className="text-xs text-muted-foreground">
                  {formatCurrency(cita.costo)}
                  {cita.pagado ? (
                    <span className="text-emerald-600 font-medium ml-1">· Pagado</span>
                  ) : ["confirmada", "completada"].includes(cita.estado?.toLowerCase() || '') ? (
                    <span className="font-medium ml-1" style={{ color: "rgb(245, 158, 11)" }}>
                      · Pendiente de pago
                    </span>
                  ) : null}
                </span>
              </div>
            )}
          </div>
        </div>

        {/* Contenedor 2: Timeline (se expande, alineado start) */}
        <div className="flex-1 flex justify-start">
          {cita.historial_estados && cita.historial_estados.length > 0 && (
            <EstadoTimeline historial={cita.historial_estados} />
          )}
        </div>

        {/* Contenedor 3: Badge (tamaño automático, alineado end) */}
        <div className="flex-shrink-0 flex justify-end">
          <Badge
            variant="secondary"
            className={`${config.bgColor} ${config.textColor} border-0 gap-1`}
          >
            <StatusIcon className="h-3 w-3" />
            {config.label}
          </Badge>
        </div>
      </div>
    </div>
  );
}

// ══════════ COMPONENTE: PAGO ══════════
function PagoMovimiento({ pago, fecha }: { pago: Pago; fecha: Date }) {
  return (
    <div className="flex items-start gap-3">
      {/* Indicador lateral verde */}
      <div className="w-1 self-stretch rounded-full flex-shrink-0 bg-blue-500" />

      {/* Icono */}
      <div className="w-9 h-9 rounded-lg flex items-center justify-center flex-shrink-0 mt-0.5 bg-blue-50 dark:bg-blue-900/20">
        <DollarSign className="h-4 w-4 text-blue-600" />
      </div>

      {/* Contenido */}
      <div className="flex-1 min-w-0">
        <div className="flex items-start justify-between gap-2">
          <div className="min-w-0">
            <p className="font-semibold text-sm text-foreground">
              {pago.concepto || pago.referencia_nombre}
            </p>
            <p className="text-xs text-muted-foreground mt-0.5">
              {(() => {
                const wd = fecha.toLocaleDateString("es-PE", { weekday: "short" });
                const mo = fecha.toLocaleDateString("es-PE", { month: "short" });
                const time = fecha.toLocaleTimeString("es-PE", { hour: "2-digit", minute: "2-digit", hour12: false });
                return `${wd}, ${fecha.getDate()} ${mo} de ${fecha.getFullYear()} - ${time}`;
              })()} • {pago.metodo_pago}
            </p>
          </div>

          <span className="font-bold text-sm text-foreground flex-shrink-0">
            {formatCurrency(pago.monto)}
          </span>
        </div>

        <div className="flex items-center gap-2 mt-1.5">
          <Badge
            variant="secondary"
            className="bg-blue-50 text-blue-700 dark:bg-blue-900/20 dark:text-blue-400 border-0"
          >
            <CheckCircle className="h-3 w-3 mr-1" />
            Pago completado
          </Badge>
          <span className="text-[10px] text-muted-foreground capitalize">
            {pago.tipo === "consulta" ? "Consulta" : "Tratamiento"}
          </span>
        </div>

        {pago.notas && (
          <p className="text-xs text-muted-foreground mt-1.5">
            <span className="font-medium">Nota:</span> {pago.notas}
          </p>
        )}
      </div>
    </div>
  );
}

