                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>
            </form>
          </Form>
        </div>

        <div className="px-6 py-5 border-t border-slate-100 flex justify-end gap-3 bg-white flex-none">
          <Button
            type="button"
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={isSubmitting}
            className="rounded-xl h-11 px-6 border-slate-200 text-slate-600 hover:bg-slate-50 transition-all font-medium"
          >
            Cancelar
          </Button>
          <Button
            type="submit"
            form="employee-edit-form"
            disabled={isSubmitting}
            className="bg-primary hover:bg-primary/90 text-white rounded-xl h-11 px-8 font-bold shadow-lg shadow-primary/20 transition-all disabled:opacity-50 disabled:shadow-none"
          >
            {isSubmitting ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Guardando...
              </>
            ) : (
              "Actualizar Empleado"
            )}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

// src/components/employees/HorarioSemanal.tsx
import { Sun, Sunset, Moon, Check } from "lucide-react";
import { cn } from "@/lib/utils";
import type { HorarioValue } from "@/types/employee";

type Dia = "lunes" | "martes" | "miercoles" | "jueves" | "viernes" | "sabado" | "domingo";

interface HorarioSemanalProps {
  value: HorarioValue;
  onChange: (value: HorarioValue) => void;
  disabled?: boolean;
}

// ── Config ───────────────────────────────────────────────────────────────────

const DIAS: { key: Dia; label: string; abrev: string }[] = [
  { key: "lunes",     label: "Lunes",     abrev: "Lun" },
  { key: "martes",    label: "Martes",    abrev: "Mar" },
  { key: "miercoles", label: "Miércoles", abrev: "Mié" },
  { key: "jueves",    label: "Jueves",    abrev: "Jue" },
  { key: "viernes",   label: "Viernes",   abrev: "Vie" },
  { key: "sabado",    label: "Sábado",    abrev: "Sáb" },
  { key: "domingo",   label: "Domingo",   abrev: "Dom" },
];

export const HORARIO_VACIO: HorarioValue = {
  lunes:     { mañana: false, tarde: false },
  martes:    { mañana: false, tarde: false },
  miercoles: { mañana: false, tarde: false },
  jueves:    { mañana: false, tarde: false },
  viernes:   { mañana: false, tarde: false },
  sabado:    { mañana: false, tarde: false },
  domingo:   { mañana: false, tarde: false },
};

// ── Component ─────────────────────────────────────────────────────────────────

export default function HorarioSemanal({
  value,
  onChange,
  disabled = false,
}: HorarioSemanalProps) {
  const toggle = (dia: Dia, turno: "mañana" | "tarde") => {
    if (disabled || dia === "domingo") return;
    onChange({
      ...value,
      [dia]: { ...value[dia], [turno]: !value[dia][turno] },
    });
  };

  return (
    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-7 gap-2">
      {DIAS.map(({ key, label, abrev }) => {
        const esDomingo = key === "domingo";
        const turno = value[key];
        const activosCount = esDomingo
          ? 0
          : (turno.mañana ? 1 : 0) + (turno.tarde ? 1 : 0);

        return (
          <div
            key={key}
            className={cn(
              "flex flex-col rounded-xl border overflow-hidden transition-all",
              esDomingo
                ? "border-border/30 bg-muted/10"
                : activosCount > 0
                ? "border-primary/20 bg-primary/[0.03] shadow-sm"
                : "border-border/50 bg-card"
            )}
          >
            {/* Header del día */}
            <div
              className={cn(
                "flex items-center justify-between px-3 py-2 border-b",
                esDomingo
                  ? "border-border/20 bg-muted/10"
                  : activosCount > 0
                  ? "border-primary/10 bg-primary/5"
                  : "border-border/40 bg-muted/20"
              )}
            >
              <div className="flex flex-col">
                <span
                  className={cn(
                    "text-[11px] font-bold uppercase tracking-wider leading-none",
                    esDomingo ? "text-muted-foreground/40" : "text-foreground"
                  )}
                >
                  {abrev}
                </span>
                <span
                  className={cn(
                    "text-[9px] font-medium mt-0.5 hidden md:block",
                    esDomingo ? "text-muted-foreground/30" : "text-muted-foreground"
                  )}
                >
                  {label}
                </span>
              </div>

              {/* Badge contador */}
              {activosCount > 0 && (
                <span className="w-4 h-4 rounded-full bg-primary text-primary-foreground text-[9px] font-bold flex items-center justify-center leading-none flex-shrink-0">
                  {activosCount}
                </span>
              )}
            </div>

            {/* Cuerpo */}
            <div className="flex flex-col gap-1.5 p-2 flex-1">
              {esDomingo ? (
                /* Domingo — bloque de descanso */
                <div className="flex-1 flex flex-col items-center justify-center gap-1.5 py-3 rounded-lg bg-muted/20 min-h-[80px]">
                  <Moon className="h-4 w-4 text-muted-foreground/30" />
                  <span className="text-[10px] font-medium text-muted-foreground/40 text-center leading-tight">
                    Descanso
                  </span>
                </div>
              ) : (
                <>
                  {/* Turno Mañana */}
                  <TurnoButton
                    label="Mañana"
                    icon={<Sun className="h-3.5 w-3.5 flex-shrink-0" />}
                    active={turno.mañana}
                    disabled={disabled}
                    onClick={() => toggle(key, "mañana")}
                  />

                  {/* Turno Tarde */}
                  <TurnoButton
                    label="Tarde"
                    icon={<Sunset className="h-3.5 w-3.5 flex-shrink-0" />}
                    active={turno.tarde}
                    disabled={disabled}
                    onClick={() => toggle(key, "tarde")}
                  />
                </>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ── TurnoButton ───────────────────────────────────────────────────────────────

interface TurnoButtonProps {
  label: string;
  icon: React.ReactNode;
  active: boolean;
  disabled: boolean;
  onClick: () => void;
}

function TurnoButton({ label, icon, active, disabled, onClick }: TurnoButtonProps) {
  return (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      className={cn(
        "w-full flex items-center gap-1.5 px-2 py-2 rounded-lg text-[11px] font-medium transition-all duration-150 select-none",
        disabled && "cursor-not-allowed opacity-50",
        !disabled && active &&
          "bg-primary text-primary-foreground shadow-sm",
        !disabled && !active &&
          "bg-muted/40 text-muted-foreground hover:bg-muted hover:text-foreground"
      )}
    >
      {active && !disabled ? (
        <Check className="h-3 w-3 flex-shrink-0" />
      ) : (
        icon
      )}
      <span className="leading-none">{label}</span>
    </button>
  );
}

import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { Loader2, Calendar as CalendarIcon, Package, Sprout, X, Info, Tag, Settings, ClipboardList } from "lucide-react";
import { format } from "date-fns";
import { es } from "date-fns/locale";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Calendar } from "@/components/ui/calendar";
import { cn } from "@/lib/utils";
import { useActivityLog } from "@/hooks/useActivityLog";
import { diffObjects } from "@/utils/activityDiff";
import { toast } from "@/hooks/use-toast";
import {
    InventoryItemType,
    InventoryItemFormValues,
    inventoryItemSchema,
    INVENTORY_CATEGORIES,
} from "@/types/inventory";
import { createInventoryItem, updateInventoryItem } from "@/services/inventoryService";
import { capitalizeName, formatNotes, handleNotesKeyDown } from "@/utils/formatters";

interface InventoryDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    item?: InventoryItemType | null;
    onSuccess?: () => void;
}

export function InventoryDialog({ open, onOpenChange, item, onSuccess }: InventoryDialogProps) {
    const [loading, setLoading] = useState(false);
    const { log } = useActivityLog();

    const form = useForm<InventoryItemFormValues>({
        resolver: zodResolver(inventoryItemSchema),
        defaultValues: {
            nombre: "",
            descripcion: "",
            categoria: "Rotación",
            // Valores por defecto para que los campos no sean undefined
            marca: "",
            modelo: "",
            numero_serie: "",
            fecha_mantencion: "",
            stock_actual: 0,
            stock_minimo: 5,
            fecha_vencimiento: "",
            lote: "",
        } as any, // Hacemos cast a any temporalmente para proveer defaults a todos los campos
    });

    const categoriaSeleccionada = form.watch("categoria");

    useEffect(() => {
        if (item && open) {
            form.reset({
                nombre: item.nombre,
                descripcion: item.descripcion || "",
                categoria: item.categoria,
                ...(item.categoria === "Estático"
                    ? {
                        marca: item.marca,
                        modelo: item.modelo,
                        numero_serie: item.numero_serie,
                        fecha_mantencion: item.fecha_mantencion || "",
                    }
                    : {
                        stock_actual: item.stock_actual,
                        stock_minimo: item.stock_minimo,
                        fecha_vencimiento: item.fecha_vencimiento || "",
                        lote: item.lote || "",
                    }),
            } as InventoryItemFormValues);
        } else if (open && !item) {
            form.reset({
                nombre: "",
                descripcion: "",
                categoria: "Rotación",
                marca: "",
                modelo: "",
                numero_serie: "",
                fecha_mantencion: "",
                stock_actual: 0,
                stock_minimo: 5,
                fecha_vencimiento: "",
                lote: "",
            } as any);
        }
    }, [item, open, form]);

    const onSubmit = async (data: InventoryItemFormValues) => {
        try {
            setLoading(true);
            if (item?.id) {
                await updateInventoryItem(item.id, data);
                toast({
                    title: "Producto actualizado",
                    description: "El producto ha sido actualizado correctamente.",
                });
                const cambios = diffObjects(
                    { nombre: item.nombre, stock_actual: (item as any).stock_actual, stock_minimo: (item as any).stock_minimo, precio: (item as any).precio },
                    { nombre: data.nombre, stock_actual: (data as any).stock_actual, stock_minimo: (data as any).stock_minimo, precio: (data as any).precio },
                    { nombre: "Nombre", stock_actual: "Stock actual", stock_minimo: "Stock mínimo", precio: "Precio" }
                );
                log({ modulo: "Inventario", accion: "editó", entidad: "producto", entidad_id: item.id, entidad_nombre: data.nombre, cambios });
            } else {
                await createInventoryItem(data);
                toast({
                    title: "Producto registrado",
                    description: "El nuevo producto ha sido registrado correctamente.",
                });
                log({ modulo: "Inventario", accion: "creó", entidad: "producto", entidad_nombre: data.nombre });
            }
            onSuccess?.();
            onOpenChange(false);
        } catch (error) {
            console.error("Error saving inventory item:", error);
            toast({
                variant: "destructive",
                title: "Error",
                description: "Hubo un error al guardar el producto.",
            });
        } finally {
            setLoading(false);
        }
    };

    const currentYear = new Date().getFullYear();

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-3xl h-[90vh] flex flex-col p-0 border-none bg-white rounded-3xl overflow-hidden">
                <DialogHeader className="px-6 py-5 border-b border-slate-100 bg-white flex-none relative">
                    <DialogTitle className="text-2xl font-semibold text-slate-900">
                        {item ? "Editar Producto" : "Nuevo Producto"}
                    </DialogTitle>
                    <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        className="absolute right-4 top-4 rounded-full h-10 w-10 text-slate-400 hover:text-slate-900 hover:bg-slate-100 transition-all"
                        onClick={() => onOpenChange(false)}
                    >
                        <X className="h-5 w-5" />
                    </Button>
                </DialogHeader>

                <div className="flex-1 overflow-y-auto px-6 pt-1 pb-2">
                    <Form {...form}>
                        <form id="inventory-form" autoComplete="off" onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
                            {/* ℹ️ SECCIÓN 1: INFORMACIÓN GENERAL */}
                            <div className="space-y-4">
                                <div className="flex items-center gap-2 pb-2 border-b border-slate-100">
                                    <Info className="h-4 w-4 text-primary" />
                                    <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Información General</h3>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <FormField
                                        control={form.control}
                                        name="nombre"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Nombre del Producto *</FormLabel>
                                                <FormControl>
                                                    <Input
                                                        placeholder="Ej. Lámpara de Fotocurado"
                                                        {...field}
                                                        autoComplete="none"
                                                        onChange={(e) => field.onChange(capitalizeName(e.target.value))}
                                                        className="h-11 bg-slate-50 border-slate-200 rounded-xl focus-visible:ring-primary/20"
                                                    />
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />

                                    <FormField
                                        control={form.control}
                                        name="categoria"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Tipo de Producto *</FormLabel>
                                                <Select
                                                    onValueChange={(val) => {
                                                        field.onChange(val);
                                                        form.clearErrors();
                                                    }}
                                                    defaultValue={field.value}
                                                    value={field.value}
                                                >
                                                    <FormControl>
                                                        <SelectTrigger className="h-11 bg-slate-50 border-slate-200 rounded-xl">
                                                            <SelectValue placeholder="Seleccione el tipo" />
                                                        </SelectTrigger>
                                                    </FormControl>
                                                    <SelectContent>
                                                        {INVENTORY_CATEGORIES.map((cat) => (
                                                            <SelectItem key={cat.value} value={cat.value}>
                                                                <div className="flex items-center gap-2">
                                                                    {cat.value === "Estático" ? (
                                                                        <div className="w-2 h-2 rounded-full bg-blue-500" />
                                                                    ) : (
                                                                        <div className="w-2 h-2 rounded-full bg-orange-500" />
                                                                    )}
                                                                    {cat.label}
                                                                </div>
                                                            </SelectItem>
                                                        ))}
                                                    </SelectContent>
                                                </Select>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />
                                </div>

                                <FormField
                                    control={form.control}
                                    name="descripcion"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Descripción (Opcional)</FormLabel>
                                            <FormControl>
                                                <Textarea
                                                    placeholder="Detalles adicionales del producto o equipo..."
                                                    className="resize-none min-h-[100px] bg-slate-50 border-slate-200 rounded-2xl focus-visible:ring-primary/20"
                                                    {...field}
                                                    autoComplete="off"
                                                    onChange={(e) => {
                                                        const formattedValue = formatNotes(e.target.value);
                                                        field.onChange(formattedValue);
                                                    }}
                                                    onKeyDown={(e) => handleNotesKeyDown(e, field.value || "", field.onChange)}
                                                />
                                            </FormControl>
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />
                            </div>

                            <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100 space-y-6">
                                <div className="flex items-center gap-2 pb-2 border-b border-slate-200/60">
                                    <Settings className="h-4 w-4 text-primary" />
                                    <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider">
                                        {categoriaSeleccionada === "Estático"
                                            ? "Detalles Técnicos y Activo Fijo"
                                            : "Control de Inventario y Stock"}
                                    </h3>
                                </div>

                                {categoriaSeleccionada === "Estático" ? (
                                    /* ESTÁTICO FIELDS */
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <FormField
                                            control={form.control}
                                            name="marca"
                                            render={({ field }) => (
                                                <FormItem>
                                                    <FormLabel>Marca *</FormLabel>
                                                    <FormControl>
                                                        <Input
                                                            placeholder="Ej. 3M"
                                                            {...field}
                                                            value={field.value || ""}
                                                            autoComplete="none"
                                                            onChange={(e) => field.onChange(capitalizeName(e.target.value))}
                                                            className="h-11 bg-white border-slate-200 rounded-xl"
                                                        />
                                                    </FormControl>
                                                    <FormMessage />
                                                </FormItem>
                                            )}
                                        />
                                        <FormField
                                            control={form.control}
                                            name="modelo"
                                            render={({ field }) => (
                                                <FormItem>
                                                    <FormLabel>Modelo *</FormLabel>
                                                    <FormControl>
                                                        <Input
                                                            placeholder="Ej. Elipar DeepCure"
                                                            {...field}
                                                            value={field.value || ""}
                                                            autoComplete="none"
                                                            onChange={(e) => field.onChange(capitalizeName(e.target.value))}
                                                            className="h-11 bg-white border-slate-200 rounded-xl"
                                                        />
                                                    </FormControl>
                                                    <FormMessage />
                                                </FormItem>
                                            )}
                                        />
                                        <FormField
                                            control={form.control}
                                            name="numero_serie"
                                            render={({ field }) => (
                                                <FormItem>
                                                    <FormLabel>Número de Serie *</FormLabel>
                                                    <FormControl>
                                                        <Input placeholder="SN-XXXXX" {...field} value={field.value || ""} autoComplete="none" className="h-11 bg-white border-slate-200 rounded-xl" />
                                                    </FormControl>
                                                    <FormMessage />
                                                </FormItem>
                                            )}
                                        />
                                        <FormField
                                            control={form.control}
                                            name="fecha_mantencion"
                                            render={({ field }) => {
                                                const dateValue = field.value ? new Date(field.value + "T00:00:00") : undefined;
                                                // eslint-disable-next-line react-hooks/rules-of-hooks
                                                const [displayMonth, setDisplayMonth] = useState(dateValue || new Date());

                                                return (
                                                    <FormItem>
                                                        <FormLabel>Última Mantención</FormLabel>
                                                        <Popover>
                                                            <PopoverTrigger asChild>
                                                                <FormControl>
                                                                    <Button
                                                                        variant={"outline"}
                                                                        className={cn(
                                                                            "w-full pl-3 text-left font-normal h-11 bg-white border-slate-200 rounded-xl hover:bg-slate-50 transition-colors",
                                                                            !field.value && "text-slate-400"
                                                                        )}
                                                                    >
                                                                        {field.value ? (
                                                                            format(dateValue!, "PPP", { locale: es })
                                                                        ) : (
                                                                            <span>Selecciona una fecha</span>
                                                                        )}
                                                                        <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                                                                    </Button>
                                                                </FormControl>
                                                            </PopoverTrigger>
                                                            <PopoverContent className="w-auto p-3" align="start">
                                                                <div className="flex justify-between mb-2 gap-2">
                                                                    <select
                                                                        className="border rounded-md px-2 py-1 text-xs"
                                                                        value={displayMonth.getMonth()}
                                                                        onChange={(e) =>
                                                                            setDisplayMonth(new Date(displayMonth.getFullYear(), parseInt(e.target.value)))
                                                                        }
                                                                    >
                                                                        {Array.from({ length: 12 }, (_, i) => (
                                                                            <option key={i} value={i}>
                                                                                {format(new Date(0, i), "MMMM", { locale: es })}
                                                                            </option>
                                                                        ))}
                                                                    </select>
                                                                    <select
                                                                        className="border rounded-md px-2 py-1 text-xs"
                                                                        value={displayMonth.getFullYear()}
                                                                        onChange={(e) =>
                                                                            setDisplayMonth(new Date(parseInt(e.target.value), displayMonth.getMonth()))
                                                                        }
                                                                    >
                                                                        {Array.from({ length: 15 }, (_, i) => currentYear - 10 + i).map((y) => (
                                                                            <option key={y} value={y}>
                                                                                {y}
                                                                            </option>
                                                                        ))}
                                                                    </select>
                                                                </div>
                                                                <Calendar
                                                                    mode="single"
                                                                    selected={dateValue}
                                                                    onSelect={(date) => {
                                                                        if (date) {
                                                                            field.onChange(format(date, "yyyy-MM-dd"));
                                                                        } else {
                                                                            field.onChange("");
                                                                        }
                                                                    }}
                                                                    month={displayMonth}
                                                                    onMonthChange={setDisplayMonth}
                                                                    initialFocus
                                                                />
                                                            </PopoverContent>
                                                        </Popover>
                                                        <FormMessage />
                                                    </FormItem>
                                                );
                                            }}
                                        />
                                    </div>
                                ) : (
                                    /* ROTATION FIELDS */
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                        <FormField
                                            control={form.control}
                                            name="stock_actual"
                                            render={({ field }) => (
                                                <FormItem>
                                                    <FormLabel>Stock Actual *</FormLabel>
                                                    <FormControl>
                                                        <Input
                                                            type="number"
                                                            min="0"
                                                            {...field}
                                                            value={field.value ?? 0}
                                                            onChange={(e) => field.onChange(Number(e.target.value))}
                                                            className="h-11 bg-white border-slate-200 rounded-xl"
                                                        />
                                                    </FormControl>
                                                    <FormMessage />
                                                </FormItem>
                                            )}
                                        />
                                        <FormField
                                            control={form.control}
                                            name="stock_minimo"
                                            render={({ field }) => (
                                                <FormItem>
                                                    <FormLabel>Stock Mínimo (Alerta) *</FormLabel>
                                                    <FormControl>
                                                        <Input
                                                            type="number"
                                                            min="0"
                                                            {...field}
                                                            value={field.value ?? 0}
                                                            onChange={(e) => field.onChange(Number(e.target.value))}
                                                            className="h-11 bg-white border-slate-200 rounded-xl"
                                                        />
                                                    </FormControl>
                                                    <FormMessage />
                                                </FormItem>
                                            )}
                                        />
                                        <FormField
                                            control={form.control}
                                            name="lote"
                                            render={({ field }) => (
                                                <FormItem>
                                                    <FormLabel>Número de Lote (Opcional)</FormLabel>
                                                    <FormControl>
                                                        <Input placeholder="Ej. L-2026A" {...field} value={field.value || ""} autoComplete="none" className="h-11 bg-white border-slate-200 rounded-xl" />
                                                    </FormControl>
                                                    <FormMessage />
                                                </FormItem>
                                            )}
                                        />
                                        <FormField
                                            control={form.control}
                                            name="fecha_vencimiento"
                                            render={({ field }) => {
                                                const dateValue = field.value ? new Date(field.value + "T00:00:00") : undefined;
                                                // eslint-disable-next-line react-hooks/rules-of-hooks
                                                const [displayMonth, setDisplayMonth] = useState(dateValue || new Date());

                                                return (
                                                    <FormItem>
                                                        <FormLabel>Fecha de Vencimiento (Opcional)</FormLabel>
                                                        <Popover>
                                                            <PopoverTrigger asChild>
                                                                <FormControl>
                                                                    <Button
                                                                        variant={"outline"}
                                                                        className={cn(
                                                                            "w-full pl-3 text-left font-normal h-11 bg-white border-slate-200 rounded-xl hover:bg-slate-50 transition-colors",
                                                                            !field.value && "text-slate-400"
                                                                        )}
                                                                    >
                                                                        {field.value ? (
                                                                            format(dateValue!, "PPP", { locale: es })
                                                                        ) : (
                                                                            <span>Selecciona una fecha</span>
                                                                        )}
                                                                        <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                                                                    </Button>
                                                                </FormControl>
                                                            </PopoverTrigger>
                                                            <PopoverContent className="w-auto p-3" align="start">
                                                                <div className="flex justify-between mb-2 gap-2">
                                                                    <select
                                                                        className="border rounded-md px-2 py-1 text-xs"
                                                                        value={displayMonth.getMonth()}
                                                                        onChange={(e) =>
                                                                            setDisplayMonth(new Date(displayMonth.getFullYear(), parseInt(e.target.value)))
                                                                        }
                                                                    >
                                                                        {Array.from({ length: 12 }, (_, i) => (
                                                                            <option key={i} value={i}>
                                                                                {format(new Date(0, i), "MMMM", { locale: es })}
                                                                            </option>
                                                                        ))}
                                                                    </select>
                                                                    <select
                                                                        className="border rounded-md px-2 py-1 text-xs"
                                                                        value={displayMonth.getFullYear()}
                                                                        onChange={(e) =>
                                                                            setDisplayMonth(new Date(parseInt(e.target.value), displayMonth.getMonth()))
                                                                        }
                                                                    >
                                                                        {Array.from({ length: 10 }, (_, i) => currentYear + i).map((y) => (
                                                                            <option key={y} value={y}>
                                                                                {y}
                                                                            </option>
                                                                        ))}
                                                                    </select>
                                                                </div>
                                                                <Calendar
                                                                    mode="single"
                                                                    selected={dateValue}
                                                                    onSelect={(date) => {
                                                                        if (date) {
                                                                            field.onChange(format(date, "yyyy-MM-dd"));
                                                                        } else {
                                                                            field.onChange("");
                                                                        }
                                                                    }}
                                                                    month={displayMonth}
                                                                    onMonthChange={setDisplayMonth}
                                                                    initialFocus
                                                                />
                                                            </PopoverContent>
                                                        </Popover>
                                                        <FormMessage />
                                                    </FormItem>
                                                );
                                            }}
                                        />
                                    </div>
                                )}
                            </div>
                        </form>
                    </Form>
                </div>

                <div className="px-6 py-5 border-t border-slate-100 flex justify-end gap-3 bg-white flex-none">
                    <Button
                        type="button"
                        variant="outline"
                        onClick={() => onOpenChange(false)}
                        className="rounded-xl h-11 px-6 border-slate-200 text-slate-600 hover:bg-slate-50 transition-all font-medium"
                    >
                        Cancelar
                    </Button>
                    <Button
                        type="submit"
                        form="inventory-form"
                        disabled={loading}
                        className="bg-primary hover:bg-primary/90 text-white rounded-xl h-11 px-8 font-bold shadow-lg shadow-primary/20 transition-all disabled:opacity-50 disabled:shadow-none"
                    >
                        {loading ? (
                            <>
                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                Guardando...
                            </>
                        ) : (
                            item ? "Guardar Cambios" : "Registrar Producto"
                        )}
                    </Button>
                </div>
            </DialogContent>
        </Dialog>
    );
}

import { ReactNode } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import {
  LayoutDashboard,
  Users,
  UserCircle,
  Calendar,
  CreditCard,
  UserCheck,
  Menu,
  X,
  LogOut,
  Settings2,
  UserCog,
  Ellipsis,
  Package,
  History,
} from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Button } from "@/components/ui/button";
import { useState } from "react";
import { useAuthContext } from "@/context/AuthContext";
import type { User } from "firebase/auth";

interface LayoutProps {
  children: ReactNode;
}

const ALL_MENU_ITEMS = [
  { icon: LayoutDashboard, label: "Dashboard",     path: "/",             roles: ["admin"] },
  { icon: Calendar,        label: "Calendario",    path: "/calendario",   roles: ["admin", "recepcionista"] },
  { icon: UserCircle,      label: "Pacientes",     path: "/pacientes",    roles: ["admin", "recepcionista"] },
  { icon: CreditCard,      label: "Pagos",         path: "/pagos",        roles: ["admin", "recepcionista"] },
  { icon: Package,         label: "Inventario",    path: "/inventario",   roles: ["admin"] },
  { icon: Users,           label: "Empleados",     path: "/empleados",    roles: ["admin"] },
  { icon: UserCheck,       label: "Usuarios",      path: "/usuarios",     roles: ["admin"] },
  { icon: Settings2,       label: "Configuración", path: "/configuracion",roles: ["admin"] },
  { icon: History,         label: "Actividad",     path: "/actividad",    roles: ["admin"] },
] as const;

export function Layout({ children }: LayoutProps) {
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const { signOut, user, userProfile, rol } = useAuthContext();
  const menuItems = ALL_MENU_ITEMS.filter(item => rol ? item.roles.includes(rol) : false);

  return (
    <div className="min-h-screen bg-background">
      {/* Mobile Header */}
      <header className="lg:hidden fixed top-0 left-0 right-0 h-16 bg-sidebar border-b border-sidebar-border z-50 flex items-center px-4">
        <Button
          variant="ghost"
          size="icon"
          onClick={() => setSidebarOpen(!sidebarOpen)}
          className="text-sidebar-foreground hover:bg-sidebar-accent"
        >
          {sidebarOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
        </Button>
        <h1 className="ml-4 text-xl font-bold text-sidebar-foreground"></h1>
      </header>

      {/* Sidebar */}
      <aside
        className={`
          fixed top-0 left-0 h-full w-64 bg-sidebar border-r border-sidebar-border z-40
          transition-transform duration-300 ease-in-out
          ${sidebarOpen ? "translate-x-0" : "-translate-x-full"}
          lg:translate-x-0
        `}
      >
        <div className="px-4 py-2 flex justify-start">
          <img
            src="/logo-bamboo-verde.svg"
            alt="Logo Bamboo"
            className="w-full h-auto max-w-[180px] object-contain brightness-0 invert"
          />
        </div>

        <nav className="px-3 space-y-1 flex flex-col h-[calc(100vh-120px)]">
          <div className="flex-1">
            {menuItems.map((item) => {
              const Icon = item.icon;
              const isActive = location.pathname === item.path;
              return (
                <Link
                  key={item.path}
                  to={item.path}
                  onClick={() => setSidebarOpen(false)}
                  className={`
                    flex items-center gap-3 px-3 py-3 rounded-lg transition-all
                    ${isActive
                      ? "bg-sidebar-accent text-sidebar-accent-foreground font-medium"
                      : "text-sidebar-foreground/80 hover:bg-sidebar-accent/50 hover:text-sidebar-foreground"
                    }
                  `}
                >
                  <Icon className="h-5 w-5" />
                  <span>{item.label}</span>
                </Link>
              );
            })}
          </div>

          {/* User menu */}
          <div className="border-t border-sidebar-border pt-4 pb-4 px-3 flex flex-col gap-2">
            {user && (
              <UserMenu
                user={user}
                userProfile={userProfile}
                onSignOut={signOut}
              />
            )}
          </div>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="lg:ml-64 min-h-screen pt-16 lg:pt-0">
        <div className="p-6 lg:p-8">
          {children}
        </div>
      </main>

      {/* Overlay for mobile */}
      {sidebarOpen && (
        <div
          className="fixed inset-0 bg-black/50 z-30 lg:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}
    </div>
  );
}

/* ─────────────────────────────────────────
   UserMenu — componente de usuario
───────────────────────────────────────── */

function getInitials(user: User): string {
  if (user.displayName) {
    const parts = user.displayName.trim().split(/\s+/);
    if (parts.length >= 2) return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
    return parts[0][0].toUpperCase();
  }
  return (user.email?.[0] ?? "U").toUpperCase();
}

function UserAvatar({
  user,
  size = "sm",
  variant = "sidebar",
}: {
  user: User;
  size?: "sm" | "md";
  variant?: "sidebar" | "menu";
}) {
  const initials = getInitials(user);
  const dim = size === "md" ? "w-10 h-10 text-sm" : "w-9 h-9 text-xs";

  const ringClass =
    variant === "sidebar" ? "ring-2 ring-white/25" : "ring-1 ring-border";

  if (user.photoURL) {
    return (
      <img
        src={user.photoURL}
        alt="Avatar"
        referrerPolicy="no-referrer"
        className={`${dim} rounded-lg object-cover ${ringClass} flex-none`}
      />
    );
  }

  const bgClass =
    variant === "sidebar"
      ? "bg-white/15 text-white"
      : "bg-primary/10 text-primary";

  return (
    <div
      className={`${dim} rounded-lg ${bgClass} ${ringClass} flex items-center justify-center flex-none font-semibold`}
    >
      {initials}
    </div>
  );
}

function UserMenu({
  user,
  userProfile,
  onSignOut,
}: {
  user: User;
  userProfile?: any;
  onSignOut: () => void;
}) {
  const navigate = useNavigate();
  const rawName = userProfile?.nombre || user.displayName || user.email?.split("@")[0] || "Usuario";
  const role = userProfile?.rol || "Administrador";

  return (
    <div className="flex flex-col gap-2 w-full">
      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <button className="group flex items-center gap-3 p-2 rounded-xl transition-all duration-200 outline-none w-full hover:bg-white/5 active:bg-white/10">
            <UserAvatar user={user} size="sm" />

            <div className="flex-1 min-w-0 text-left">
              <p className="font-bold text-sidebar-foreground truncate leading-tight text-[13px]">
                {rawName}
              </p>
              <p className="text-[10px] text-sidebar-foreground/50 truncate font-medium uppercase tracking-wider mt-0.5">
                {role}
              </p>
            </div>
          </button>
        </DropdownMenuTrigger>

        <DropdownMenuContent
          side="top"
          align="start"
          sideOffset={12}
          className="w-64 p-0 overflow-hidden shadow-2xl border-white/10"
        >
          {/* Header con info del usuario */}
          <div className="flex items-center gap-3 px-4 py-4 bg-muted/40 border-b border-border/50">
            <UserAvatar user={user} size="md" variant="menu" />
            <div className="flex-1 min-w-0">
              <p className="text-sm font-bold text-foreground leading-tight truncate">
                {rawName}
              </p>
              <p className="text-[11px] text-muted-foreground truncate leading-tight mt-1 opacity-80">
                {user.email}
              </p>
            </div>
          </div>

          <div className="p-1.5">
            <DropdownMenuItem
              onClick={() => navigate("/perfil")}
              className="flex items-center gap-3 px-3 py-2.5 text-sm cursor-pointer rounded-lg hover:bg-primary/5 focus:bg-primary/5 transition-colors"
            >
              <div className="w-8 h-8 rounded-md bg-primary/10 flex items-center justify-center text-primary">
                <UserCircle className="h-4 w-4" />
              </div>
              <span className="font-medium">Gestión de perfil</span>
            </DropdownMenuItem>

            <DropdownMenuItem
              onClick={onSignOut}
              className="flex items-center gap-3 px-3 py-2.5 text-sm cursor-pointer rounded-lg hover:bg-destructive/10 focus:bg-destructive/10 text-destructive transition-colors mt-1"
            >
              <div className="w-8 h-8 rounded-md bg-destructive/10 flex items-center justify-center">
                <LogOut className="h-4 w-4" />
              </div>
              <span className="font-medium">Cerrar sesión</span>
            </DropdownMenuItem>
          </div>
        </DropdownMenuContent>
      </DropdownMenu>
    </div>
  );
}

