                              <CardContent className="p-6 space-y-6 bg-white animate-in fade-in slide-in-from-top-2 duration-200">
                                {/* Diagnóstico */}
                                <div className="space-y-2">
                                  <h4 className="text-[11px] font-bold text-slate-400 uppercase tracking-wider">
                                    Diagnóstico
                                  </h4>
                                  <div className="text-sm text-slate-600 bg-slate-50 p-4 rounded-2xl border border-slate-100/50">
                                    {treatment.diagnostico}
                                  </div>
                                </div>

                                {/* Citas */}
                                <div className="space-y-3">
                                  <h4 className="text-[11px] font-bold text-slate-400 uppercase tracking-wider">
                                    Citas del tratamiento
                                  </h4>
                                  {(() => {
                                    const citasIdsSet = new Set(treatment.citas || []);
                                    const citasDelTratamiento = appointments.filter(apt =>
                                      citasIdsSet.has(apt.id) || apt.tratamiento_id === treatment.id
                                    );

                                    if (citasDelTratamiento.length === 0) {
                                      return (
                                        <p className="text-xs text-muted-foreground italic pl-1">
                                          No hay citas registradas
                                        </p>
                                      );
                                    }

                                    return (
                                      <div className="rounded-2xl border border-slate-100 overflow-hidden shadow-sm">
                                        <div className="bg-slate-50/50 px-4 py-2 grid grid-cols-12 gap-2 text-[10px] font-bold text-slate-400 uppercase tracking-wider border-b">
                                          <div className="col-span-1">N°</div>
                                          <div className="col-span-4">Fecha</div>
                                          <div className="col-span-3">Atendido por</div>
                                          <div className="col-span-2">Duración</div>
                                          <div className="col-span-2 text-right">Acción</div>
                                        </div>
                                        <div className="divide-y divide-slate-100">
                                          {citasDelTratamiento.map((cita: any, idx: number) => {
                                            const fechaCita = cita.fecha instanceof Date ? cita.fecha : new Date(cita.fecha);
                                            return (
                                              <div key={cita.id} className="px-4 py-3 grid grid-cols-12 gap-2 items-center hover:bg-slate-50/30 transition-colors">
                                                <div className="col-span-1 text-xs font-bold text-slate-400">{idx + 1}</div>
                                                <div className="col-span-4">
                                                  <p className="text-xs font-bold text-slate-700">
                                                    {fechaCita.toLocaleDateString('es-PE', {
                                                      day: '2-digit', month: 'short', year: 'numeric'
                                                    })}
                                                  </p>
                                                  <p className="text-[10px] text-muted-foreground">{cita.hora}</p>
                                                </div>
                                                <div className="col-span-3 text-xs text-slate-600 truncate">
                                                  {cita.atendido_por || "—"}
                                                </div>
                                                <div className="col-span-2 text-xs text-slate-600">
                                                  {cita.duracion ? `${cita.duracion}m` : "—"}
                                                </div>
                                                <div className="col-span-2 text-right">
                                                  <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="h-7 px-2 text-[10px] text-primary hover:text-primary hover:bg-primary/5"
                                                    onClick={(e) => {
                                                      e.stopPropagation();
                                                      setSelectedCitaDetail(cita);
                                                      setIsCitaDetailOpen(true);
                                                    }}
                                                  >
                                                    <Eye className="h-3 w-3 mr-1" />
                                                    Detalle
                                                  </Button>
                                                </div>
                                              </div>
                                            );
                                          })}
                                        </div>
                                      </div>
                                    );
                                  })()}
                                </div>

                                {/* Presupuesto Detallado */}
                                <div className="space-y-3">
                                  <h4 className="text-[11px] font-bold text-slate-400 uppercase tracking-wider">
                                    Presupuesto Detallado
                                  </h4>
                                  <div className="rounded-2xl border border-slate-100 overflow-hidden shadow-sm">
                                    <div className="bg-slate-50/50 px-4 py-2 grid grid-cols-12 gap-4 text-[10px] font-bold text-slate-400 uppercase tracking-wider border-b">
                                      <div className="col-span-1 tracking-tighter">Cant.</div>
                                      <div className="col-span-7">Descripción</div>
                                      <div className="col-span-2 text-right">Unit.</div>
                                      <div className="col-span-2 text-right">Total</div>
                                    </div>
                                    <div className="divide-y divide-slate-100">
                                      {treatment.presupuesto.map((item, idx) => (
                                        <div key={idx}>
                                          <div className="px-4 py-3 grid grid-cols-12 gap-4 items-center">
                                            <div className="col-span-1 text-xs font-bold text-slate-400">{item.cantidad}</div>
                                            <div className="col-span-7 text-xs font-medium text-slate-700">{item.descripcion}</div>
                                            <div className="col-span-2 text-right text-[11px] text-slate-500">
                                              {item.subitems && item.subitems.length > 0 ? "-" : formatCurrency(item.precio_unitario)}
                                            </div>
                                            <div className="col-span-2 text-right text-xs font-bold text-slate-700">
                                              {formatCurrency(
                                                item.subitems && item.subitems.length > 0
                                                  ? item.subitems.reduce((sum: number, sub: any) => sum + (sub.cantidad * sub.precio_unitario), 0)
                                                  : item.cantidad * item.precio_unitario
                                              )}
                                            </div>
                                          </div>
                                          {item.subitems?.map((subitem: any, subIdx: number) => (
                                            <div key={subIdx} className="px-4 py-2 grid grid-cols-12 gap-4 bg-slate-50/50 items-center">
                                              <div className="col-span-1 text-[11px] text-slate-400 pl-2">{subitem.cantidad}</div>
                                              <div className="col-span-7 text-[11px] text-slate-500 pl-2">↳ {subitem.descripcion}</div>
                                              <div className="col-span-2 text-right text-[10px] text-slate-400">
                                                {formatCurrency(subitem.precio_unitario)}
                                              </div>
                                              <div className="col-span-2 text-right text-[11px] font-medium text-slate-500">
                                                {formatCurrency(subitem.cantidad * subitem.precio_unitario)}
                                              </div>
                                            </div>
                                          ))}
                                        </div>
                                      ))}
                                    </div>
                                    <div className="bg-slate-50 border-t-2 border-slate-200 px-4 py-3 grid grid-cols-12 gap-4 items-center">
                                      <div className="col-span-1" />
                                      <div className="col-span-7 text-xs font-bold text-slate-600 uppercase tracking-wider">Total</div>
                                      <div className="col-span-2" />
                                      <div className="col-span-2 text-right text-xs font-bold text-slate-800">
                                        {formatCurrency(treatment.total_presupuesto)}
                                      </div>
                                    </div>
                                  </div>
                                </div>

                                {/* Cronograma de Pagos */}
                                <div className="space-y-3">
                                  <h4 className="text-[11px] font-bold text-slate-400 uppercase tracking-wider">
                                    Cronograma de Pagos
                                  </h4>
                                  {treatment.cronograma_pagos && treatment.cronograma_pagos.length > 0 ? (
                                    <div className="rounded-2xl border border-slate-100 overflow-hidden shadow-inner bg-slate-50/30">
                                      <div className="bg-slate-50/50 px-4 py-2 grid grid-cols-12 gap-2 text-[10px] font-bold text-slate-400 uppercase tracking-wider border-b">
                                        <div className="col-span-1">N°</div>
                                        <div className="col-span-8 text-right">Monto</div>
                                        <div className="col-span-3 text-right pr-2">Estado</div>
                                      </div>

                                      <div className="bg-white/40 divide-y divide-slate-100">
                                        {treatment.cronograma_pagos.map((cuota, i) => (
                                          <div key={i} className="px-4 py-3 grid grid-cols-12 gap-2 items-center hover:bg-slate-50/30 transition-colors">
                                            <div className="col-span-1 text-xs font-bold text-slate-400">
                                              {cuota.numero === 0 ? "★" : cuota.numero}
                                            </div>
                                            <div className="col-span-8 text-right text-xs font-bold text-slate-700">
                                              {formatCurrency(cuota.monto)}
                                            </div>
                                            <div className="col-span-3 flex justify-end">
                                              <Badge
                                                variant="secondary"
                                                className={cn(
                                                  "text-[9px] px-1.5 py-0 font-bold uppercase tracking-wider",
                                                  cuota.estado === "pagado"
                                                    ? "bg-green-50 text-green-600 border-green-100"
                                                    : "bg-amber-50 text-amber-600 border-amber-100"
                                                )}
                                              >
                                                {cuota.estado}
                                              </Badge>
                                            </div>
                                          </div>
                                        ))}
                                      </div>
                                    </div>
                                  ) : (
                                    <div className="p-4 rounded-2xl border border-dashed border-slate-200 text-center bg-slate-50/50">
                                      <p className="text-xs text-muted-foreground italic mb-3">No se ha definido un cronograma de pagos</p>
                                      <Button
                                        variant="outline"
                                        size="sm"
                                        className="h-8 text-[11px]"
                                        onClick={(e) => {
                                          e.stopPropagation();
                                          setSelectedTreatment(treatment);
                                          setIsEditTreatmentDialogOpen(true);
                                        }}
                                      >
                                        <Plus className="h-3.5 w-3.5 mr-1.5" />
                                        Definir Cronograma
                                      </Button>
                                    </div>
                                  )}
                                </div>

                                {/* Acciones del tratamiento */}
                                <div className="flex justify-end gap-2 pt-4 border-t border-slate-100">
                                  <Button
                                    variant="outline"
                                    size="sm"
                                    className="h-8 text-[11px] border-red-200 text-red-500 hover:bg-red-50 hover:text-red-600"
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      setTreatmentToDelete(treatment.id);
                                      setIsDeleteDialogOpen(true);
                                    }}
                                  >
                                    <Trash2 className="h-3.5 w-3.5 mr-1.5" />
                                    Eliminar
                                  </Button>

                                  {treatment.estado !== "cancelado" && treatment.estado !== "cancelada" && (
                                    <DropdownMenu>
                                      <DropdownMenuTrigger asChild>
                                        <Button
                                          variant="outline"
                                          size="sm"
                                          className="h-8 text-[11px] border-slate-200 text-slate-500 hover:bg-slate-50"
                                          onClick={(e) => e.stopPropagation()}
                                        >
                                          <Activity className="h-3.5 w-3.5 mr-1.5" />
                                          Cambiar estado
                                          <ChevronDown className="h-3 w-3 ml-1.5" />
                                        </Button>
                                      </DropdownMenuTrigger>
                                      <DropdownMenuContent align="end">
                                        {treatment.estado === "pausada" || treatment.estado === "pausado" ? (
                                          <DropdownMenuItem
                                            onClick={async (e) => {
                                              e.stopPropagation();
                                              try {
                                                await updateTreatment(treatment.id!, {
                                                  ...treatment,
                                                  estado: "activo",
                                                  monto_abonado: treatment.monto_abonado || 0,
                                                  total_presupuesto: treatment.total_presupuesto || 0,
                                                  cantidad_citas_planificadas: treatment.cantidad_citas_planificadas || 0,
                                                  presupuesto: treatment.presupuesto || [],
                                                  diagnostico: treatment.diagnostico || "",
                                                  tratamiento: treatment.tratamiento || ""
                                                } as any);
                                                toast({ title: "Estado actualizado", description: "Tratamiento activado" });
                                                fetchTreatments();
                                              } catch (error) {
                                                toast({ title: "Error", description: "No se pudo actualizar el estado", variant: "destructive" });
                                              }
                                            }}
                                          >
                                            Activar
                                          </DropdownMenuItem>
                                        ) : (
                                          <DropdownMenuItem
                                            onClick={async (e) => {
                                              e.stopPropagation();
                                              try {
                                                await updateTreatment(treatment.id!, {
                                                  ...treatment,
                                                  estado: "pausado",
                                                  monto_abonado: treatment.monto_abonado || 0,
                                                  total_presupuesto: treatment.total_presupuesto || 0,
                                                  cantidad_citas_planificadas: treatment.cantidad_citas_planificadas || 0,
                                                  presupuesto: treatment.presupuesto || [],
                                                  diagnostico: treatment.diagnostico || "",
                                                  tratamiento: treatment.tratamiento || ""
                                                } as any);
                                                toast({ title: "Estado actualizado", description: "Tratamiento pausado" });
                                                fetchTreatments();
                                              } catch (error) {
                                                toast({ title: "Error", description: "No se pudo actualizar el estado", variant: "destructive" });
                                              }
                                            }}
                                          >
                                            Pausado
                                          </DropdownMenuItem>
                                        )}
                                        <DropdownMenuItem
                                          className="text-red-500 focus:text-red-600"
                                          onClick={(e) => {
                                            e.stopPropagation();
                                            setTreatmentToCancel(treatment);
                                            setIsCancelDialogOpen(true);
                                          }}
                                        >
                                          Cancelado
                                        </DropdownMenuItem>
                                      </DropdownMenuContent>
                                    </DropdownMenu>
                                  )}

                                  <Button
                                    size="sm"
                                    className="h-8 text-[11px] bg-[#00665a] hover:bg-[#004d44]"
                                    onClick={(e) => {
                                      e.stopPropagation();
                                      setSelectedTreatment(treatment);
                                      setIsEditTreatmentDialogOpen(true);
                                    }}
                                  >
                                    <Edit className="h-3.5 w-3.5 mr-1.5" />
                                    Editar
                                  </Button>
                                </div>
                              </CardContent>
                            )}
                          </Card>
                        );
                      })}
                    </div>
                  )}
                </>
              )}
            </div>
          </ScrollArea>
        </div>
      </div>
    );
  };

  const PatientHeader = () => {
    const optionalFields = [
      patient!.email,
      patient!.celular,
      patient!.direccion,
      patient!.distrito_direccion,
      patient!.lugar_procedencia,
      patient!.estado_civil,
      patient!.ocupacion,
      patient!.sexo,
      patient!.fecha_nacimiento,
    ];
    const filled = optionalFields.filter(f => f && String(f).trim() !== "").length;
    const total = optionalFields.length;
    const pct = Math.round((filled / total) * 100);
    const isComplete = pct === 100;

    const size = 76;
    const strokeWidth = 7;
    const radius = (size - strokeWidth) / 2;
    const circumference = 2 * Math.PI * radius;
    const dashOffset = circumference - (pct / 100) * circumference;
    const ringColor = isComplete ? "#22c55e" : "#eab308";

    return (
      <div className="p-0">
        <div>
          <Link to="/pacientes">
            <Button variant="ghost" size="sm" className="-ml-2 h-7 text-[10px] text-muted-foreground hover:text-primary transition-colors font-bold uppercase tracking-wider">
              <ArrowLeft className="h-3 w-3 mr-1" />
              Volver
            </Button>
          </Link>
        </div>

        <Separator className="my-6" />

        <div className="md:w-[80%] mx-auto">
          <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-6 border-b border-slate-50 pb-0">
            <div className="flex items-center gap-5 min-w-0">
              <div className="w-20 h-20 rounded-full bg-primary/10 flex items-center justify-center flex-shrink-0 shadow-inner">
                <span className="text-2xl font-bold text-primary">
                  {patient!.initials}
                </span>
              </div>
              <div className="flex-1 min-w-0 flex flex-col gap-2">
                <div className="flex flex-wrap items-center gap-4">
                  <h1 className="text-3xl font-bold text-foreground leading-tight m-0">
                    {patient!.fullName}
                  </h1>
                  {isComplete && (
                    <Badge className="bg-green-500 hover:bg-green-500 text-white text-xs">
                      Perfil completo
                    </Badge>
                  )}
                </div>

                <div className="flex flex-wrap items-center gap-3">
                  <span className="text-sm text-muted-foreground">
                    DNI: {patient!.dni_cliente}
                  </span>
                  {patient!.age && (
                    <span className="text-sm text-muted-foreground">
                      {patient!.age} años
                    </span>
                  )}
                </div>

                {(patient!.celular || patient!.ocupacion) && (
                  <div className="flex flex-wrap items-center gap-3">
                    {patient!.celular && (
                      <div className="flex items-center gap-1">
                        <Phone className="h-4 w-4 text-muted-foreground" />
                        <span className="text-sm text-muted-foreground">
                          {patient!.celular}
                        </span>
                      </div>
                    )}
                    {patient!.ocupacion && (
                      <div className="flex items-center gap-1">
                        <Briefcase className="h-4 w-4 text-muted-foreground" />
                        <span className="text-sm text-muted-foreground">
                          {patient!.ocupacion}
                        </span>
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>

            {!isComplete && (
              <div className="flex flex-col items-center ml-4 self-start">
                <div className="relative" style={{ width: size, height: size }}>
                  <svg width={size} height={size} className="-rotate-90">
                    <circle
                      cx={size / 2}
                      cy={size / 2}
                      r={radius}
                      fill="none"
                      stroke={ringColor}
                      strokeWidth={strokeWidth}
                      strokeOpacity={0.2}
                    />
                    <circle
                      cx={size / 2}
                      cy={size / 2}
                      r={radius}
                      fill="none"
                      stroke={ringColor}
                      strokeWidth={strokeWidth}
                      strokeDasharray={circumference}
                      strokeDashoffset={dashOffset}
                      strokeLinecap="round"
                      style={{ transition: "stroke-dashoffset 0.5s ease" }}
                    />
                  </svg>
                  <div className="absolute inset-0 flex items-center justify-center">
                    <span className="text-[13px] font-bold" style={{ color: ringColor }}>
                      {pct}%
                    </span>
                  </div>
                </div>
              </div>
            )}

            <Button
              variant={isComplete ? "outline" : "default"}
              size="sm"
              onClick={() => setIsEditDialogOpen(true)}
              className={isComplete ? "md:ml-auto" : "md:ml-auto bg-amber-400 hover:bg-amber-500 text-white border-0"}
            >
              <Edit className="h-4 w-4 mr-2 shrink-0" />
              {isComplete ? "Editar" : "Completar datos"}
            </Button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-4">
      <div className="bg-background rounded-3xl overflow-hidden">
        {PatientHeader()}

        <Separator className="my-6" />

        <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
          <TabsList className="grid w-full grid-cols-4 mb-6">
            <TabsTrigger value="general">Información General</TabsTrigger>
            <TabsTrigger value="movimientos">Historial</TabsTrigger>
            <TabsTrigger value="treatments">Tratamientos</TabsTrigger>
            <TabsTrigger value="financial">Finanzas</TabsTrigger>
          </TabsList>

          <TabsContent value="general" className="space-y-6">
            {GeneralTab()}
          </TabsContent>

          <TabsContent value="movimientos">
            <MovimientosRecientes
              appointments={appointments}
              pagos={pagos}
              loadingAppointments={loadingAppointments}
              loadingPagos={loadingPagos}
            />
          </TabsContent>

          <TabsContent value="treatments">
            {TreatmentsTab()}
          </TabsContent>

          <TabsContent value="financial">
            {FinancialTab()}
          </TabsContent>

        </Tabs>
      </div>

      <EditPatientDialog
        open={isEditDialogOpen}
        onOpenChange={setIsEditDialogOpen}
        patient={patient}
        onSuccess={handleEditSuccess}
      />

      <TreatmentDialog
        open={isTreatmentDialogOpen}
        onOpenChange={setIsTreatmentDialogOpen}
        patientId={patient.id!}
        patientName={patient.fullName}
        onSuccess={handleTreatmentSuccess}
      />
      <TreatmentEditDialog
        open={isEditTreatmentDialogOpen}
        onOpenChange={setIsEditTreatmentDialogOpen}
        treatment={selectedTreatment}
        onSuccess={handleTreatmentSuccess}
      />
      <ConfirmationDialog
        open={isDeleteDialogOpen}
        onOpenChange={(open) => {
          setIsDeleteDialogOpen(open);
          if (!open) {
            setTreatmentToDelete(null);
          }
        }}
        onConfirm={handleDeleteTreatment}
        title="¿Eliminar tratamiento?"
        description="Esta acción eliminará permanentemente el tratamiento y todos sus datos relacionados. Esta acción no se puede deshacer."
        confirmText="Eliminar"
        cancelText="Cancelar"
        variant="destructive"
        loading={isDeleting}
      />
      <ConfirmationDialog
        open={isCancelDialogOpen}
        onOpenChange={(open) => {
          setIsCancelDialogOpen(open);
          if (!open) {
            setTreatmentToCancel(null);
          }
        }}
        onConfirm={handleCancelTreatment}
        title="¿Cancelar tratamiento?"
        description="Esta acción es irreversible. Una vez cancelado, el tratamiento no podrá volver a activarse."
        confirmText="Confirmar Cancelación"
        cancelText="Volver"
        variant="destructive"
        loading={isCancelling}
      />
      <PaymentDialog
        open={isPaymentDialogOpen}
        onOpenChange={(open) => {
          setIsPaymentDialogOpen(open);
          if (!open) {
            setSelectedPaymentType(undefined);
            setSelectedPaymentReferenceId(undefined);
          }
        }}
        onSuccess={() => {
          fetchTreatments();
          fetchPagos();
          fetchPatient();
        }}
        preselectedPatientId={patient?.id}
        preselectedPatientName={patient?.fullName}
        preselectedType={selectedPaymentType}
        preselectedReferenceId={selectedPaymentReferenceId}
      />

      {/* Modal de detalle de cita de tratamiento */}
      <Dialog open={isCitaDetailOpen} onOpenChange={setIsCitaDetailOpen}>
        <DialogContent className="max-w-2xl p-0 overflow-hidden">
          {selectedCitaDetail && (() => {
            const cita = selectedCitaDetail;
            const fechaCita = cita.fecha instanceof Date ? cita.fecha : new Date(cita.fecha);
            const estadoNorm = cita.estado?.toLowerCase() || '';
            const isAtendida = estadoNorm === 'atendida' || estadoNorm === 'completada';
            const creadoPor = cita.historial_estados?.[0]?.realizado_por;
            return (
              <div className="flex flex-col max-h-[90vh]">
                {/* Header */}
                <div className="flex items-center justify-between gap-4 px-6 pt-6 pb-4 flex-shrink-0">
                  <DialogTitle className="text-xl font-semibold">
                    {citaDetailType === "consulta" ? "Detalle de Consulta" : "Detalle de Cita"}
                  </DialogTitle>
                  <div className="mt-1">{getStatusBadge(cita.estado)}</div>
                </div>

                {/* Contenido */}
                <div className="overflow-y-auto min-h-0 px-6 pb-6">
                  <div className="space-y-3">

                    {/* Fecha y Hora */}
                    <div className="grid grid-cols-2 gap-3">
                      <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                        <Calendar className="h-4 w-4 text-primary flex-shrink-0" />
                        <div>
                          <p className="text-xs text-muted-foreground">Fecha</p>
                          <p className="text-sm font-semibold">
                            {fechaCita.toLocaleDateString('es-PE', { day: '2-digit', month: 'long', year: 'numeric' })}
                          </p>
                        </div>
                      </div>
                      <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                        <Clock className="h-4 w-4 text-primary flex-shrink-0" />
                        <div>
                          <p className="text-xs text-muted-foreground">Hora</p>
                          <p className="text-sm font-semibold">{cita.hora}</p>
                        </div>
                      </div>
                    </div>

                    {/* Celular y Consulta/Tratamiento */}
                    <div className="grid grid-cols-2 gap-3">
                      <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                        <Phone className="h-4 w-4 text-primary flex-shrink-0" />
                        <div>
                          <p className="text-xs text-muted-foreground">Celular</p>
                          <p className="text-sm font-semibold">{patient?.celular || "No registrado"}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                        <Stethoscope className="h-4 w-4 text-primary flex-shrink-0" />
                        <div>
                          <p className="text-xs text-muted-foreground">
                            {cita.es_tratamiento ? "Tratamiento" : "Consulta"}
                          </p>
                          <p className="text-sm font-semibold">
                            {cita.es_tratamiento ? (cita.tratamiento_nombre || cita.tipo_consulta) : cita.tipo_consulta}
                          </p>
                        </div>
                      </div>
                    </div>

                    {/* Duración estimada y Creado por */}
                    <div className="grid grid-cols-2 gap-3">
                      <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                        <Clock className="h-4 w-4 text-primary flex-shrink-0" />
                        <div>
                          <p className="text-xs text-muted-foreground">Duración estimada</p>
                          <p className="text-sm font-semibold">{cita.duracion ? `${cita.duracion} min` : "No registrado"}</p>
                        </div>
                      </div>
                      {creadoPor && (
                        <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                          <User className="h-4 w-4 text-primary flex-shrink-0" />
                          <div>
                            <p className="text-xs text-muted-foreground">Creado por</p>
                            <p className="text-sm font-semibold">{creadoPor}</p>
                          </div>
                        </div>
                      )}
                    </div>

                    {/* Notas generales */}
                    {cita.notas_observaciones && (
                      <div className="flex items-start gap-3 p-3 border rounded-lg bg-muted/30">
                        <FileText className="h-4 w-4 text-primary flex-shrink-0 mt-0.5" />
                        <div>
                          <p className="text-xs text-muted-foreground">Notas</p>
                          <p className="text-sm font-semibold whitespace-pre-line mt-0.5">{cita.notas_observaciones}</p>
                        </div>
                      </div>
                    )}

                    {/* Sección de atención */}
                    {isAtendida && (
                      <div className="border-t pt-3 space-y-3">
                        <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider flex items-center gap-1.5">
                          <Activity className="h-3.5 w-3.5" />
                          Información de atención
                        </p>

                        {/* Personal */}
                        {cita.personal_consulta && cita.personal_consulta.length > 0 ? (
                          <div className="flex items-start gap-3 p-3 border rounded-lg bg-muted/30">
                            <Users className="h-4 w-4 text-primary flex-shrink-0 mt-0.5" />
                            <div className="flex-1">
                              <p className="text-xs text-muted-foreground mb-1.5">Personal</p>
                              <div className="space-y-1">
                                {cita.personal_consulta.map((p: any, i: number) => (
                                  <div key={i} className="flex items-center justify-between">
                                    <p className="text-sm font-semibold">{p.nombre}</p>
                                    <span className="text-xs text-muted-foreground bg-muted px-2 py-0.5 rounded-full">{p.rol}</span>
                                  </div>
                                ))}
                              </div>
                            </div>
                          </div>
                        ) : (
                          <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                            <UserCheck className="h-4 w-4 text-primary flex-shrink-0" />
                            <div>
                              <p className="text-xs text-muted-foreground">Atendido por</p>
                              <p className="text-sm font-semibold">{cita.atendido_por || "No registrado"}</p>
                            </div>
                          </div>
                        )}

                        <div className="flex items-center gap-3 p-3 border rounded-lg bg-muted/30">
                          <Timer className="h-4 w-4 text-primary flex-shrink-0" />
                          <div>
                            <p className="text-xs text-muted-foreground">Duración real</p>
                            <p className="text-sm font-semibold">
                              {cita.duracion_real && cita.duracion_real !== "0"
                                ? `${cita.duracion_real} min`
                                : "No registrada"}
                            </p>
                          </div>
                        </div>

                        {cita.notas_atencion && (
                          <div className="flex items-start gap-3 p-3 border rounded-lg bg-muted/30">
                            <FileText className="h-4 w-4 text-primary flex-shrink-0 mt-0.5" />
                            <div>
                              <p className="text-xs text-muted-foreground">Notas de cita</p>
                              <p className="text-sm font-semibold whitespace-pre-line mt-0.5">{cita.notas_atencion}</p>
                            </div>
                          </div>
                        )}

                        {cita.planificacion_siguiente_cita && (
                          <div className="flex items-start gap-3 p-3 border rounded-lg bg-muted/30">
                            <CalendarPlus className="h-4 w-4 text-primary flex-shrink-0 mt-0.5" />
                            <div>
                              <p className="text-xs text-muted-foreground">Planificación siguiente cita</p>
                              <p className="text-sm font-semibold whitespace-pre-line mt-0.5">{cita.planificacion_siguiente_cita}</p>
                            </div>
                          </div>
                        )}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            );
          })()}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
} from "@/components/ui/dialog";
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from "@/components/ui/form";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { toast } from "@/hooks/use-toast";
import {
    Calendar as CalendarIcon,
    Loader2,
    User,
    Phone,
    MapPin,
    Mail,
    Info,
    CreditCard,
    Save,
    X,
    Hash
} from "lucide-react";
import { format } from "date-fns";
import { es } from "date-fns/locale";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { cn } from "@/lib/utils";
import { doc, updateDoc, Timestamp } from "firebase/firestore";
import { db } from "@/lib/firebase";
import { Patient } from "@/types/appointment";
import { capitalizeName } from "@/utils/formatters";
import { useActivityLog } from "@/hooks/useActivityLog";
import { diffObjects } from "@/utils/activityDiff";

// 📋 SCHEMA DE VALIDACIÓN (IDÉNTICO AL DE CREACIÓN PARA CONSISTENCIA)
const patientFormSchema = z.object({
    nombre: z.string().min(1, "El nombre es requerido"),
    apellido_paterno: z.string().min(1, "El apellido paterno es requerido"),
    apellido_materno: z.string().min(1, "El apellido materno es requerido"),
    dni_cliente: z
        .string()
        .length(8, "El DNI debe tener 8 dígitos")
        .regex(/^\d+$/, "Solo se permiten números"),
    edad: z.number().min(0, "La edad debe ser mayor a 0").optional(),
    fecha_nacimiento: z.date({
        required_error: "La fecha de nacimiento es requerida",
    }),
    sexo: z.enum(["Masculino", "Femenino", "Otro", ""]),
    email: z.string().email("Email inválido").or(z.literal("")),
    celular: z
        .string()
        .length(9, "El celular debe tener 9 dígitos")
        .regex(/^9\d+$/, "Debe empezar con 9"),
    telefono_fijo: z.string().optional(),
    direccion: z.string().optional(),
    distrito_direccion: z.string().optional(),
    lugar_procedencia: z.string().optional(),
    estado_civil: z.enum(["Soltero", "Casado", "Divorciado", "Viudo", ""]),
    ocupacion: z.string().optional(),
});

type PatientFormValues = z.infer<typeof patientFormSchema>;

interface EditPatientDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    patient: Patient | null;
    onSuccess?: () => void;
}

export default function EditPatientDialog({
    open,
    onOpenChange,
    patient,
    onSuccess,
}: EditPatientDialogProps) {
    const [isSubmitting, setIsSubmitting] = useState(false);
    const { log } = useActivityLog();
    const [displayDate, setDisplayDate] = useState<Date>(new Date());

    const form = useForm<PatientFormValues>({
        resolver: zodResolver(patientFormSchema),
        defaultValues: {
            nombre: "",
            apellido_paterno: "",
            apellido_materno: "",
            dni_cliente: "",
            edad: undefined,
            fecha_nacimiento: undefined,
            sexo: "",
            email: "",
            celular: "",
            telefono_fijo: "",
            direccion: "",
            distrito_direccion: "",
            lugar_procedencia: "",
            estado_civil: "",
            ocupacion: "",
        },
    });

    // Cargar datos del paciente cuando se abre el modal
    useEffect(() => {
        if (patient && open) {
            form.reset({
                nombre: patient.nombre || "",
                apellido_paterno: patient.apellido_paterno || "",
                apellido_materno: patient.apellido_materno || "",
                dni_cliente: patient.dni_cliente || "",
                edad: patient.edad || undefined,
                fecha_nacimiento: patient.fecha_nacimiento || undefined,
                sexo: (patient.sexo as any) || "",
                email: patient.email || "",
                celular: patient.celular || "",
                telefono_fijo: patient.telefono_fijo || "",
                direccion: patient.direccion || "",
                distrito_direccion: patient.distrito_direccion || "",
                lugar_procedencia: patient.lugar_procedencia || "",
                estado_civil: (patient.estado_civil as any) || "",
                ocupacion: patient.ocupacion || "",
            });
            if (patient.fecha_nacimiento) {
                setDisplayDate(patient.fecha_nacimiento);
            }
        }
    }, [patient, open, form]);

    const calculateAge = (date: Date) => {
        const today = new Date();
        let age = today.getFullYear() - date.getFullYear();
        const monthDiff = today.getMonth() - date.getMonth();
        if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < date.getDate())) {
            age--;
        }
        return age;
    };

    const onSubmit = async (data: PatientFormValues) => {
        if (!patient?.id) {
            toast({
                title: "❌ Error",
                description: "No se puede actualizar el paciente sin ID.",
                variant: "destructive",
            });
            return;
        }

        try {
            setIsSubmitting(true);

            const updatedData = {
                nombre: capitalizeName(data.nombre.trim()),
                apellido_paterno: capitalizeName(data.apellido_paterno.trim()),
                apellido_materno: capitalizeName(data.apellido_materno.trim()),
                dni_cliente: data.dni_cliente,
                edad: data.edad || null,
                fecha_nacimiento: data.fecha_nacimiento
                    ? Timestamp.fromDate(data.fecha_nacimiento)
                    : null,
                sexo: data.sexo || "",
                email: data.email?.toLowerCase().trim() || "",
                celular: data.celular,
                telefono_fijo: data.telefono_fijo || "",
                direccion: capitalizeName(data.direccion?.trim() || ""),
                distrito_direccion: capitalizeName(data.distrito_direccion?.trim() || ""),
                lugar_procedencia: capitalizeName(data.lugar_procedencia?.trim() || ""),
                estado_civil: data.estado_civil || "",
                ocupacion: capitalizeName(data.ocupacion?.trim() || ""),
            };

            await updateDoc(doc(db, "pacientes", patient.id), updatedData);

            toast({
                title: "✅ Paciente actualizado",
                description: `${updatedData.nombre} ${updatedData.apellido_paterno} ha sido actualizado con éxito.`,
            });

            // Registrar actividad con diferencias
            const cambios = diffObjects(
                {
                    nombre: patient.nombre,
                    apellido_paterno: patient.apellido_paterno,
                    celular: patient.celular,
                    email: patient.email,
                    direccion: patient.direccion,
                    distrito_direccion: patient.distrito_direccion,
                    estado_civil: patient.estado_civil,
                    ocupacion: patient.ocupacion,
                    sexo: patient.sexo,
                },
                {
                    nombre: updatedData.nombre,
                    apellido_paterno: updatedData.apellido_paterno,
                    celular: updatedData.celular,
                    email: updatedData.email,
                    direccion: updatedData.direccion,
                    distrito_direccion: updatedData.distrito_direccion,
                    estado_civil: updatedData.estado_civil,
                    ocupacion: updatedData.ocupacion,
                    sexo: updatedData.sexo,
                },
                {
                    nombre: "Nombre",
                    apellido_paterno: "Apellido",
                    celular: "Celular",
                    email: "Email",
                    direccion: "Dirección",
                    distrito_direccion: "Distrito",
                    estado_civil: "Estado civil",
                    ocupacion: "Ocupación",
                    sexo: "Sexo",
                }
            );

            await log({
                modulo: "Pacientes",
                accion: "editó",
                entidad: "paciente",
                entidad_id: patient.id,
                entidad_nombre: `${updatedData.nombre} ${updatedData.apellido_paterno}`,
                cambios,
            });

            onOpenChange(false);
            onSuccess?.();
        } catch (error) {
            console.error("Error al actualizar paciente:", error);
            toast({
                title: "❌ Error",
                description: "No se pudo actualizar el paciente. Intenta de nuevo.",
                variant: "destructive",
            });
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-3xl h-[90vh] flex flex-col p-0 border-none bg-white rounded-3xl overflow-hidden">
                <DialogHeader className="px-6 py-5 border-b border-slate-100 bg-white flex-none relative">
                    <DialogTitle className="text-2xl font-semibold text-slate-900">Editar Paciente</DialogTitle>
                    <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        className="absolute right-4 top-4 rounded-full h-10 w-10 text-slate-400 hover:text-slate-900 hover:bg-slate-100 transition-all"
                        onClick={() => onOpenChange(false)}
                    >
                        <X className="h-5 w-5" />
                    </Button>
                </DialogHeader>

                <div className="flex-1 overflow-y-auto px-6 pt-1 pb-2">
                    <Form {...form}>
                        <form id="edit-patient-form" autoComplete="off" onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
                        {/* 👤 SECCIÓN: INFORMACIÓN PERSONAL */}
                        <div className="space-y-4">
                            <div className="flex items-center gap-2 pb-2 border-b border-slate-100">
                                <User className="h-4 w-4 text-primary" />
                                <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Información Personal</h3>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-2">
                                <FormField
                                    control={form.control}
                                    name="nombre"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel className="text-slate-700 font-medium text-[13px]">Nombre(s) *</FormLabel>
                                            <FormControl>
                                                <Input
                                                    {...field}
                                                    placeholder="Ej. Juan"
                                                    className="h-11 bg-slate-50 border-slate-200 rounded-xl focus:bg-white transition-all"
                                                    onChange={(e) => field.onChange(capitalizeName(e.target.value.replace(/[^a-zA-ZáéíóúÁÉÍÓÚüÜñÑ\s]/g, "")))}
                                                />
                                            </FormControl>
                                            <FormMessage className="text-[11px]" />
                                        </FormItem>
                                    )}
                                />
                                <FormField
                                    control={form.control}
                                    name="apellido_paterno"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel className="text-slate-700 font-medium text-[13px]">Apellido Paterno *</FormLabel>
                                            <FormControl>
                                                <Input
                                                    {...field}
                                                    placeholder="Ej. Pérez"
                                                    className="h-11 bg-slate-50 border-slate-200 rounded-xl focus:bg-white transition-all"
                                                    onChange={(e) => field.onChange(capitalizeName(e.target.value.replace(/[^a-zA-ZáéíóúÁÉÍÓÚüÜñÑ\s]/g, "")))}
                                                />
                                            </FormControl>
                                            <FormMessage className="text-[11px]" />
                                        </FormItem>
                                    )}
                                />
                                <FormField
                                    control={form.control}
                                    name="apellido_materno"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel className="text-slate-700 font-medium text-[13px]">Apellido Materno *</FormLabel>
                                            <FormControl>
                                                <Input
                                                    {...field}
                                                    placeholder="Ej. López"
                                                    className="h-11 bg-slate-50 border-slate-200 rounded-xl focus:bg-white transition-all"
                                                    onChange={(e) => field.onChange(capitalizeName(e.target.value.replace(/[^a-zA-ZáéíóúÁÉÍÓÚüÜñÑ\s]/g, "")))}
                                                />
                                            </FormControl>
                                            <FormMessage className="text-[11px]" />
                                        </FormItem>
                                    )}
                                />
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <FormField
                                    control={form.control}
                                    name="dni_cliente"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel className="text-slate-700 font-medium text-[13px]">
                                                DNI *
                                            </FormLabel>
                                            <FormControl>
                                                <Input
                                                    {...field}
                                                    placeholder="8 dígitos"
                                                    maxLength={8}
                                                    className="h-11 bg-slate-50 border-slate-200 rounded-xl focus:bg-white transition-all"
                                                    onChange={(e) => {
                                                        const val = e.target.value.replace(/\D/g, "");
                                                        if (val.length > 0 && val[0] === "0") return;
                                                        field.onChange(val);
                                                    }}
                                                />
                                            </FormControl>
                                            <FormMessage className="text-[11px]" />
                                        </FormItem>
                                    )}
                                />
                                <FormField
                                    control={form.control}
                                    name="sexo"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel className="text-slate-700 font-medium text-[13px]">Sexo</FormLabel>
                                            <Select onValueChange={field.onChange} value={field.value}>
                                                <FormControl>
                                                    <SelectTrigger className="h-11 bg-slate-50 border-slate-200 rounded-xl focus:bg-white transition-all">
                                                        <SelectValue placeholder="Seleccionar" />
                                                    </SelectTrigger>
                                                </FormControl>
                                                <SelectContent>
                                                    <SelectItem value="Masculino">Masculino</SelectItem>
                                                    <SelectItem value="Femenino">Femenino</SelectItem>
                                                    <SelectItem value="Otro">Otro</SelectItem>
                                                </SelectContent>
                                            </Select>
                                            <FormMessage className="text-[11px]" />
                                        </FormItem>
                                    )}
                                />
                                <FormField
                                    control={form.control}
                                    name="edad"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel className="text-slate-700 font-medium text-[13px]">
                                                Edad
                                            </FormLabel>
                                            <FormControl>
                                                <Input
                                                    readOnly
                                                    placeholder="Autocalculada"
                                                    className="h-11 bg-slate-100 border-slate-200 rounded-xl text-slate-500 cursor-not-allowed font-semibold"
                                                    value={field.value || ""}
                                                />
                                            </FormControl>
                                            <FormMessage className="text-[11px]" />
                                        </FormItem>
                                    )}
                                />
                            </div>

                            <FormField
                                control={form.control}
                                name="fecha_nacimiento"
                                render={({ field }) => {
                                    const currentYear = new Date().getFullYear();
                                    return (
                                        <FormItem className="flex flex-col">
                                            <FormLabel className="text-slate-700 font-medium text-[13px]">Fecha de Nacimiento *</FormLabel>
                                            <Popover>
                                                <PopoverTrigger asChild>
                                                    <FormControl>
                                                        <Button
                                                            variant="outline"
                                                            className={cn(
                                                                "w-full h-11 pl-3 text-left font-normal bg-slate-50 border-slate-200 rounded-xl hover:bg-slate-100 transition-all",
                                                                !field.value && "text-muted-foreground"
                                                            )}
                                                        >
                                                            {field.value ? (
                                                                format(field.value, "PPP", { locale: es })
                                                            ) : (
                                                                <span>Selecciona una fecha</span>
                                                            )}
                                                            <CalendarIcon className="ml-auto h-4 w-4 opacity-50 text-primary" />
                                                        </Button>
                                                    </FormControl>
                                                </PopoverTrigger>
                                                <PopoverContent className="w-auto p-3 bg-white" align="start">
                                                    <div className="flex justify-between mb-2 gap-2 pb-2 border-b border-slate-100">
                                                        <select
                                                            className="border-none bg-slate-100 rounded-md px-2 py-1 text-xs font-medium focus:ring-0"
                                                            value={displayDate.getMonth()}
                                                            onChange={(e) => setDisplayDate(new Date(displayDate.getFullYear(), parseInt(e.target.value)))}
                                                        >
                                                            {Array.from({ length: 12 }, (_, i) => (
                                                                <option key={i} value={i}>
                                                                    {format(new Date(0, i), "MMMM", { locale: es })}
                                                                </option>
                                                            ))}
                                                        </select>
                                                        <select
                                                            className="border-none bg-slate-100 rounded-md px-2 py-1 text-xs font-medium focus:ring-0"
                                                            value={displayDate.getFullYear()}
                                                            onChange={(e) => setDisplayDate(new Date(parseInt(e.target.value), displayDate.getMonth()))}
                                                        >
                                                            {Array.from({ length: 125 }, (_, i) => currentYear - i).map((y) => (
                                                                <option key={y} value={y}>{y}</option>
                                                            ))}
                                                        </select>
                                                    </div>
                                                    <Calendar
                                                        mode="single"
                                                        selected={field.value}
                                                        onSelect={(date) => {
                                                            field.onChange(date);
                                                            if (date) form.setValue("edad", calculateAge(date));
                                                        }}
                                                        month={displayDate}
                                                        onMonthChange={setDisplayDate}
                                                        disabled={(date) => date > new Date() || date < new Date("1900-01-01")}
                                                        initialFocus
                                                        locale={es}
                                                    />
                                                </PopoverContent>
                                            </Popover>
                                            <FormMessage className="text-[11px]" />
                                        </FormItem>
                                    );
                                }}
                            />
                        </div>

                        {/* 📍 SECCIÓN: DATOS DE CONTACTO */}
                        <div className="space-y-4 pt-2">
                            <div className="flex items-center gap-2 pb-2 border-b border-slate-100">
                                <Phone className="h-4 w-4 text-primary" />
                                <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider">Contacto y Ubicación</h3>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-2">
                                <FormField
                                    control={form.control}
                                    name="celular"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel className="text-slate-700 font-medium text-[13px]">Celular *</FormLabel>
                                            <FormControl>
                                                <div className="flex group focus-within:ring-2 focus-within:ring-primary/20 rounded-xl transition-all">
                                                    <div className="flex items-center justify-center px-4 border border-r-0 border-slate-200 bg-slate-100/50 text-slate-500 text-sm font-bold rounded-l-xl">
                                                        +51
                                                    </div>
