const formatDate = (dateStr: string): string => {
  if (!dateStr) return "No especificada";
  // Convertir YYYY-MM-DD a DD/MM/YYYY para mostrar
  if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
    const [year, month, day] = dateStr.split("-");
    return `${day}/${month}/${year}`;
  }
  return dateStr;
};

export default function Empleados() {
  const [searchTerm, setSearchTerm] = useState("");
  const [typeFilter, setTypeFilter] = useState("all");
  const [sortBy, setSortBy] = useState<"reciente" | "antiguo" | "apellido_az" | "apellido_za">("reciente");
  const [employees, setEmployees] = useState<EmployeeWithStats[]>([]);
  const [loading, setLoading] = useState(true);
  const show = useMinLoading(loading);
  const [refreshing, setRefreshing] = useState(false);
  const isInitialLoad = useRef(true);
  const [error, setError] = useState<string | null>(null);

  // Estados para diálogos
  const [isNewEmployeeDialogOpen, setIsNewEmployeeDialogOpen] = useState(false);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [selectedEmployee, setSelectedEmployee] = useState<EmployeeWithStats | null>(null);
  const [employeeToDelete, setEmployeeToDelete] = useState<string | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  // Vista
  const [viewMode, setViewMode] = useState<"table" | "grid">("table");

  // Paginación
  const [currentPage, setCurrentPage] = useState(1);
  const [employeesPerPage, setEmployeesPerPage] = useState(10);

  const fetchEmployees = async () => {
    try {
      if (isInitialLoad.current) { setLoading(true); } else { setRefreshing(true); }
      setError(null);
      const employeesData = await getAllEmployees();
      setEmployees(employeesData);
    } catch (err) {
      console.error("Error al obtener empleados:", err);
      setError("Error al cargar los empleados. Por favor, intenta de nuevo.");
    } finally {
      setLoading(false);
      setRefreshing(false);
      isInitialLoad.current = false;
    }
  };

  useEffect(() => {
    fetchEmployees();
  }, []);

  const handleEditEmployee = (employee: EmployeeWithStats) => {
    setSelectedEmployee(employee);
    setIsEditDialogOpen(true);
  };

  const handleDeleteEmployee = async () => {
    if (!employeeToDelete) return;

    try {
      setIsDeleting(true);
      await deleteEmployee(employeeToDelete);

      toast({
        title: "✅ Empleado eliminado",
        description: "El empleado ha sido eliminado permanentemente.",
      });

      fetchEmployees();
      setIsDeleteDialogOpen(false);
      setEmployeeToDelete(null);
    } catch (error) {
      console.error("Error al eliminar empleado:", error);
      toast({
        title: "❌ Error",
        description: "No se pudo eliminar el empleado.",
        variant: "destructive",
      });
    } finally {
      setIsDeleting(false);
    }
  };

  const formatSalary = (salary: number) => {
    return new Intl.NumberFormat("es-PE", {
      style: "currency",
      currency: "PEN",
    }).format(salary);
  };

  // Filtrado
  const filteredEmployees = employees.filter((emp) => {
    const searchLower = searchTerm.toLowerCase();
    const searchMatch =
      emp.fullName.toLowerCase().includes(searchLower) ||
      emp.dni_empleado.includes(searchTerm) ||
      emp.numero_telefonico.includes(searchTerm) ||
      emp.tipo_empleado_id.toLowerCase().includes(searchLower);

    const typeMatch = typeFilter === "all" || emp.tipo_empleado_id === typeFilter;

    return searchMatch && typeMatch;
  }).sort((a, b) => {
    switch (sortBy) {
      case "reciente": return new Date(b.fecha_contratacion || 0).getTime() - new Date(a.fecha_contratacion || 0).getTime();
      case "antiguo": return new Date(a.fecha_contratacion || 0).getTime() - new Date(b.fecha_contratacion || 0).getTime();
      case "apellido_az": return a.apellido_paterno.localeCompare(b.apellido_paterno, "es");
      case "apellido_za": return b.apellido_paterno.localeCompare(a.apellido_paterno, "es");
      default: return 0;
    }
  });

  const clearFilters = () => {
    setTypeFilter("all");
    setSearchTerm("");
    setSortBy("reciente");
    setCurrentPage(1);
  };

  const activeFiltersCount = [
    typeFilter !== "all",
    searchTerm !== "",
    sortBy !== "reciente",
  ].filter(Boolean).length;

  // Estadísticas
  const totalEmployees = employees.length;
  const activeEmployees = employees.filter((e) => e.activo).length;

  // Paginación
  const totalPages = Math.ceil(filteredEmployees.length / employeesPerPage);
  const indexOfLastEmployee = currentPage * employeesPerPage;
  const indexOfFirstEmployee = indexOfLastEmployee - employeesPerPage;
  const currentEmployees = filteredEmployees.slice(indexOfFirstEmployee, indexOfLastEmployee);

  const nextPage = () => {
    if (currentPage < totalPages) setCurrentPage(currentPage + 1);
  };

  const prevPage = () => {
    if (currentPage > 1) setCurrentPage(currentPage - 1);
  };

  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, typeFilter, sortBy]);

  if (show) return <PageLoader message="Cargando empleados..." />;

  return (
    <div className="flex flex-col gap-6">
      {/* Header */}
      <div className="flex justify-between items-center relative z-20 pb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-gray-100">Empleados</h1>
          <p className="text-gray-500 dark:text-gray-400 mt-1 flex items-center gap-2">
            Gestiona el personal de tu clínica dental
            {refreshing && <span className="animate-spin rounded-full h-3.5 w-3.5 border-b-2 border-primary flex-none" />}
          </p>
        </div>
        <div className="flex items-center gap-2">
          {/* View mode toggle */}
          <div className="flex items-center bg-muted rounded-lg p-0.5 gap-0.5">
            <button
              onClick={() => setViewMode("table")}
              title="Vista lista"
              className={`p-1.5 rounded-md transition-all duration-150 ${viewMode === "table"
                ? "bg-white text-foreground shadow-sm ring-1 ring-black/[0.06]"
                : "text-muted-foreground hover:text-foreground"
              }`}
            >
              <List className="h-4 w-4" />
            </button>
            <button
              onClick={() => setViewMode("grid")}
              title="Vista tarjetas"
              className={`p-1.5 rounded-md transition-all duration-150 ${viewMode === "grid"
                ? "bg-white text-foreground shadow-sm ring-1 ring-black/[0.06]"
                : "text-muted-foreground hover:text-foreground"
              }`}
            >
              <LayoutGrid className="h-4 w-4" />
            </button>
          </div>
          <Button
            className="bg-primary hover:bg-primary/90 text-primary-foreground shadow-sm"
            onClick={() => setIsNewEmployeeDialogOpen(true)}
          >
            <Plus className="mr-2 h-4 w-4" />
            Nuevo Empleado
          </Button>
        </div>
      </div>

      {/* ── Stats — compact horizontal bar ── */}
      <div className="flex items-stretch divide-x divide-border/70 bg-card rounded-xl border border-border/70 shadow-sm overflow-hidden">
        <div className="flex items-center gap-3 px-5 py-3.5 flex-1">
          <div className="p-1.5 rounded-lg bg-primary/10 flex-none">
            <Users className="h-3.5 w-3.5 text-primary" />
          </div>
          <div>
            <p className="text-xl font-bold text-foreground leading-none">
              {loading ? <span className="text-muted-foreground text-base">—</span> : totalEmployees}
            </p>
            <p className="text-[10px] text-muted-foreground mt-0.5 font-medium uppercase tracking-wide">
              Total
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3 px-5 py-3.5 flex-1">
          <div className="p-1.5 rounded-lg bg-emerald-50 flex-none">
            <UserPlus className="h-3.5 w-3.5 text-emerald-600" />
          </div>
          <div>
            <p className="text-xl font-bold text-foreground leading-none">
              {loading ? <span className="text-muted-foreground text-base">—</span> : activeEmployees}
            </p>
            <p className="text-[10px] text-muted-foreground mt-0.5 font-medium uppercase tracking-wide">
              Activos
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3 px-5 py-3.5 flex-1">
          <div className="p-1.5 rounded-lg bg-violet-50 flex-none">
            <Search className="h-3.5 w-3.5 text-violet-600" />
          </div>
          <div>
            <p className="text-xl font-bold text-foreground leading-none">
              {loading ? <span className="text-muted-foreground text-base">—</span> : filteredEmployees.length}
            </p>
            <p className="text-[10px] text-muted-foreground mt-0.5 font-medium uppercase tracking-wide">
              En búsqueda
            </p>
          </div>
        </div>
      </div>

      {/* ── Controls: search (half width) + filters right ── */}
      <div className="flex gap-3 items-center flex-wrap">
        {/* Search — fixed half the row */}
        <div className="relative w-1/2 flex-shrink-0">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
          <Input
            placeholder="Buscar por nombre, DNI, teléfono o cargo..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-9 pr-9 h-9 text-sm"
          />
          {searchTerm && (
            <button
              onClick={() => setSearchTerm("")}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
            >
              <X className="h-3.5 w-3.5" />
            </button>
          )}
        </div>

        {/* Type filter & Sort */}
        <div className="flex items-center gap-3">
          <Select value={typeFilter} onValueChange={setTypeFilter}>
            <SelectTrigger className="h-9 text-xs w-[160px]">
              <SelectValue placeholder="Tipo de empleado" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos los tipos</SelectItem>
              {EMPLOYEE_TYPES.map((type) => (
                <SelectItem key={type.value} value={type.value}>
                  {type.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          <div className="flex items-center gap-1.5">
            <SlidersHorizontal className="h-3.5 w-3.5 text-muted-foreground flex-none" />
            <Select value={sortBy} onValueChange={(v) => setSortBy(v as any)}>
              <SelectTrigger className="h-9 text-xs w-[148px]">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="reciente">Más reciente</SelectItem>
                <SelectItem value="antiguo">Más antiguo</SelectItem>
                <SelectItem value="apellido_az">Apellido A–Z</SelectItem>
                <SelectItem value="apellido_za">Apellido Z–A</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </div>

        {/* Clear */}
        {activeFiltersCount > 0 && (
          <button
            onClick={clearFilters}
            className="flex items-center gap-1.5 text-xs font-medium text-muted-foreground hover:text-foreground"
          >
            <X className="h-3.5 w-3.5" />
            Limpiar
          </button>
        )}
      </div>

      {/* Error State */}
      {error && (
        <Card className="border-destructive">
          <CardContent className="p-6">
            <div className="flex items-center gap-3">
              <AlertCircle className="h-5 w-5 text-destructive" />
              <div>
                <p className="font-semibold text-destructive">Error al cargar empleados</p>
                <p className="text-sm text-muted-foreground mt-1">{error}</p>
              </div>
              <Button
                variant="outline"
                size="sm"
                onClick={fetchEmployees}
                className="ml-auto"
              >
                Reintentar
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Empty State */}
      {!loading && !error && employees.length === 0 && (
        <Card>
          <CardContent className="p-12">
            <div className="flex flex-col items-center justify-center gap-4 text-center">
              <Users className="h-12 w-12 text-muted-foreground" />
              <div>
                <p className="font-semibold text-foreground">No hay empleados registrados</p>
                <p className="text-sm text-muted-foreground mt-1">
                  Comienza agregando tu primer empleado
                </p>
              </div>
              <Button onClick={() => setIsNewEmployeeDialogOpen(true)}>
                <Plus className="h-4 w-4 mr-2" />
                Nuevo Empleado
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* No Results State */}
      {!loading && !error && employees.length > 0 && filteredEmployees.length === 0 && (
        <Card>
          <CardContent className="p-12">
            <div className="flex flex-col items-center justify-center gap-4 text-center">
              <Search className="h-12 w-12 text-muted-foreground" />
              <div>
                <p className="font-semibold text-foreground">No se encontraron resultados</p>
                <p className="text-sm text-muted-foreground mt-1">
                  Intenta ajustar los filtros de búsqueda
                </p>
              </div>
              <Button variant="outline" onClick={clearFilters}>
                Limpiar filtros
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* ── Employee table view ── */}
      {!loading && !error && currentEmployees.length > 0 && viewMode === "table" && (
        <div className="bg-card border border-border/50 rounded-xl shadow-sm overflow-hidden">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader className="bg-muted/30">
                <TableRow>
                  <TableHead className="w-[200px] max-w-[200px]">Nombre</TableHead>
                  <TableHead className="w-[120px]">Cargo</TableHead>
                  <TableHead className="w-[100px]">DNI</TableHead>
                  <TableHead className="w-[120px]">Contacto</TableHead>
                  <TableHead className="w-[160px]">Dirección</TableHead>
                  <TableHead className="w-[110px]">F. Contrato</TableHead>
                  <TableHead className="w-[100px]">Sueldo</TableHead>
                  <TableHead className="w-[100px] text-right"></TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {currentEmployees.map((employee) => (
                  <TableRow key={employee.id} className="hover:bg-muted/20">
                    {/* Nombre */}
                    <TableCell className="w-[200px] max-w-[200px] overflow-hidden">
                      <div className="flex items-center gap-3 min-w-0">
                        <div className="flex-none w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center text-xs font-bold text-primary ring-1 ring-primary/20">
                          {employee.initials}
                        </div>
                        <div className="relative min-w-0 flex-1 overflow-hidden">
                          <span className="font-medium text-sm text-foreground whitespace-nowrap">
                            {employee.fullName}
                          </span>
                          <div className="absolute inset-y-0 right-0 w-10 bg-gradient-to-l from-card to-transparent pointer-events-none" />
                        </div>
                      </div>
                    </TableCell>

                    {/* Cargo */}
                    <TableCell>
                      <span className="text-sm text-muted-foreground">
                        {getRoleFromType(employee.tipo_empleado_id) || <span className="text-muted-foreground/40">—</span>}
                      </span>
                    </TableCell>

                    {/* DNI */}
                    <TableCell>
                      {employee.dni_empleado ? (
                        <span className="text-sm text-muted-foreground">{employee.dni_empleado}</span>
                      ) : (
                        <span className="text-sm text-muted-foreground/40">—</span>
                      )}
                    </TableCell>

                    {/* Contacto */}
                    <TableCell>
                      {employee.numero_telefonico ? (
                        <span className="text-sm text-muted-foreground">{employee.numero_telefonico}</span>
                      ) : (
                        <span className="text-sm text-muted-foreground/40">—</span>
                      )}
                    </TableCell>

                    {/* Dirección */}
                    <TableCell className="w-[160px] max-w-[160px] overflow-hidden">
                      <div className="relative overflow-hidden">
                        <span className="text-sm text-muted-foreground whitespace-nowrap">
                          {employee.direccion || <span className="text-muted-foreground/40">—</span>}
                        </span>
                        {employee.direccion && (
                          <div className="absolute inset-y-0 right-0 w-8 bg-gradient-to-l from-card to-transparent pointer-events-none" />
                        )}
                      </div>
                    </TableCell>

                    {/* Fecha de contrato */}
                    <TableCell>
                      {employee.fecha_contratacion ? (
                        <span className="text-sm text-muted-foreground">{formatDate(employee.fecha_contratacion)}</span>
                      ) : (
                        <span className="text-sm text-muted-foreground/40">—</span>
                      )}
                    </TableCell>

                    {/* Sueldo */}
                    <TableCell>
                      {employee.salario != null ? (
                        <span className="text-sm font-medium text-foreground">{formatSalary(employee.salario)}</span>
                      ) : (
                        <span className="text-sm text-muted-foreground/40">—</span>
                      )}
                    </TableCell>

                    <TableCell className="text-right">
                      <Link
                        to={`/empleados/${employee.id}`}
                        className="inline-flex items-center gap-1 text-xs font-bold text-emerald-600 hover:text-emerald-700 hover:gap-1.5 transition-all duration-150"
                      >
                        Ver perfil
                        <ChevronRight className="h-3.5 w-3.5 shrink-0" />
                      </Link>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        </div>
      )}

      {/* ── Employee grid view ── */}
      {!loading && !error && currentEmployees.length > 0 && viewMode === "grid" && (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          {currentEmployees.map((employee) => (
            <Card key={employee.id} className="overflow-hidden hover:shadow-lg transition-shadow">
              <CardContent className="p-6">
                <div className="flex items-start gap-4 mb-4">
                  <div className="w-16 h-16 rounded-full bg-primary/10 flex items-center justify-center flex-shrink-0">
                    <span className="text-xl font-bold text-primary">
                      {employee.initials}
                    </span>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className="font-semibold text-foreground text-lg truncate">
                      {employee.fullName}
                    </h3>
                    <Badge variant="secondary" className="mt-1">
                      {getRoleFromType(employee.tipo_empleado_id)}
                    </Badge>
                  </div>
                </div>

                <div className="space-y-3">
                  <div className="flex items-center gap-2 text-sm">
                    <IdCard className="h-4 w-4 text-muted-foreground" />
                    <span className="text-muted-foreground">DNI: {employee.dni_empleado}</span>
                  </div>
                  <div className="flex items-center gap-2 text-sm">
                    <Phone className="h-4 w-4 text-muted-foreground" />
                    <span className="text-muted-foreground">{employee.numero_telefonico}</span>
                  </div>
                  {employee.direccion && (
                    <div className="flex items-center gap-2 text-sm">
                      <MapPin className="h-4 w-4 text-muted-foreground" />
                      <span className="text-muted-foreground truncate">{employee.direccion}</span>
                    </div>
                  )}
                  <div className="flex items-center gap-2 text-sm">
                    <Calendar className="h-4 w-4 text-muted-foreground" />
                    <span className="text-muted-foreground">
                      Contratado: {formatDate(employee.fecha_contratacion)}
                    </span>
                  </div>
                </div>

                <div className="mt-4 pt-4 border-t border-border flex justify-between items-center">
                  <div className="flex flex-col">
                    <span
                      className={`text-xs font-medium flex items-center gap-1 ${employee.activo ? "text-success" : "text-muted-foreground"}`}
                    >
                      <span className={`w-2 h-2 rounded-full ${employee.activo ? "bg-success" : "bg-muted-foreground"}`} />
                      {employee.activo ? "Activo" : "Inactivo"}
                    </span>
                    <span className="text-sm font-semibold text-foreground mt-1">
                      {formatSalary(employee.salario)}
                    </span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Link
                      to={`/empleados/${employee.id}`}
                      className="inline-flex items-center gap-1 text-xs font-bold text-emerald-600 hover:text-emerald-700 hover:gap-1.5 transition-all duration-150"
                    >
                      Ver perfil
                      <ChevronRight className="h-3.5 w-3.5 shrink-0" />
                    </Link>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Paginación */}
      {!loading && !error && filteredEmployees.length > 0 && (
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
          <p className="text-xs text-muted-foreground">
            Mostrando{" "}
            <span className="font-semibold text-foreground">
              {indexOfFirstEmployee + 1}–{Math.min(indexOfLastEmployee, filteredEmployees.length)}
            </span>{" "}
            de{" "}
            <span className="font-semibold text-foreground">{filteredEmployees.length}</span> empleados
          </p>

          {totalPages > 1 && (
            <div className="flex items-center gap-1">
              <button
                onClick={prevPage}
                disabled={currentPage === 1}
                className="p-1.5 rounded-lg hover:bg-muted disabled:opacity-40 disabled:cursor-not-allowed transition-colors text-muted-foreground hover:text-foreground"
              >
                <ChevronLeft className="h-4 w-4" />
              </button>
              <div className="flex gap-1">
                {Array.from({ length: Math.min(totalPages, 5) }, (_, i) => {
                  let pageNumber: number;
                  if (totalPages <= 5) {
                    pageNumber = i + 1;
                  } else if (currentPage <= 3) {
                    pageNumber = i + 1;
                  } else if (currentPage >= totalPages - 2) {
                    pageNumber = totalPages - 4 + i;
                  } else {
                    pageNumber = currentPage - 2 + i;
                  }
                  const isActive = currentPage === pageNumber;
                  return (
                    <button
                      key={pageNumber}
                      onClick={() => setCurrentPage(pageNumber)}
                      className={`w-8 h-8 rounded-lg text-xs font-semibold transition-all ${isActive
                        ? "bg-primary text-primary-foreground shadow-sm"
                        : "text-muted-foreground hover:bg-muted hover:text-foreground"
                      }`}
                    >
                      {pageNumber}
                    </button>
                  );
                })}
              </div>
              <button
                onClick={nextPage}
                disabled={currentPage === totalPages}
                className="p-1.5 rounded-lg hover:bg-muted disabled:opacity-40 disabled:cursor-not-allowed transition-colors text-muted-foreground hover:text-foreground"
              >
                <ChevronRight className="h-4 w-4" />
              </button>
            </div>
          )}

          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <span>Por página:</span>
            <Select
              value={employeesPerPage.toString()}
              onValueChange={(value) => {
                setEmployeesPerPage(Number(value));
                setCurrentPage(1);
              }}
            >
              <SelectTrigger className="h-7 w-16 text-xs">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="5">5</SelectItem>
                <SelectItem value="10">10</SelectItem>
                <SelectItem value="20">20</SelectItem>
                <SelectItem value="50">50</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </div>
      )}

      {/* Diálogos */}
      <EmployeeDialog
        open={isNewEmployeeDialogOpen}
        onOpenChange={setIsNewEmployeeDialogOpen}
        onSuccess={fetchEmployees}
      />

      <EmployeeEditDialog
        open={isEditDialogOpen}
        onOpenChange={setIsEditDialogOpen}
        employee={selectedEmployee}
        onSuccess={fetchEmployees}
      />

      <ConfirmationDialog
        open={isDeleteDialogOpen}
        onOpenChange={(open) => {
          setIsDeleteDialogOpen(open);
          if (!open) setEmployeeToDelete(null);
        }}
        onConfirm={handleDeleteEmployee}
        title="¿Eliminar empleado?"
        description="Esta acción eliminará permanentemente el empleado del sistema. Esta acción no se puede deshacer."
        confirmText="Eliminar"
        cancelText="Cancelar"
        variant="destructive"
        loading={isDeleting}
      />
    </div>
  );
}

import { useState, useEffect, useMemo, useRef } from "react";
import { PageLoader } from "@/components/ui/PageLoader";
import { useMinLoading } from "@/hooks/useMinLoading";
import { useActivityLog } from "@/hooks/useActivityLog";
import { Plus, Package, AlertTriangle, AlertOctagon, Search, Edit, Trash2, ArrowUpDown, RefreshCw, X, Users } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { InventoryItemType, RotationInventoryItem } from "@/types/inventory";
import { getInventoryItems, deleteInventoryItem } from "@/services/inventoryService";
import { InventoryDialog } from "@/components/inventory/InventoryDialog";
import { StockAdjustmentDialog } from "@/components/inventory/StockAdjustmentDialog";
import { format, differenceInDays, parseISO } from "date-fns";
import { es } from "date-fns/locale";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { cn } from "@/lib/utils";

export default function Inventario() {
    const [items, setItems] = useState<InventoryItemType[]>([]);
    const [loading, setLoading] = useState(true);
    const show = useMinLoading(loading);
    const [refreshing, setRefreshing] = useState(false);
    const isInitialLoad = useRef(true);

    // Filters
    const [searchTerm, setSearchTerm] = useState("");
    const [categoryFilter, setCategoryFilter] = useState<"Todos" | "Estático" | "Rotación">("Todos");
    const [sortBy, setSortBy] = useState<"reciente" | "antiguo" | "nombre_az" | "nombre_za">("reciente");

    // Modals state
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [selectedItem, setSelectedItem] = useState<InventoryItemType | null>(null);
    const [isAdjustmentDialogOpen, setIsAdjustmentDialogOpen] = useState(false);
    const [adjustmentItem, setAdjustmentItem] = useState<RotationInventoryItem | null>(null);

    // Delete state
    const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
    const [itemToDelete, setItemToDelete] = useState<string | null>(null);
    const [itemToDeleteName, setItemToDeleteName] = useState<string>("");
    const { log } = useActivityLog();

    const { toast } = useToast();

    const loadItems = async () => {
        try {
            if (isInitialLoad.current) { setLoading(true); } else { setRefreshing(true); }
            const data = await getInventoryItems();
            setItems(data);
        } catch (error) {
            console.error("Error loading inventory:", error);
            toast({
                variant: "destructive",
                title: "Error",
                description: "No se pudieron cargar los datos del inventario.",
            });
        } finally {
            setLoading(false);
            setRefreshing(false);
            isInitialLoad.current = false;
        }
    };

    useEffect(() => {
        loadItems();
    }, []);

    const filteredAndSortedItems = useMemo(() => {
        let result = [...items];

        if (searchTerm) {
            const term = searchTerm.toLowerCase();
            result = result.filter(item =>
                item.nombre.toLowerCase().includes(term) ||
                (item.descripcion?.toLowerCase() || "").includes(term) ||
                (item.categoria === "Estático" && (
                    item.marca.toLowerCase().includes(term) ||
                    item.modelo.toLowerCase().includes(term) ||
                    item.numero_serie.toLowerCase().includes(term)
                ))
            );
        }

        if (categoryFilter !== "Todos") {
            result = result.filter(item => item.categoria === categoryFilter);
        }

        return result.sort((a, b) => {
            const dateA = a.fecha_registro ? parseISO(a.fecha_registro).getTime() : 0;
            const dateB = b.fecha_registro ? parseISO(b.fecha_registro).getTime() : 0;

            switch (sortBy) {
                case "reciente": return dateB - dateA;
                case "antiguo": return dateA - dateB;
                case "nombre_az": return a.nombre.localeCompare(b.nombre);
                case "nombre_za": return b.nombre.localeCompare(a.nombre);
                default: return 0;
            }
        });
    }, [items, searchTerm, categoryFilter, sortBy]);

    const activeFiltersCount = (searchTerm ? 1 : 0) + (categoryFilter !== "Todos" ? 1 : 0);

    const clearFilters = () => {
        setSearchTerm("");
        setCategoryFilter("Todos");
        setSortBy("reciente");
    };

    const handleDelete = async () => {
        if (!itemToDelete) return;
        try {
            await deleteInventoryItem(itemToDelete);
            toast({
                title: "Producto eliminado",
                description: "El producto ha sido removido del inventario.",
            });
            log({ modulo: "Inventario", accion: "eliminó", entidad: "producto", entidad_id: itemToDelete, entidad_nombre: itemToDeleteName });
            loadItems();
        } catch (error) {
            toast({
                variant: "destructive",
                title: "Error",
                description: "No se pudo eliminar el producto.",
            });
        } finally {
            setIsDeleteDialogOpen(false);
            setItemToDelete(null);
        }
    };

    // Dashboard calculations
    const totalActivos = items.length;

    const proximosAgotar = items.filter(
        (item) => item.categoria === "Rotación" && item.stock_actual <= item.stock_minimo
    ).length;

    const today = new Date();
    const porVencer = items.filter((item) => {
        if (item.categoria !== "Rotación" || !item.fecha_vencimiento) return false;
        const expDate = new Date(item.fecha_vencimiento + "T00:00:00");
        const diffDays = differenceInDays(expDate, today);
        return diffDays <= 60 && diffDays >= -365; // Expiring in <= 60 days (or recently expired)
    }).length;

    const getStatusBadge = (item: InventoryItemType) => {
        if (item.categoria === "Estático") {
            return <Badge variant="outline" className="bg-blue-50 text-blue-700 border-blue-200">Activo Fijo</Badge>;
        }

        const { stock_actual, stock_minimo, fecha_vencimiento } = item;

        // Check expiration first
        if (fecha_vencimiento) {
            const expDate = new Date(fecha_vencimiento + "T00:00:00");
            const diffDays = differenceInDays(expDate, today);
            if (diffDays <= 0) {
                return <Badge variant="destructive" className="bg-red-500">Vencido</Badge>;
            }
            if (diffDays <= 60) {
                return <Badge variant="outline" className="bg-orange-100 text-orange-800 border-orange-300">Por vencer</Badge>;
            }
        }

        // Check stock
        if (stock_actual <= 0) {
            return <Badge variant="destructive" className="bg-red-500">Sin Stock</Badge>;
        }
        if (stock_actual <= stock_minimo) {
            return <Badge variant="outline" className="bg-yellow-100 text-yellow-800 border-yellow-300">Stock Bajo</Badge>;
        }

        return <Badge variant="outline" className="bg-emerald-100 text-emerald-700 border-emerald-200">Stock Óptimo</Badge>;
    };

    if (show) return <PageLoader message="Cargando inventario..." />;

    return (
        <div className="flex flex-col gap-6">
            <div className="flex justify-between items-center relative z-20 pb-2">
                <div>
                    <h1 className="text-3xl font-bold text-gray-900 dark:text-gray-100">
                        Inventario
                    </h1>
                    <p className="text-gray-500 dark:text-gray-400 mt-1 flex items-center gap-2">
                        Gestión de activos fijos y control de productos de rotación clínica
                        {refreshing && <span className="animate-spin rounded-full h-3.5 w-3.5 border-b-2 border-primary flex-none" />}
                    </p>
                </div>
                <Button
                    className="bg-primary hover:bg-primary/90 text-primary-foreground shadow-sm"
                    onClick={() => {
                        setSelectedItem(null);
                        setIsDialogOpen(true);
                    }}
                >
                    <Plus className="mr-2 h-4 w-4" /> Registrar Producto
                </Button>
            </div>

            {/* ── Stats — compact horizontal bar ── */}
            <div className="flex items-stretch divide-x divide-border/70 bg-card rounded-xl border border-border/70 shadow-sm overflow-hidden">
                <div className="flex items-center gap-3 px-5 py-3.5 flex-1">
                    <div className="p-1.5 rounded-lg bg-primary/10 flex-none">
                        <Package className="h-3.5 w-3.5 text-primary" />
                    </div>
                    <div>
                        <p className="text-xl font-bold text-foreground leading-none">
                            {loading ? <span className="text-muted-foreground text-base">—</span> : totalActivos}
                        </p>
                        <p className="text-[10px] text-muted-foreground mt-0.5 font-medium uppercase tracking-wide">
                            Total
                        </p>
                    </div>
                </div>

                <div className="flex items-center gap-3 px-5 py-3.5 flex-1">
                    <div className="p-1.5 rounded-lg bg-amber-50 flex-none">
                        <AlertTriangle className={cn("h-3.5 w-3.5", proximosAgotar > 0 ? "text-amber-600" : "text-amber-400")} />
                    </div>
                    <div>
                        <p className="text-xl font-bold text-foreground leading-none">
                            {loading ? <span className="text-muted-foreground text-base">—</span> : proximosAgotar}
                        </p>
                        <p className="text-[10px] text-muted-foreground mt-0.5 font-medium uppercase tracking-wide">
                            Por Agotar
                        </p>
                    </div>
                </div>

                <div className="flex items-center gap-3 px-5 py-3.5 flex-1">
                    <div className="p-1.5 rounded-lg bg-rose-50 flex-none">
                        <AlertOctagon className={cn("h-3.5 w-3.5", porVencer > 0 ? "text-rose-600" : "text-rose-400")} />
                    </div>
                    <div>
                        <p className="text-xl font-bold text-foreground leading-none">
                            {loading ? <span className="text-muted-foreground text-base">—</span> : porVencer}
                        </p>
                        <p className="text-[10px] text-muted-foreground mt-0.5 font-medium uppercase tracking-wide">
                            Por Vencer
                        </p>
                    </div>
                </div>
            </div>

            {/* FILTERS AND ACTIONS */}
            <div className="flex flex-wrap items-center gap-3">
                {/* Search — fixed half the row */}
                <div className="relative w-1/2 flex-shrink-0">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                        placeholder="Buscar por nombre, descripción, marca o serie..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="pl-9 pr-9 h-9 text-sm"
                    />
                    {searchTerm && (
                        <button
                            onClick={() => setSearchTerm("")}
                            className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                        >
                            <X className="h-3.5 w-3.5" />
                        </button>
                    )}
                </div>

                {/* Category Pills */}
                <div className="flex items-center bg-muted rounded-lg p-0.5 gap-0.5">
                    {(["Todos", "Estático", "Rotación"] as const).map((cat) => (
                        <button
                            key={cat}
                            onClick={() => setCategoryFilter(cat)}
                            className={`px-3 py-1.5 text-xs font-semibold rounded-md transition-all duration-150 ${categoryFilter === cat
                                ? "bg-white text-foreground shadow-sm ring-1 ring-black/[0.06]"
                                : "text-muted-foreground hover:text-foreground"
                                }`}
                        >
                            {cat === "Todos" ? "Todos" : cat === "Estático" ? "Activos Fijos" : "Consumibles"}
                        </button>
                    ))}
                </div>

                {/* Sort */}
                <div className="flex items-center gap-1.5">
                    <ArrowUpDown className="h-3.5 w-3.5 text-muted-foreground flex-none" />
                    <Select value={sortBy} onValueChange={(v: any) => setSortBy(v)}>
                        <SelectTrigger className="h-9 text-xs w-[148px]">
                            <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="reciente">Más reciente</SelectItem>
                            <SelectItem value="antiguo">Más antiguo</SelectItem>
                            <SelectItem value="nombre_az">Nombre A–Z</SelectItem>
                            <SelectItem value="nombre_za">Nombre Z–A</SelectItem>
                        </SelectContent>
                    </Select>
                </div>

                {/* Clear */}
                {activeFiltersCount > 0 && (
                    <button
                        onClick={clearFilters}
                        className="flex items-center gap-1 px-2.5 py-1.5 text-xs font-semibold rounded-lg bg-muted text-muted-foreground hover:text-foreground transition-colors"
                    >
                        <X className="h-3 w-3" />
                        Limpiar
                    </button>
                )}
            </div>

            {/* TABLE CONTAINER */}
            <div className="bg-card border border-border/50 rounded-xl shadow-sm overflow-hidden">

                <div className="overflow-x-auto">
                    <Table>
                        <TableHeader className="bg-muted/30">
                            <TableRow>
                                <TableHead>Producto</TableHead>
                                <TableHead>Categoría / Detalle</TableHead>
                                <TableHead>Stock / Lote</TableHead>
                                <TableHead>Estado</TableHead>
                                <TableHead className="text-right">Acciones</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {filteredAndSortedItems.length === 0 ? (
                                <TableRow>
                                    <TableCell colSpan={5} className="text-center h-48">
                                        <div className="flex flex-col items-center justify-center h-full gap-3">
                                            <div className="p-3 rounded-full bg-muted">
                                                <Search className="h-6 w-6 text-muted-foreground" />
                                            </div>
                                            <div>
                                                <p className="font-medium text-foreground">Sin resultados</p>
                                                <p className="text-sm text-muted-foreground">Intenta ajustar los filtros de búsqueda</p>
                                            </div>
                                            {activeFiltersCount > 0 && (
                                                <Button variant="outline" size="sm" onClick={clearFilters}>
                                                    Limpiar filtros
                                                </Button>
                                            )}
                                        </div>
                                    </TableCell>
                                </TableRow>
                            ) : (
                                filteredAndSortedItems.map((item) => (
                                    <TableRow key={item.id} className="hover:bg-muted/20">
                                        <TableCell className="font-medium">
                                            {item.nombre}
                                            {item.descripcion && (
                                                <p className="text-xs text-muted-foreground mt-0.5 truncate max-w-[200px]">
                                                    {item.descripcion}
                                                </p>
                                            )}
                                        </TableCell>
                                        <TableCell>
                                            {item.categoria === "Estático" ? (
                                                <div className="text-sm">
                                                    <span className="font-medium">{item.marca}</span>
                                                    <span className="text-muted-foreground block text-xs">Mod: {item.modelo}</span>
                                                    <span className="text-muted-foreground block text-xs">SN: {item.numero_serie}</span>
                                                </div>
                                            ) : (
                                                <div className="text-sm text-muted-foreground">
                                                    Consumible de Rotación
                                                </div>
                                            )}
                                        </TableCell>
                                        <TableCell>
                                            {item.categoria === "Rotación" ? (
                                                <div className="text-sm">
                                                    <span className="font-semibold">{item.stock_actual} unid.</span>
                                                    <span className="text-muted-foreground block text-xs">(Mín: {item.stock_minimo})</span>
                                                    {item.lote && <span className="text-muted-foreground block text-xs">Lote: {item.lote}</span>}
                                                </div>
                                            ) : (
                                                <span className="text-muted-foreground text-sm">-</span>
                                            )}
                                        </TableCell>
                                        <TableCell>
                                            {getStatusBadge(item)}
                                        </TableCell>
                                        <TableCell className="text-right">
                                            <div className="flex justify-end gap-2">
                                                {item.categoria === "Rotación" && (
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        onClick={() => {
                                                            setAdjustmentItem(item as RotationInventoryItem);
                                                            setIsAdjustmentDialogOpen(true);
                                                        }}
                                                        title="Ajuste Rápido de Stock"
                                                        className="h-8 w-8 text-emerald-600 hover:text-emerald-700 hover:bg-emerald-50"
                                                    >
                                                        <RefreshCw className="h-4 w-4" />
                                                    </Button>
                                                )}
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    onClick={() => {
                                                        setSelectedItem(item);
                                                        setIsDialogOpen(true);
                                                    }}
                                                    title="Editar"
                                                    className="h-8 w-8 text-primary hover:text-primary/80 hover:bg-primary/10"
                                                >
                                                    <Edit className="h-4 w-4" />
                                                </Button>
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    onClick={() => {
                                                        setItemToDelete(item.id!);
                                                        setItemToDeleteName(item.nombre);
                                                        setIsDeleteDialogOpen(true);
                                                    }}
                                                    title="Eliminar"
                                                    className="h-8 w-8 text-destructive hover:text-destructive/80 hover:bg-destructive/10"
                                                >
                                                    <Trash2 className="h-4 w-4" />
                                                </Button>
                                            </div>
                                        </TableCell>
                                    </TableRow>
                                ))
                            )}
                        </TableBody>
                    </Table>
                </div>
            </div>

            {/* MODALS */}
            <InventoryDialog
                open={isDialogOpen}
                onOpenChange={setIsDialogOpen}
                item={selectedItem}
                onSuccess={loadItems}
            />

            <StockAdjustmentDialog
                open={isAdjustmentDialogOpen}
                onOpenChange={setIsAdjustmentDialogOpen}
                item={adjustmentItem}
                onSuccess={loadItems}
            />

            <AlertDialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>¿Estás seguro de eliminar este producto?</AlertDialogTitle>
                        <AlertDialogDescription>
                            Esta acción no se puede deshacer. Se eliminará permanentemente el producto del inventario de la clínica.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>Cancelar</AlertDialogCancel>
                        <AlertDialogAction onClick={handleDelete} className="bg-destructive hover:bg-destructive/90 text-white">
                            Eliminar Producto
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>

        </div>
    );
}

import { useState, useEffect, useMemo, useRef } from "react";
import { Link } from "react-router-dom";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { PageLoader } from "@/components/ui/PageLoader";
import { useMinLoading } from "@/hooks/useMinLoading";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import {
  Plus,
  Search,
  Mail,
  Phone,
  FileText,
  AlertCircle,
  AlertTriangle,
  Users,
  UserPlus,
  SlidersHorizontal,
  X,
  LayoutGrid,
  List,
} from "lucide-react";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import PatientDialog from "@/components/patients/PatientDialog";
import { collection, getDocs, query, orderBy } from "firebase/firestore";
import { db } from "@/lib/firebase";
import { Patient } from "@/types/appointment";

interface PatientWithStats extends Patient {
  fullName: string;
  age: number | null;
  initials: string;
}

type SortBy = "reciente" | "antiguo" | "apellido_az" | "apellido_za";

const DATE_FILTER_OPTIONS = [
  { label: "Todos", value: "all" },
  { label: "Semana", value: "lastWeek" },
  { label: "Mes", value: "lastMonth" },
  { label: "3 meses", value: "last3Months" },
];

const AVATAR_PALETTES = [
  { bg: "bg-blue-100", text: "text-blue-700", ring: "ring-blue-200" },
  { bg: "bg-teal-100", text: "text-teal-700", ring: "ring-teal-200" },
  { bg: "bg-violet-100", text: "text-violet-700", ring: "ring-violet-200" },
  { bg: "bg-amber-100", text: "text-amber-700", ring: "ring-amber-200" },
  { bg: "bg-rose-100", text: "text-rose-700", ring: "ring-rose-200" },
  { bg: "bg-emerald-100", text: "text-emerald-700", ring: "ring-emerald-200" },
  { bg: "bg-sky-100", text: "text-sky-700", ring: "ring-sky-200" },
  { bg: "bg-orange-100", text: "text-orange-700", ring: "ring-orange-200" },
];

function getAvatarPalette(name: string) {
  // Always returning primary theme palette
  return { bg: "bg-primary/10", text: "text-primary", ring: "ring-primary/20" };
}

const PROFILE_FIELDS: (keyof PatientWithStats)[] = [
  "nombre",
  "apellido_paterno",
  "apellido_materno",
  "dni_cliente",
  "celular",
  "email",
  "fecha_nacimiento",
  "sexo",
  "estado_civil",
  "direccion",
  "distrito_direccion",
  "ocupacion",
];

function calcProfileCompletion(patient: PatientWithStats): number {
  const filled = PROFILE_FIELDS.filter((field) => {
    const val = patient[field];
    if (val === null || val === undefined) return false;
    if (typeof val === "string") return val.trim() !== "";
    return true;
  }).length;
  return Math.round((filled / PROFILE_FIELDS.length) * 100);
}

export default function Pacientes() {
  const [searchTerm, setSearchTerm] = useState("");
  const [dateFilter, setDateFilter] = useState("all");
  const [sortBy, setSortBy] = useState<SortBy>("reciente");
  const [isNewPatientDialogOpen, setIsNewPatientDialogOpen] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [patientsPerPage, setPatientsPerPage] = useState(12);

  const [patients, setPatients] = useState<PatientWithStats[]>([]);
  const [loading, setLoading] = useState(true);
  const show = useMinLoading(loading);
  const [refreshing, setRefreshing] = useState(false);
  const isInitialLoad = useRef(true);
  const [error, setError] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<"grid" | "table">("table");

  const calculateAge = (fechaNacimiento: Date | undefined): number | null => {
    if (!fechaNacimiento) return null;
    const today = new Date();
    const birthDate =
      fechaNacimiento instanceof Date ? fechaNacimiento : new Date(fechaNacimiento);
    let age = today.getFullYear() - birthDate.getFullYear();
    const monthDiff = today.getMonth() - birthDate.getMonth();
    if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) age--;
    return age;
  };

  const fetchPatients = async () => {
    try {
      if (isInitialLoad.current) { setLoading(true); } else { setRefreshing(true); }
      setError(null);
      const patientsRef = collection(db, "pacientes");
      const q = query(patientsRef, orderBy("fecha_creacion", "desc"));
      const querySnapshot = await getDocs(q);

      const patientsData: PatientWithStats[] = querySnapshot.docs.map((doc) => {
        const data = doc.data();
        const fechaNacimiento = data.fecha_nacimiento?.toDate();
        const fechaCreacion = data.fecha_creacion?.toDate() || new Date();
        const fullName =
          `${data.nombre} ${data.apellido_paterno} ${data.apellido_materno}`.trim();
        const age = data.edad || calculateAge(fechaNacimiento);
        const initials =
          `${data.nombre?.[0] || ""}${data.apellido_paterno?.[0] || ""}`.toUpperCase();

        return {
          id: doc.id,
          nombre: data.nombre || "",
          apellido_paterno: data.apellido_paterno || "",
          apellido_materno: data.apellido_materno || "",
          dni_cliente: data.dni_cliente || "",
          celular: data.celular || "",
          telefono_fijo: data.telefono_fijo || "",
          email: data.email || "",
          fecha_nacimiento: fechaNacimiento,
          edad: age,
          sexo: data.sexo || "",
          estado_civil: data.estado_civil || "",
          direccion: data.direccion || "",
          distrito_direccion: data.distrito_direccion || "",
          lugar_procedencia: data.lugar_procedencia || "",
          ocupacion: data.ocupacion || "",
          fecha_creacion: fechaCreacion,
          fullName,
          age,
          initials,
        };
      });

      setPatients(patientsData);
    } catch (err) {
      console.error("Error al obtener pacientes:", err);
      setError("Error al cargar los pacientes. Por favor, intenta de nuevo.");
    } finally {
      setLoading(false);
      setRefreshing(false);
      isInitialLoad.current = false;
    }
  };

  useEffect(() => { fetchPatients(); }, []);
  useEffect(() => { if (!isNewPatientDialogOpen) fetchPatients(); }, [isNewPatientDialogOpen]);
  useEffect(() => { setCurrentPage(1); }, [searchTerm, dateFilter, sortBy]);

  const totalPacientes = patients.length;
  const pacientesUltimoMes = patients.filter((p) => {
    const diffDays = Math.floor(
      (new Date().getTime() - p.fecha_creacion.getTime()) / 86400000
    );
    return diffDays <= 30;
  }).length;

  const filteredPatients = useMemo(() => {
    const filtered = patients.filter((patient) => {
      const searchMatch =
        patient.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        patient.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
        patient.celular.includes(searchTerm) ||
        patient.dni_cliente.includes(searchTerm);

      const dateMatch = (() => {
        if (dateFilter === "all") return true;
        const diffDays = Math.floor(
          (new Date().getTime() - patient.fecha_creacion.getTime()) / 86400000
        );
        switch (dateFilter) {
          case "lastWeek": return diffDays <= 7;
          case "lastMonth": return diffDays <= 30;
          case "last3Months": return diffDays <= 90;
          default: return true;
        }
      })();

      return searchMatch && dateMatch;
    });

    return [...filtered].sort((a, b) => {
      switch (sortBy) {
        case "reciente": return b.fecha_creacion.getTime() - a.fecha_creacion.getTime();
        case "antiguo": return a.fecha_creacion.getTime() - b.fecha_creacion.getTime();
        case "apellido_az": return a.apellido_paterno.localeCompare(b.apellido_paterno, "es");
        case "apellido_za": return b.apellido_paterno.localeCompare(a.apellido_paterno, "es");
        default: return 0;
      }
    });
  }, [patients, searchTerm, dateFilter, sortBy]);

  const clearFilters = () => {
    setDateFilter("all");
    setSearchTerm("");
    setSortBy("reciente");
    setCurrentPage(1);
  };
  const activeFiltersCount = [
    dateFilter !== "all",
    searchTerm !== "",
    sortBy !== "reciente",
  ].filter(Boolean).length;

  const totalPatients = filteredPatients.length;
  const totalPages = Math.ceil(totalPatients / patientsPerPage);
  const indexOfLastPatient = currentPage * patientsPerPage;
  const indexOfFirstPatient = indexOfLastPatient - patientsPerPage;
  const currentPatients = filteredPatients.slice(indexOfFirstPatient, indexOfLastPatient);

  const paginate = (pageNumber: number) => setCurrentPage(pageNumber);
  const nextPage = () => { if (currentPage < totalPages) setCurrentPage(currentPage + 1); };
  const prevPage = () => { if (currentPage > 1) setCurrentPage(currentPage - 1); };

  if (show) return <PageLoader message="Cargando pacientes..." />;

  return (
    <div className="flex flex-col gap-6">
      {/* ── Header ── */}
      <div className="flex justify-between items-center relative z-20 pb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-gray-100">Pacientes</h1>
          <p className="text-gray-500 dark:text-gray-400 mt-1 flex items-center gap-2">
            Gestiona las fichas médicas del consultorio
            {refreshing && <span className="animate-spin rounded-full h-3.5 w-3.5 border-b-2 border-primary flex-none" />}
          </p>
        </div>
        <div className="flex items-center gap-2">
          {/* View mode toggle */}
          <div className="flex items-center bg-muted rounded-lg p-0.5 gap-0.5">
            <button
              onClick={() => setViewMode("table")}
              title="Vista lista"
              className={`p-1.5 rounded-md transition-all duration-150 ${viewMode === "table"
                ? "bg-white text-foreground shadow-sm ring-1 ring-black/[0.06]"
                : "text-muted-foreground hover:text-foreground"
                }`}
            >
              <List className="h-4 w-4" />
            </button>
            <button
              onClick={() => setViewMode("grid")}
              title="Vista tarjetas"
              className={`p-1.5 rounded-md transition-all duration-150 ${viewMode === "grid"
                ? "bg-white text-foreground shadow-sm ring-1 ring-black/[0.06]"
                : "text-muted-foreground hover:text-foreground"
                }`}
            >
              <LayoutGrid className="h-4 w-4" />
            </button>
          </div>
          <Button
            className="bg-primary hover:bg-primary/90 text-primary-foreground shadow-sm"
            onClick={() => setIsNewPatientDialogOpen(true)}
          >
            <Plus className="mr-2 h-4 w-4" />
            Nuevo Paciente
          </Button>
        </div>
      </div>

      {/* ── Stats — compact horizontal bar ── */}
      <div className="flex items-stretch divide-x divide-border/70 bg-card rounded-xl border border-border/70 shadow-sm overflow-hidden">
        <div className="flex items-center gap-3 px-5 py-3.5 flex-1">
          <div className="p-1.5 rounded-lg bg-primary/10 flex-none">
            <Users className="h-3.5 w-3.5 text-primary" />
          </div>
          <div>
            <p className="text-xl font-bold text-foreground leading-none">
              {loading ? <span className="text-muted-foreground text-base">—</span> : totalPacientes}
            </p>
            <p className="text-[10px] text-muted-foreground mt-0.5 font-medium uppercase tracking-wide">
              Total
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3 px-5 py-3.5 flex-1">
          <div className="p-1.5 rounded-lg bg-emerald-50 flex-none">
            <UserPlus className="h-3.5 w-3.5 text-emerald-600" />
          </div>
          <div>
            <p className="text-xl font-bold text-foreground leading-none">
              {loading ? <span className="text-muted-foreground text-base">—</span> : pacientesUltimoMes}
            </p>
            <p className="text-[10px] text-muted-foreground mt-0.5 font-medium uppercase tracking-wide">
              Nuevos este mes
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3 px-5 py-3.5 flex-1">
          <div className="p-1.5 rounded-lg bg-violet-50 flex-none">
            <Search className="h-3.5 w-3.5 text-violet-600" />
          </div>
          <div>
            <p className="text-xl font-bold text-foreground leading-none">
              {loading ? <span className="text-muted-foreground text-base">—</span> : filteredPatients.length}
            </p>
            <p className="text-[10px] text-muted-foreground mt-0.5 font-medium uppercase tracking-wide">
              En búsqueda
            </p>
          </div>
        </div>
      </div>

      {/* ── Controls: search (half width) + filters right ── */}
      <div className="flex gap-3 items-center flex-wrap">
        {/* Search — fixed half the row */}
        <div className="relative w-1/2 flex-shrink-0">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
          <Input
            placeholder="Buscar por nombre, DNI, email o teléfono..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-9 pr-9 h-9 text-sm"
          />
          {searchTerm && (
            <button
              onClick={() => setSearchTerm("")}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
            >
              <X className="h-3.5 w-3.5" />
            </button>
          )}
        </div>

        {/* Time filter pills */}
        <div className="flex items-center bg-muted rounded-lg p-0.5 gap-0.5">
          {DATE_FILTER_OPTIONS.map((opt) => (
            <button
              key={opt.value}
              onClick={() => setDateFilter(opt.value)}
              className={`px-3 py-1.5 text-xs font-semibold rounded-md transition-all duration-150 ${dateFilter === opt.value
                ? "bg-white text-foreground shadow-sm ring-1 ring-black/[0.06]"
                : "text-muted-foreground hover:text-foreground"
                }`}
            >
              {opt.label}
            </button>
          ))}
        </div>

        {/* Sort */}
        <div className="flex items-center gap-1.5">
          <SlidersHorizontal className="h-3.5 w-3.5 text-muted-foreground flex-none" />
          <Select value={sortBy} onValueChange={(v) => setSortBy(v as SortBy)}>
            <SelectTrigger className="h-9 text-xs w-[148px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="reciente">Más reciente</SelectItem>
              <SelectItem value="antiguo">Más antiguo</SelectItem>
              <SelectItem value="apellido_az">Apellido A–Z</SelectItem>
              <SelectItem value="apellido_za">Apellido Z–A</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Clear */}
        {activeFiltersCount > 0 && (
          <button
            onClick={clearFilters}
            className="flex items-center gap-1 px-2.5 py-1.5 text-xs font-semibold rounded-lg bg-muted text-muted-foreground hover:text-foreground transition-colors"
          >
            <X className="h-3 w-3" />
            Limpiar
          </button>
        )}
      </div>

      {/* ── Error ── */}
      {error && (
        <Card className="shadow-sm border-destructive/40">
          <CardContent className="p-5">
            <div className="flex items-center gap-3">
              <div className="p-2 rounded-xl bg-destructive/10 flex-none">
                <AlertCircle className="h-4 w-4 text-destructive" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="font-semibold text-sm text-destructive">Error al cargar pacientes</p>
                <p className="text-xs text-muted-foreground mt-0.5">{error}</p>
              </div>
              <Button variant="outline" size="sm" onClick={fetchPatients} className="flex-none">
                Reintentar
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* ── Empty: no patients ── */}
      {!loading && !error && patients.length === 0 && (
        <Card className="shadow-sm border-border/70">
          <CardContent className="py-16 flex flex-col items-center gap-3 text-center">
            <div className="p-4 rounded-2xl bg-muted">
              <FileText className="h-7 w-7 text-muted-foreground" />
            </div>
            <div>
              <p className="font-semibold text-sm text-foreground">No hay pacientes registrados</p>
              <p className="text-xs text-muted-foreground mt-1">
                Comienza agregando tu primer paciente
              </p>
            </div>
            <Button size="sm" onClick={() => setIsNewPatientDialogOpen(true)} className="gap-2 mt-1">
              <Plus className="h-4 w-4" />
              Nuevo Paciente
            </Button>
          </CardContent>
        </Card>
      )}

      {/* ── No results ── */}
      {!loading && !error && patients.length > 0 && filteredPatients.length === 0 && (
        <Card className="shadow-sm border-border/70">
          <CardContent className="py-16 flex flex-col items-center gap-3 text-center">
            <div className="p-4 rounded-2xl bg-muted">
              <Search className="h-7 w-7 text-muted-foreground" />
            </div>
            <div>
              <p className="font-semibold text-sm text-foreground">Sin resultados</p>
              <p className="text-xs text-muted-foreground mt-1">
                Intenta ajustar los filtros de búsqueda
              </p>
            </div>
            <button
              onClick={clearFilters}
              className="mt-1 text-xs font-semibold text-primary hover:underline underline-offset-2"
            >
              Limpiar filtros
            </button>
          </CardContent>
        </Card>
      )}

      {/* ── Patient grid — 3 cols ── */}
      {!loading && !error && currentPatients.length > 0 && viewMode === "grid" && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {currentPatients.map((patient) => {
            const palette = getAvatarPalette(patient.nombre);
            const completion = calcProfileCompletion(patient);
            const isIncomplete = completion < 100;

            return (
              <Link key={patient.id} to={`/pacientes/${patient.id}`} className="group block">
                <Card className="h-full shadow-sm border-border/70 hover:border-primary/30 hover:shadow-md transition-all duration-200 cursor-pointer">
                  <CardContent className="p-4 flex h-full">
                    <div className="flex items-center justify-between w-full gap-4">
                      {/* Left side: Avatar + User Info (Identity + DNI/Contact) */}
                      <div className="flex items-center gap-4 min-w-0 flex-1">
                        <div
                          className={`flex-none w-12 h-12 rounded-xl flex items-center justify-center text-sm font-bold ring-1 ${palette.bg} ${palette.text} ${palette.ring}`}
                        >
                          {patient.initials}
                        </div>
                        <div className="min-w-0 flex-1">
                          <h3 className="font-bold text-foreground text-[15px] leading-tight truncate group-hover:text-primary transition-colors">
                            {patient.fullName}
                          </h3>
                          <div className="flex flex-col mt-1.5">
                            {patient.dni_cliente && (
                              <div className="flex items-center text-[11px] text-muted-foreground font-medium">
                                <span className="text-[10px] text-muted-foreground/50 mr-1.5 font-sans uppercase tracking-tight">DNI</span>
                                <span>{patient.dni_cliente}</span>
                              </div>
                            )}
                            {patient.celular && (
                              <div className="flex items-center text-[11px] text-muted-foreground font-medium">
                                <span className="text-[10px] text-muted-foreground/50 mr-1.5 font-sans uppercase tracking-tight">Contacto</span>
                                <span>{patient.celular}</span>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>

                      {/* Right side: Actions (Vertical Stack) */}
                      <div className="flex flex-col items-end flex-none gap-0.5">
                        <div
                          className="flex items-center gap-1 text-xs font-bold text-emerald-600 group-hover:gap-1.5 transition-all duration-200"
                        >
                          <span>Ver perfil</span>
                          <ChevronRight className="h-4 w-4 shrink-0" />
                        </div>
                        {isIncomplete && (
                          <span className="text-[9px] font-bold text-amber-500 uppercase tracking-tight">
                            Perfil incompleto ({completion}%)
                          </span>
                        )}
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </Link>
            );
          })}
        </div>
      )}

      {/* ── Patient table view ── */}
      {!loading && !error && currentPatients.length > 0 && viewMode === "table" && (
        <div className="bg-card border border-border/50 rounded-xl shadow-sm overflow-hidden">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader className="bg-muted/30">
                <TableRow>
                  <TableHead className="w-[180px]">Nombre</TableHead>
                  <TableHead className="w-[90px]">DNI</TableHead>
                  <TableHead className="w-[90px]">Edad</TableHead>
                  <TableHead className="w-[90px]">Contacto</TableHead>
                  <TableHead className="w-[160px] text-right" />
                </TableRow>
              </TableHeader>
              <TableBody>
                {currentPatients.map((patient) => {
                  const palette = getAvatarPalette(patient.nombre);
                  const completion = calcProfileCompletion(patient);
                  const isIncomplete = completion < 100;

                  return (
                    <TableRow key={patient.id} className="hover:bg-muted/20">
                      {/* Nombre */}
                      <TableCell className="w-[180px] max-w-[180px] overflow-hidden">
                        <div className="flex items-center gap-3 min-w-0">
                          <div
                            className={`flex-none w-8 h-8 rounded-lg flex items-center justify-center text-xs font-bold ring-1 ${palette.bg} ${palette.text} ${palette.ring}`}
                          >
                            {patient.initials}
                          </div>
                          <div className="relative min-w-0 flex-1 overflow-hidden">
                            <span className="font-medium text-sm text-foreground whitespace-nowrap">
                              {patient.fullName}
                            </span>
                            <div className="absolute inset-y-0 right-0 w-10 bg-gradient-to-l from-card to-transparent pointer-events-none" />
                          </div>
                        </div>
                      </TableCell>

                      {/* DNI */}
                      <TableCell>
                        {patient.dni_cliente ? (
                          <span className="text-sm text-muted-foreground">{patient.dni_cliente}</span>
                        ) : (
                          <span className="text-sm text-muted-foreground/40">—</span>
                        )}
                      </TableCell>

                      {/* Edad */}
                      <TableCell>
                        {patient.age != null ? (
                          <span className="text-sm text-muted-foreground">{patient.age} años</span>
                        ) : (
                          <span className="text-sm text-muted-foreground/40">—</span>
                        )}
                      </TableCell>

                      {/* Contacto */}
                      <TableCell>
                        {patient.celular ? (
                          <span className="text-sm text-muted-foreground">{patient.celular}</span>
                        ) : (
                          <span className="text-sm text-muted-foreground/40">—</span>
                        )}
                      </TableCell>

                      {/* Acción */}
                      <TableCell className="text-right">
                        <div className="flex flex-col items-end gap-0.5">
                          <Link
                            to={`/pacientes/${patient.id}`}
                            className="inline-flex items-center gap-1 text-xs font-bold text-emerald-600 hover:text-emerald-700 hover:gap-1.5 transition-all duration-150"
                          >
                            Ver perfil
                            <ChevronRight className="h-3.5 w-3.5 shrink-0" />
                          </Link>
                          {isIncomplete && (
                            <span className="text-[9px] font-bold text-amber-500 uppercase tracking-tight">
                              Perfil incompleto ({completion}%)
                            </span>
                          )}
                        </div>
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          </div>
        </div>
      )}

      {/* ── Pagination ── */}
      {!loading && !error && totalPatients > 0 && (
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
          <p className="text-xs text-muted-foreground">
            Mostrando{" "}
            <span className="font-semibold text-foreground">
              {indexOfFirstPatient + 1}–{Math.min(indexOfLastPatient, totalPatients)}
            </span>{" "}
            de{" "}
            <span className="font-semibold text-foreground">{totalPatients}</span> pacientes
          </p>

          {totalPages > 1 && (
            <div className="flex items-center gap-1">
              <button
                onClick={prevPage}
                disabled={currentPage === 1}
                className="p-1.5 rounded-lg hover:bg-muted disabled:opacity-40 disabled:cursor-not-allowed transition-colors text-muted-foreground hover:text-foreground"
              >
                <ChevronLeft className="h-4 w-4" />
              </button>

              <div className="flex gap-1">
                {Array.from({ length: Math.min(totalPages, 5) }, (_, i) => {
                  let pageNumber: number;
                  if (totalPages <= 5) {
                    pageNumber = i + 1;
                  } else if (currentPage <= 3) {
                    pageNumber = i + 1;
                  } else if (currentPage >= totalPages - 2) {
                    pageNumber = totalPages - 4 + i;
                  } else {
                    pageNumber = currentPage - 2 + i;
                  }
                  const isActive = currentPage === pageNumber;
                  return (
                    <button
                      key={pageNumber}
                      onClick={() => paginate(pageNumber)}
                      className={`w-8 h-8 rounded-lg text-xs font-semibold transition-all ${isActive
                        ? "bg-primary text-primary-foreground shadow-sm"
                        : "text-muted-foreground hover:bg-muted hover:text-foreground"
                        }`}
                    >
                      {pageNumber}
                    </button>
                  );
                })}
              </div>

              <button
                onClick={nextPage}
                disabled={currentPage === totalPages}
                className="p-1.5 rounded-lg hover:bg-muted disabled:opacity-40 disabled:cursor-not-allowed transition-colors text-muted-foreground hover:text-foreground"
              >
                <ChevronRight className="h-4 w-4" />
              </button>
            </div>
          )}

          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <span>Por página:</span>
            <Select
              value={patientsPerPage.toString()}
              onValueChange={(value) => {
                setPatientsPerPage(Number(value));
                setCurrentPage(1);
              }}
            >
              <SelectTrigger className="h-7 w-16 text-xs">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="6">6</SelectItem>
                <SelectItem value="12">12</SelectItem>
                <SelectItem value="24">24</SelectItem>
                <SelectItem value="48">48</SelectItem>
              </SelectContent>
            </Select>
          </div>
        </div>
      )}

      <PatientDialog
        open={isNewPatientDialogOpen}
        onOpenChange={setIsNewPatientDialogOpen}
      />
    </div>
  );
}

import { Card, CardContent } from "@/components/ui/card";
import { useAuthContext } from "@/context/AuthContext";
import { StatCard } from "@/components/dashboard/StatCard";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
  Plus,
  Search,
  FileText,
  ChevronLeft,
  ChevronRight,
  SlidersHorizontal,
  X,
  Banknote,
  CreditCard,
  Send,
  TrendingUp,
  Receipt,
  Activity,
  List,
} from "lucide-react";
import { calcPct } from "@/components/common/PctBadge";
import { getAllPayments } from "@/services/paymentService";
import { formatCurrencyAxis } from "@/utils/formatters";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { useState, useEffect, useMemo, useRef } from "react";
import { PageLoader } from "@/components/ui/PageLoader";
import { useMinLoading } from "@/hooks/useMinLoading";
import PaymentDialog from "@/components/payments/PaymentDialog";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from "recharts";
import {
  format,
  startOfDay,
  endOfDay,
  startOfWeek,
  endOfWeek,
  startOfMonth,
  endOfMonth,
  startOfYear,
  endOfYear,
  addDays,
  addWeeks,
  addMonths,
  addYears,
  subDays,
  subWeeks,
  subMonths,
  subYears,
  eachHourOfInterval,
  eachDayOfInterval,
  eachMonthOfInterval,
  isSameHour,
  isSameDay,
  isSameMonth,
} from "date-fns";
import { es } from "date-fns/locale";

type PeriodType = "dia" | "semana" | "mes" | "anio";

const PERIOD_OPTIONS: { label: string; value: PeriodType }[] = [
  { label: "Día", value: "dia" },
  { label: "Semana", value: "semana" },
  { label: "Mes", value: "mes" },
  { label: "Año", value: "anio" },
];

function getMetodoCfg(metodo: string): {
  color: string;
  bg: string;
  ring: string;
  Icon: typeof Banknote;
  label: string;
} {
  const m = metodo.toLowerCase();
  if (m.includes("efectivo") || m.includes("cash")) {
    return { color: "text-emerald-700", bg: "bg-emerald-50", ring: "ring-emerald-200", Icon: Banknote, label: "Efectivo" };
  }
  if (m.includes("tarjeta") || m.includes("card") || m.includes("débito") || m.includes("crédito")) {
    return { color: "text-blue-700", bg: "bg-blue-50", ring: "ring-blue-200", Icon: CreditCard, label: "Tarjeta" };
  }
  if (m.includes("transferencia") || m.includes("transfer") || m.includes("yape") || m.includes("plin")) {
    return { color: "text-violet-700", bg: "bg-violet-50", ring: "ring-violet-200", Icon: Send, label: metodo };
  }
  return { color: "text-gray-600", bg: "bg-gray-100", ring: "ring-gray-200", Icon: Receipt, label: metodo };
}

export default function Pagos() {
  const { rol } = useAuthContext();
  const isRecepcionista = rol === "recepcionista";

  const [searchTerm, setSearchTerm] = useState("");
  const [isPaymentDialogOpen, setIsPaymentDialogOpen] = useState(false);
  const [showHistorial, setShowHistorial] = useState(false);
  const [chartFullHeight, setChartFullHeight] = useState(420);
  const [pagos, setPagos] = useState<any[]>([]);
  const [loadingPagos, setLoadingPagos] = useState(true);
  const show = useMinLoading(loadingPagos);
  const [refreshing, setRefreshing] = useState(false);
  const isInitialLoad = useRef(true);
  const [period, setPeriod] = useState<PeriodType>("mes");
  const [currentDate, setCurrentDate] = useState(new Date());
  const [historialPeriod, setHistorialPeriod] = useState<"todo" | PeriodType>("todo");
  const [sortBy, setSortBy] = useState<"reciente" | "antiguo" | "mayor_monto" | "menor_monto">("reciente");

  const fetchPagos = async () => {
    try {
      if (isInitialLoad.current) { setLoadingPagos(true); } else { setRefreshing(true); }
      const pagosData = await getAllPayments();
      setPagos(pagosData);
    } catch (error) {
      console.error("Error al cargar pagos:", error);
    } finally {
      setLoadingPagos(false);
      setRefreshing(false);
      isInitialLoad.current = false;
    }
  };

  useEffect(() => {
    fetchPagos();
  }, []);

  // Compute chart height dynamically to fill available viewport space
  useEffect(() => {
    const compute = () => {
      // Approximate pixels consumed above the chart area:
      // layout padding(64) + header(80) + gap(24) + period-row(40) + gap(24) + stat-cards(72) + gap(24) + chart-label(54)
      const aboveChart = 64 + 80 + 24 + 40 + 24 + 72 + 24 + 54;
      setChartFullHeight(Math.max(220, window.innerHeight - aboveChart));
    };
    compute();
    window.addEventListener("resize", compute);
    return () => window.removeEventListener("resize", compute);
  }, []);

  const firstPaymentDate = useMemo(() => {
    if (pagos.length === 0) return null;
    return pagos.reduce((earliest, p) => {
      const d = new Date(p.fecha);
      return d < earliest ? d : earliest;
    }, new Date(pagos[0].fecha));
  }, [pagos]);

  const dateRange = useMemo(() => {
    switch (period) {
      case "dia":
        return { start: startOfDay(currentDate), end: endOfDay(currentDate) };
      case "semana":
        return {
          start: startOfWeek(currentDate, { weekStartsOn: 1 }),
          end: endOfWeek(currentDate, { weekStartsOn: 1 }),
        };
      case "mes":
        return { start: startOfMonth(currentDate), end: endOfMonth(currentDate) };
      case "anio":
        return { start: startOfYear(currentDate), end: endOfYear(currentDate) };
    }
  }, [period, currentDate]);

  const prevDateRange = useMemo(() => {
    switch (period) {
      case "dia": {
        const prev = subDays(currentDate, 1);
        return { start: startOfDay(prev), end: endOfDay(prev) };
      }
      case "semana": {
        const prev = subWeeks(currentDate, 1);
        return {
          start: startOfWeek(prev, { weekStartsOn: 1 }),
          end: endOfWeek(prev, { weekStartsOn: 1 }),
        };
      }
      case "mes": {
        const prev = subMonths(currentDate, 1);
        return { start: startOfMonth(prev), end: endOfMonth(prev) };
      }
      case "anio": {
        const prev = subYears(currentDate, 1);
        return { start: startOfYear(prev), end: endOfYear(prev) };
      }
    }
  }, [period, currentDate]);

  const navigatePrev = () => {
    switch (period) {
      case "dia": setCurrentDate((d) => subDays(d, 1)); break;
      case "semana": setCurrentDate((d) => subWeeks(d, 1)); break;
      case "mes": setCurrentDate((d) => subMonths(d, 1)); break;
      case "anio": setCurrentDate((d) => subYears(d, 1)); break;
    }
  };

  const navigateNext = () => {
    switch (period) {
      case "dia": setCurrentDate((d) => addDays(d, 1)); break;
      case "semana": setCurrentDate((d) => addWeeks(d, 1)); break;
      case "mes": setCurrentDate((d) => addMonths(d, 1)); break;
      case "anio": setCurrentDate((d) => addYears(d, 1)); break;
    }
  };

  const periodLabel = useMemo(() => {
    switch (period) {
      case "dia":
        return format(currentDate, "dd/MM/yyyy");
      case "semana": {
        const start = startOfWeek(currentDate, { weekStartsOn: 1 });
        const end = endOfWeek(currentDate, { weekStartsOn: 1 });
        return `${format(start, "dd/MM/yyyy")} – ${format(end, "dd/MM/yyyy")}`;
      }
      case "mes":
        return format(currentDate, "MMMM yyyy", { locale: es });
      case "anio":
        return format(currentDate, "yyyy");
    }
  }, [period, currentDate]);

  const pagosEnRango = useMemo(() =>
    pagos.filter((p) => {
      const f = new Date(p.fecha);
      return f >= dateRange.start && f <= dateRange.end;
    }), [pagos, dateRange]);

  const pagosAnterior = useMemo(() =>
    pagos.filter((p) => {
      const f = new Date(p.fecha);
      return f >= prevDateRange.start && f <= prevDateRange.end;
    }), [pagos, prevDateRange]);

  const totalPeriodo = pagosEnRango.reduce((sum, p) => sum + p.monto, 0);
  const cantidadPeriodo = pagosEnRango.length;
  const promedioPeriodo = cantidadPeriodo > 0 ? totalPeriodo / cantidadPeriodo : 0;

  // Estadísticas de hoy (fijas para recepcionista)
  const statsHoy = useMemo(() => {
    const hoy = startOfDay(new Date());
    const finHoy = endOfDay(new Date());
    const delDia = pagos.filter((p) => {
      const f = new Date(p.fecha);
      return f >= hoy && f <= finHoy;
    });
    return {
      total: delDia.reduce((sum, p) => sum + p.monto, 0),
      cantidad: delDia.length
    };
  }, [pagos]);

  const totalAnterior = pagosAnterior.reduce((sum, p) => sum + p.monto, 0);
  const cantidadAnterior = pagosAnterior.length;
  const promedioAnterior = cantidadAnterior > 0 ? totalAnterior / cantidadAnterior : 0;

  const chartData = useMemo(() => {
    switch (period) {
      case "dia": {
        const hours = eachHourOfInterval({ start: dateRange.start, end: dateRange.end });
        return hours.map((hour) => ({
          label: format(hour, "HH:mm"),
          total: pagosEnRango
            .filter((p) => isSameHour(new Date(p.fecha), hour))
            .reduce((sum, p) => sum + p.monto, 0),
        }));
      }
      case "semana":
      case "mes": {
        const days = eachDayOfInterval({ start: dateRange.start, end: dateRange.end });
        return days.map((day) => ({
          label:
            period === "semana"
              ? format(day, "EEE d", { locale: es })
              : format(day, "d"),
          total: pagosEnRango
            .filter((p) => isSameDay(new Date(p.fecha), day))
            .reduce((sum, p) => sum + p.monto, 0),
        }));
      }
      case "anio": {
        const yearStart = startOfYear(currentDate);
        const yearEnd = endOfYear(currentDate);
        const effectiveStart =
          firstPaymentDate &&
            firstPaymentDate.getFullYear() === currentDate.getFullYear() &&
            firstPaymentDate > yearStart
            ? startOfMonth(firstPaymentDate)
            : yearStart;

        const months = eachMonthOfInterval({ start: effectiveStart, end: yearEnd });
        return months.map((month) => ({
          label: format(month, "MMM", { locale: es }),
          total: pagos
            .filter((p) => isSameMonth(new Date(p.fecha), month))
            .reduce((sum, p) => sum + p.monto, 0),
        }));
      }
    }
  }, [period, pagos, pagosEnRango, dateRange, currentDate, firstPaymentDate]);

  const xAxisTickFormatter = (val: string) => {
    if (period !== "mes") return val;
    const n = parseInt(val, 10);
    if (n === 1 || n % 5 === 0) return val;
    return "";
  };

  const historialDateRange = useMemo(() => {
    if (historialPeriod === "todo") return null;
    const now = new Date();
    switch (historialPeriod) {
      case "dia": return { start: startOfDay(now), end: endOfDay(now) };
      case "semana": return { start: startOfWeek(now, { weekStartsOn: 1 }), end: endOfWeek(now, { weekStartsOn: 1 }) };
      case "mes": return { start: startOfMonth(now), end: endOfMonth(now) };
      case "anio": return { start: startOfYear(now), end: endOfYear(now) };
    }
  }, [historialPeriod]);

  const filteredPayments = useMemo(() => {
    let result = pagos.filter(
      (pago) =>
        pago.paciente_nombre.toLowerCase().includes(searchTerm.toLowerCase()) ||
        pago.concepto.toLowerCase().includes(searchTerm.toLowerCase()) ||
        pago.referencia_nombre.toLowerCase().includes(searchTerm.toLowerCase())
    );

    if (historialDateRange) {
      result = result.filter((p) => {
        const f = new Date(p.fecha);
        return f >= historialDateRange.start && f <= historialDateRange.end;
      });
    }

    return [...result].sort((a, b) => {
      switch (sortBy) {
        case "reciente": return new Date(b.fecha).getTime() - new Date(a.fecha).getTime();
        case "antiguo": return new Date(a.fecha).getTime() - new Date(b.fecha).getTime();
        case "mayor_monto": return b.monto - a.monto;
        case "menor_monto": return a.monto - b.monto;
        default: return 0;
      }
    });
  }, [pagos, searchTerm, historialDateRange, sortBy]);

  const historialActiveFiltersCount = [
    searchTerm !== "",
    historialPeriod !== "todo",
    sortBy !== "reciente",
  ].filter(Boolean).length;

  const clearHistorialFilters = () => {
    setSearchTerm("");
    setHistorialPeriod("todo");
    setSortBy("reciente");
  };

  const formatCurrency = (amount: number) =>
    new Intl.NumberFormat("es-PE", { style: "currency", currency: "PEN" }).format(amount);

  const chartHeight = showHistorial
    ? Math.round(chartFullHeight * 0.8)
    : chartFullHeight;

  if (show) return <PageLoader message="Cargando pagos..." />;

  return (
    <div className="flex flex-col gap-6">
      {/* ── Header ── */}
      <div className="flex justify-between items-center relative z-20 pb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-gray-100">Pagos</h1>
          <p className="text-gray-500 dark:text-gray-400 mt-1 flex items-center gap-2">
            Gestión financiera del consultorio
            {refreshing && <span className="animate-spin rounded-full h-3.5 w-3.5 border-b-2 border-primary flex-none" />}
          </p>
        </div>
        <Button
          className="bg-primary hover:bg-primary/90 text-primary-foreground shadow-sm"
          onClick={() => setIsPaymentDialogOpen(true)}
        >
          <Plus className="mr-2 h-4 w-4" />
          Registrar Pago
        </Button>
      </div>

      {/* ── Period selector + Navigator (Oculto para recepcionista) ── */}
      {!isRecepcionista && (
        <div className="flex flex-wrap items-center gap-3">
          {/* Segmented control */}
          <div className="flex items-center bg-muted rounded-xl p-1 gap-0.5">
            {PERIOD_OPTIONS.map((opt) => (
              <button
                key={opt.value}
                onClick={() => setPeriod(opt.value)}
                className={`px-4 py-1.5 text-sm font-medium rounded-lg transition-all duration-200 ${period === opt.value
                    ? "bg-white text-foreground shadow-sm ring-1 ring-black/[0.06]"
                    : "text-muted-foreground hover:text-foreground"
                  }`}
              >
                {opt.label}
              </button>
            ))}
          </div>

          {/* Date navigator */}
          <div className="flex items-center bg-muted rounded-xl p-1 gap-0.5">
            <button
              onClick={navigatePrev}
              className="p-1.5 rounded-lg hover:bg-white hover:shadow-sm hover:ring-1 hover:ring-black/[0.06] transition-all text-muted-foreground hover:text-foreground"
            >
              <ChevronLeft className="h-4 w-4" />
            </button>
            <span className="text-sm font-semibold min-w-[186px] text-center capitalize px-2 text-foreground">
              {periodLabel}
            </span>
            <button
              onClick={navigateNext}
              className="p-1.5 rounded-lg hover:bg-white hover:shadow-sm hover:ring-1 hover:ring-black/[0.06] transition-all text-muted-foreground hover:text-foreground"
            >
              <ChevronRight className="h-4 w-4" />
            </button>
          </div>

          {/* Toggle historial */}
          <button
            onClick={() => setShowHistorial((v) => !v)}
            className={`ml-auto flex items-center gap-1.5 px-3.5 py-1.5 rounded-xl text-sm font-medium transition-all duration-200 ${
              showHistorial
                ? "bg-primary text-primary-foreground shadow-sm"
                : "bg-muted text-muted-foreground hover:text-foreground"
            }`}
          >
            <List className="h-3.5 w-3.5" />
            {showHistorial ? "Ocultar historial" : "Mostrar historial"}
          </button>
        </div>
      )}

      {/* ── Stat cards ── */}
      <div className={`grid grid-cols-1 ${isRecepcionista ? 'sm:grid-cols-2' : 'sm:grid-cols-3'} gap-4`}>
        <StatCard
          title={isRecepcionista ? "Ingresos del día" : "Ingresos del período"}
          value={formatCurrency(isRecepcionista ? statsHoy.total : totalPeriodo)}
          icon={TrendingUp}
          iconBg="bg-primary/10"
          iconText="text-primary"
          trend={
            !isRecepcionista && (totalAnterior > 0 || totalPeriodo > 0)
              ? {
                  value: `${Math.abs(calcPct(totalPeriodo, totalAnterior)).toFixed(0)}% vs período ant.`,
                  positive: totalPeriodo >= totalAnterior,
                }
              : undefined
          }
        />
        <StatCard
          title={isRecepcionista ? "Pagos registrados" : "Total de pagos"}
          value={isRecepcionista ? statsHoy.cantidad : cantidadPeriodo}
          icon={Activity}
          iconBg="bg-violet-50"
          iconText="text-violet-600"
          trend={
            !isRecepcionista && (cantidadAnterior > 0 || cantidadPeriodo > 0)
              ? {
                  value: `${Math.abs(calcPct(cantidadPeriodo, cantidadAnterior)).toFixed(0)}% vs período ant.`,
                  positive: cantidadPeriodo >= cantidadAnterior,
                }
              : undefined
          }
        />
        {!isRecepcionista && (
          <StatCard
            title="Promedio por pago"
            value={formatCurrency(promedioPeriodo)}
            icon={Receipt}
            iconBg="bg-emerald-50"
            iconText="text-emerald-600"
            trend={
              promedioAnterior > 0 || promedioPeriodo > 0
                ? {
                    value: `${Math.abs(calcPct(promedioPeriodo, promedioAnterior)).toFixed(0)}% vs período ant.`,
                    positive: promedioPeriodo >= promedioAnterior,
                  }
                : undefined
            }
          />
        )}
      </div>

      {/* ── Chart + Historial sub-container (no gap between them, managed manually) ── */}
      <div className="flex flex-col">

      {/* ── Chart Card (Oculto para recepcionista) ── */}
      {!isRecepcionista && (
        <Card className="shadow-sm border-border/70">
          <CardContent className="pt-5 pb-5">
            <p className="text-sm font-semibold text-foreground mb-5">
              Evolución de ingresos
            </p>
            <div
              className="overflow-hidden"
              style={{
                height: `${chartHeight}px`,
                transition: "height 0.5s ease-in-out",
              }}
            >
            {
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart
                  data={chartData}
                  margin={{ top: 4, right: 4, left: 0, bottom: 0 }}
                >
                  <defs>
                    <linearGradient id="gradientTotal" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="hsl(var(--primary))" stopOpacity={0.15} />
                      <stop offset="95%" stopColor="hsl(var(--primary))" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <CartesianGrid
                    strokeDasharray="3 3"
                    stroke="hsl(var(--border))"
                    opacity={0.5}
                  />
                  <XAxis
                    dataKey="label"
                    tick={{ fontSize: 11, fill: "hsl(var(--muted-foreground))" }}
                    axisLine={false}
                    tickLine={false}
                    tickFormatter={xAxisTickFormatter}
                  />
                  <YAxis
                    tick={{ fontSize: 11, fill: "hsl(var(--muted-foreground))" }}
                    axisLine={false}
                    tickLine={false}
                    tickFormatter={formatCurrencyAxis}
                    width={56}
                  />
                  <Tooltip
                    formatter={(value: number) => [formatCurrency(value), "Ingresos"]}
                    contentStyle={{
                      backgroundColor: "hsl(var(--card))",
                      border: "1px solid hsl(var(--border))",
                      borderRadius: "8px",
                      fontSize: "13px",
                    }}
                    labelStyle={{ fontWeight: 600, marginBottom: 4 }}
                    cursor={{
                      stroke: "hsl(var(--primary))",
                      strokeWidth: 1,
                      strokeDasharray: "4 4",
                    }}
                  />
                  <Area
                    type="monotone"
                    dataKey="total"
                    stroke="hsl(var(--primary))"
                    strokeWidth={2}
                    fill="url(#gradientTotal)"
                    dot={false}
                    activeDot={{ r: 4, fill: "hsl(var(--primary))" }}
                  />
                </AreaChart>
              </ResponsiveContainer>
            }
            </div>
          </CardContent>
        </Card>
      )}

      {/* ── Historial (collapsible / siempre visible para recepcionista) ── */}
      <div
        className={`grid transition-all duration-500 ease-in-out ${
          (showHistorial || isRecepcionista) ? "grid-rows-[1fr] opacity-100 mt-6" : "grid-rows-[0fr] opacity-0 mt-0"
        }`}
      >
      <div className="overflow-hidden">
      <div className="space-y-6 pt-2">
      <h2 className="text-xl font-bold text-foreground">Historial de pagos</h2>

      {/* ── Controls: search + period pills + sort + clear (estilo Pacientes) ── */}
      <div className="flex gap-3 items-center flex-wrap">
        {/* Search — mitad del ancho con botón X interno */}
        <div className="relative w-1/2 flex-shrink-0">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
          <Input
            placeholder="Buscar por paciente o tratamiento..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-9 pr-9 h-9 text-sm"
          />
          {searchTerm && (
            <button
              onClick={() => setSearchTerm("")}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
            >
              <X className="h-3.5 w-3.5" />
            </button>
          )}
        </div>

        {/* Period filter pills */}
        <div className="flex items-center bg-muted rounded-lg p-0.5 gap-0.5">
          {(
            [{ label: "Todo", value: "todo" }, ...PERIOD_OPTIONS] as {
              label: string;
              value: "todo" | PeriodType;
            }[]
          ).map((opt) => (
            <button
              key={opt.value}
              onClick={() => setHistorialPeriod(opt.value)}
              className={`px-3 py-1.5 text-xs font-semibold rounded-md transition-all duration-150 ${historialPeriod === opt.value
                  ? "bg-white text-foreground shadow-sm ring-1 ring-black/[0.06]"
                  : "text-muted-foreground hover:text-foreground"
                }`}
            >
              {opt.label}
            </button>
          ))}
        </div>

        {/* Sort */}
        <div className="flex items-center gap-1.5">
          <SlidersHorizontal className="h-3.5 w-3.5 text-muted-foreground flex-none" />
          <Select value={sortBy} onValueChange={(v) => setSortBy(v as typeof sortBy)}>
            <SelectTrigger className="h-9 text-xs w-[148px]">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="reciente">Más reciente</SelectItem>
              <SelectItem value="antiguo">Más antiguo</SelectItem>
              <SelectItem value="mayor_monto">Mayor monto</SelectItem>
              <SelectItem value="menor_monto">Menor monto</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Limpiar — solo visible cuando hay filtros activos */}
        {historialActiveFiltersCount > 0 && (
          <button
            onClick={clearHistorialFilters}
            className="flex items-center gap-1 px-2.5 py-1.5 text-xs font-semibold rounded-lg bg-muted text-muted-foreground hover:text-foreground transition-colors"
          >
            <X className="h-3 w-3" />
            Limpiar
          </button>
        )}
      </div>

      {/* ── Payments list ── */}
      <Card className="shadow-sm border-border/70 overflow-hidden">
        <CardContent className="p-0">
          {filteredPayments.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-16 gap-3 text-center">
              <div className="p-4 rounded-2xl bg-muted">
                <FileText className="h-7 w-7 text-muted-foreground" />
              </div>
              <div>
                <p className="font-semibold text-foreground text-sm">
                  No hay pagos registrados
                </p>
                <p className="text-xs text-muted-foreground mt-1">
                  {searchTerm
                    ? "No se encontraron resultados para tu búsqueda"
                    : "Los pagos aparecerán aquí cuando se registren"}
                </p>
              </div>
            </div>
          ) : (
            <div className="divide-y divide-border/60">
              {filteredPayments.map((pago) => {
                const cfg = getMetodoCfg(pago.metodo_pago);
                const MetodoIcon = cfg.Icon;
                const esTratamiento = pago.tipo !== "consulta";

                return (
                  <div
                    key={pago.id}
                    className="flex items-center gap-4 px-5 py-3.5 hover:bg-muted/30 transition-colors"
                  >
                    {/* Payment method icon */}
                    <div
                      className={`flex-none w-10 h-10 rounded-xl flex items-center justify-center ring-1 ${cfg.bg} ${cfg.ring}`}
                    >
                      <MetodoIcon className={`h-4.5 w-4.5 ${cfg.color}`} />
                    </div>

                    {/* Patient + concept */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-0.5">
                        <p className="font-semibold text-sm text-foreground truncate">
                          {pago.paciente_nombre}
                        </p>
                        <Badge
                          variant="outline"
                          className={`text-[10px] font-semibold h-4 px-1.5 py-0 leading-none flex-none ${esTratamiento
                              ? "bg-teal-50 text-teal-700 border-teal-200"
                              : "bg-sky-50 text-sky-700 border-sky-200"
                            }`}
                        >
                          {esTratamiento ? "Tratamiento" : "Consulta"}
                        </Badge>
                      </div>
                      <p className="text-xs text-muted-foreground truncate">
                        {pago.concepto}
                      </p>
                      {pago.notas && (
                        <p className="text-[11px] text-muted-foreground/70 italic mt-0.5 truncate">
                          {pago.notas}
                        </p>
                      )}
                    </div>

                    {/* Date + method — hidden on small screens */}
                    <div className="hidden md:flex flex-col items-end gap-1 min-w-[120px] text-right">
                      <p className="text-xs font-medium text-foreground">
                        {pago.fecha.toLocaleDateString("es-PE", {
                          year: "numeric",
                          month: "short",
                          day: "numeric",
                        })}
                      </p>
                      <span
                        className={`inline-block text-[10px] font-semibold px-1.5 py-0.5 rounded-md ring-1 ${cfg.bg} ${cfg.color} ${cfg.ring}`}
                      >
                        {cfg.label}
                      </span>
                    </div>

                    {/* Amount */}
                    <div className="flex-none text-right min-w-[88px]">
                      <p className="text-base font-bold text-emerald-600 tabular-nums">
                        {formatCurrency(pago.monto)}
                      </p>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>
      </div>{/* /space-y-6 historial */}
      </div>{/* /overflow-hidden */}
      </div>{/* /grid collapsible */}

      </div>{/* /chart+historial sub-container */}

      <PaymentDialog
        open={isPaymentDialogOpen}
        onOpenChange={setIsPaymentDialogOpen}
        onSuccess={() => {
          fetchPagos();
        }}
      />
    </div>
  );
}

import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { PageLoader } from "@/components/ui/PageLoader";
import { useMinLoading } from "@/hooks/useMinLoading";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { ActivityList } from "@/components/profile/ActivityList";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
    User,
    Mail,
    MapPin,
    Phone,
    Briefcase,
    Calendar,
    ShieldCheck,
    Activity,
    CreditCard,
    Edit,
    Loader2,
} from "lucide-react";
import { useAuthContext } from "@/context/AuthContext";
import { getUsuarioByUid } from "@/services/usuariosService";
import type { Usuario } from "@/types/usuario";
import { ProfileManagementDialog } from "@/components/profile/ProfileManagementDialog";
import { Separator } from "@/components/ui/separator";

export default function Perfil() {
    const { user } = useAuthContext();
    const [usuario, setUsuario] = useState<Usuario | null>(null);
    const [loading, setLoading] = useState(true);
    const show = useMinLoading(loading);
    const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);

    const fetchProfile = async (isSilent = false) => {
        if (!user?.uid) return;
        try {
            if (!isSilent) setLoading(true);
            const data = await getUsuarioByUid(user.uid);
            setUsuario(data);
        } catch (error) {
            console.error("Error fetching profile:", error);
        } finally {
            if (!isSilent) setLoading(false);
        }
    };

    useEffect(() => {
        fetchProfile();
    }, [user]);

    if (show) return <PageLoader message="Cargando perfil..." />;

    if (!usuario) {
        return (
            <div className="p-6">
                <Card className="border-destructive">
                    <CardContent className="p-6">
                        <p className="text-destructive font-semibold text-center">No se pudo cargar la información del perfil.</p>
                    </CardContent>
                </Card>
            </div>
        );
    }

    const fullName = `${usuario.nombre} ${usuario.apellidoPaterno} ${usuario.apellidoMaterno || ""}`.trim();
    const initials = `${usuario.nombre[0]}${usuario.apellidoPaterno[0]}`.toUpperCase();

    return (
        <div className="flex flex-col gap-6 max-w-6xl mx-auto">
            {/* Page Header */}
            <div className="flex justify-between items-center relative z-20 pb-2">
                <div>
                    <h1 className="text-3xl font-bold text-gray-900 dark:text-gray-100">Gestión de Perfil</h1>
                    <p className="text-gray-500 dark:text-gray-400 mt-1">Administra tu información personal y preferencias de acceso en el sistema.</p>
                </div>
                <Button onClick={() => setIsEditDialogOpen(true)} className="flex items-center gap-2">
                    <Edit className="h-4 w-4" />
                    Editar Perfil
                </Button>
            </div>

            <div className="py-2">
                <Separator className="bg-slate-200" />
            </div>

            {/* Main Content Grid */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 pt-2">

                {/* Left Column: Summary Card */}
                <div className="lg:col-span-1 space-y-6">
                    <Card>
                        <CardContent className="pt-6 pb-6 text-center">
                            <div className="mx-auto w-24 h-24 mb-4 rounded-full bg-primary/10 text-primary flex items-center justify-center text-3xl font-bold shadow-sm ring-4 ring-primary/5">
                                {user?.photoURL ? (
                                    <img src={user.photoURL} alt={fullName} className="w-full h-full rounded-full object-cover" />
                                ) : (
                                    initials
                                )}
                            </div>
                            <h2 className="text-xl font-bold text-slate-800 mb-0.5">{fullName}</h2>
                            <p className="text-[10px] text-primary/60 font-bold uppercase tracking-[0.15em] mb-4">
                                {usuario.rol || "Usuario"}
                            </p>
                            <p className="text-slate-400 text-[13px] mb-4">
                                {user?.email}
                            </p>

                            <div className="flex justify-center gap-2">
                                <Badge variant={usuario.estado === "active" ? "default" : "secondary"}>
                                    {usuario.estado === "active" ? "Activo" : "Pendiente"}
                                </Badge>
                                <Badge variant="outline" className="text-primary border-primary/30">
                                    <ShieldCheck className="h-3 w-3 mr-1" />
                                    Verificado
                                </Badge>
                            </div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader className="pb-3 border-b border-slate-100">
                            <CardTitle className="text-sm font-semibold text-slate-800 flex items-center gap-2">
                                <Mail className="h-4 w-4 text-primary" />
                                Contacto Rápido
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="pt-4 space-y-4">
                            <div className="flex items-start gap-3">
                                <Mail className="h-4 w-4 text-slate-400 mt-0.5" />
                                <div className="space-y-1">
                                    <p className="text-sm font-medium leading-none text-slate-700">Email</p>
                                    <p className="text-sm text-slate-500">{user?.email}</p>
                                </div>
                            </div>
                            <div className="flex items-start gap-3">
                                <Phone className="h-4 w-4 text-slate-400 mt-0.5" />
                                <div className="space-y-1">
                                    <p className="text-sm font-medium leading-none text-slate-700">Teléfono</p>
